-- Poems batch 84
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('e4309f1f-7c80-4a1d-a8ce-484bcb3b639f','春夜雨','張嵲','宋','宋诗','song-poetry','','[]','小雨集春夜，憶居江漢時。',96,'全唐诗/poet.song.105000.json','["小雨集春夜，憶居江漢時。", "西園桃李樹，到晚有餘姿。", "載酒繞阡陌，折芳恣遨嬉。", "里閭多樂事，中年遭亂離。", "飄零向十載，南来復再朞。", "故園當日春，相見一天涯。", "他鄉花自發，山寺日初遲。", "時節豈云異，身世自堪悲。"]'),
('1b1260d1-779d-43c6-9d5e-6f2e336c1902','次韵王倅大梵寺山亭夜雨','張嵲','宋','宋诗','song-poetry','','[]','溪山含變態，可玩不可說。',96,'全唐诗/poet.song.105000.json','["溪山含變態，可玩不可說。", "西嶺澹斜暉，前山明積雪。", "潭空游鱗出，景晏飛鳥絕。", "遠嶼上孤烟，平沙散疏樾。", "天涯一尊酒，草草堂上設。", "觴詠寄高爽，對此清夜月。", "但使息營營，寧論醉兀兀。", "寓興合一篇，亡書謝三篋。"]'),
('d53ae7e4-50bf-445f-b5c1-e114e78d3ed8','自順陽至均房道五首用陳符寶去非韵  其一','張嵲','宋','宋诗','song-poetry','','[]','行客路正遠，曦馭已西馳。',96,'全唐诗/poet.song.105000.json','["行客路正遠，曦馭已西馳。", "霜風吹草樹，眇眇連荒陂。", "如何羈旅懷，更值揺落時。", "四序歘已晚，我生可無衰。", "尚紆俗吏袍，久負南山期。", "吾廬豈固好，此身自安之。", "胡爲終歲别，使我心怕悲。", "故園松菊荒，静計勿差池。"]'),
('1bcc15ae-4691-411e-b151-aabd8e98a3fc','自順陽至均房道五首用陳符寶去非韵  其二','張嵲','宋','宋诗','song-poetry','','[]','桑柘共平陸，過橋野色分。',48,'全唐诗/poet.song.105000.json','["桑柘共平陸，過橋野色分。", "冬序日向深，冒山多薄雲。", "驚飈入長林，黄葉久紛紛。", "山前有人家，雞犬時一聞。"]'),
('dce49673-5ea5-4ab6-9eac-f79f22931911','自順陽至均房道五首用陳符寶去非韵  其三','張嵲','宋','宋诗','song-poetry','','[]','我行均陽道，岡阜如群駝。',96,'全唐诗/poet.song.105000.json','["我行均陽道，岡阜如群駝。", "澗石既齒齒，寒山亦峨峨。", "喬林木葉盡，仰見鶴鸛窠。", "風景固不殊，舉目異山河。", "我生雖尚壯，百慮紛已多。", "祗今且如此，後日當奈何。", "細較平生中，憂樂恒相摩。", "悲吟誰復聽，日暮越前坡。"]'),
('171bebd4-2ef0-4e2c-97c6-c2783a225576','自順陽至均房道五首用陳符寶去非韵  其四','張嵲','宋','宋诗','song-poetry','','[]','行客日暮時，愁聞蕭條風。',96,'全唐诗/poet.song.105000.json','["行客日暮時，愁聞蕭條風。", "雲山當我前，適與清興同。", "夕澗生白烟，蒸空自溟濛。", "林壑豈不佳，陟降煩奴僮。", "徑側有黄花，凄疏隠珍叢。", "我欲採落英，恨無聖賢中。", "徘徊戀幽意，欲住興來窮。", "山深月正黑，投驛尚怱怱。"]'),
('4d933def-bf1a-4a72-b0bf-aef95fc92e8c','自順陽至均房道五首用陳符寶去非韵  其五','張嵲','宋','宋诗','song-poetry','','[]','蓐食带殘月，驅僕事西奔。',72,'全唐诗/poet.song.105000.json','["蓐食带殘月，驅僕事西奔。", "烟塵猶未息，去住敢輕論。", "道古留餘險，溪寒減漲痕。", "鳴桴聞遠驛，吠犬應前村。", "境絕增詩興，山深畏客魂。", "吾生久已定，漂轉任乾坤。"]'),
('51448dbf-baee-447d-b42f-115a177727c1','秋日訪野人','張嵲','宋','宋诗','song-poetry','','[]','忽忽倦幽獨，試尋居士室。',48,'全唐诗/poet.song.105000.json','["忽忽倦幽獨，試尋居士室。", "循籬野蔓懸，閉户鄰雞出。", "小水已清泠，前山政岑鬰。", "禾黍滿平川，高低動殘日。"]'),
('1d46159e-359b-4608-8ded-168edc03c349','過平陵漢蘇建所封','張嵲','宋','宋诗','song-poetry','','[]','寒食光輝薄，古原多夕陰。',96,'全唐诗/poet.song.105000.json','["寒食光輝薄，古原多夕陰。", "行經平陵道，感慨一何深。", "將軍昔封此，漢史傳至今。", "山川宛如舊，事跡嗟已沉。", "聚落有人烟，故國無喬林。", "尚想英雄氣，千古猶森森。", "邊塵久未定，干戈日相尋。", "興懷幾內慟，何必鼓鼙音。"]'),
('85bac4b0-66f5-48ef-84fb-62d5af6eed83','上分水嶺','張嵲','宋','宋诗','song-poetry','','[]','夜半風撼山，苦雨歇初曉。',156,'全唐诗/poet.song.105000.json','["夜半風撼山，苦雨歇初曉。", "高峰吹成冰，草樹葉盡縞。", "行行入雲中，稍稍臨木杪。", "恍疑天宇近，漸覺溪溜小。", "挺身陵絕頂，夐與人代杳。", "篁竹互蒙籠，岡巒亘縈繞。", "乃知七閩境，如此平地少。", "攻擊固其然，割據亦可考。", "始悟淮南書，鋪陳苦未了。", "右顧遠中原，前瞻臨嶺嶠。", "邊馬猶亂華，淮濆尚雲擾。", "故鄉豈不懷，甘心混蠻獠。", "九夷儻可歸，吾願從高鳥。"]'),
('a726d146-065c-4b82-bae9-9bfc525826bd','臘梅','張嵲','宋','宋诗','song-poetry','','[]','朔風吹同雲，萬木不敢芳。',84,'全唐诗/poet.song.105000.json','["朔風吹同雲，萬木不敢芳。", "黄衣何許仙，窈窕來離房。", "終期賞心會，未恨冰雪鄉。", "向來脂粉流，睨睥誰敢當。", "宜於風露晨，置在清净箱。", "更招能賦客，苾茀詠奇香。", "楚人意已疏，亡聞爲操章。"]'),
('3a04bafe-8f74-4f57-849c-3067d2e08eb9','山中雪後頗有春意','張嵲','宋','宋诗','song-poetry','','[]','山明雪猶積，林白梅已綻。',60,'全唐诗/poet.song.105000.json','["山明雪猶積，林白梅已綻。", "凍泉時斷續，晴雲既流爛。", "山空樵者歸，樹響遊蜂散。", "愁同平子多，游比相如倦。", "晞髮近陽阿，長歌何時旦。"]'),
('eda0468b-aace-4d0b-b3a5-4675df137e79','癸亥生日前一日讀神仙李清傳作','張嵲','宋','宋诗','song-poetry','','[]','孟夏倐已晚，詰旦及懸弧。',180,'全唐诗/poet.song.105000.json','["孟夏倐已晚，詰旦及懸弧。", "推遷驚歲序，俯仰念勞劬。", "感物嘆漂泊，撫已既叨踰。", "去事日已遥，來者言足圖。", "澹漠遠世紛，超遥觀道書。", "伊昔有勝士，染工藏市區。", "感悟及生朝，欲訪仙人閭。", "自縋投絕壑，果諧欣願初。", "塵念雖少牽，脫屣終不渝。", "一死會當有，貴賤理必俱。", "萬事惟一捨，此外無復餘。", "李君本市人，而予豈非夫。", "躡屐千仞崗，振策萬里塗。", "暫愒即弱水，款闗必清都。", "千載復來歸，陵谷知焉如。"]'),
('0a74c5f1-f800-49cc-a4d7-f1b75c91f3f3','將請鄉郡作','張嵲','宋','宋诗','song-poetry','','[]','本初休車騎，陶令歸田園。',180,'全唐诗/poet.song.105000.json','["本初休車騎，陶令歸田園。", "憧憧天壤間，何人無一廛。", "惟我若斷梗，漂流淛江邊。", "牽絲始立歲，屏處知命年。", "虚恬因勢使，憔悴仍化遷。", "愧無楊僕功，居不外漢闗。", "又非穉季俠，徒使墻垣穿。", "欲收衰病身，迤邐還故山。", "風波渺萬里，欲去無由緣。", "願竊刺史符，一臨江漢壖。", "敢同晝繡歸，僅比遼鶴翻。", "送老得三徑，奉親歸九原。", "如斯志願畢，天恩真滿泉。", "所祈造物心，俯狥人欲偏。", "决策在今歲，無令辜願言。"]'),
('854e55a8-01e5-4bdf-a837-82cf16c71d22','上二溪山','張嵲','宋','宋诗','song-poetry','','[]','積雨連日夜，敢謂今旦晴。',288,'全唐诗/poet.song.105000.json','["積雨連日夜，敢謂今旦晴。", "綠彩泛林端，愛此朝景明。", "晨炊肅徒馭，結束方上征。", "千巖屹穹隆，萬壑臨峥嶸。", "誰知有微逕，在此蒼翠屏。", "昔聞五尺道，馳心已伶俜。", "今朝復何朝，冒此絕險行。", "側路不容足，下瞰千仞阬。", "步武一蹉跌，隕身如建瓴。", "避地本愛死，兹行豈偷生。", "籃輿仗傖人，崎嶇信所經。", "下爲崖石礙，上苦蘿蔓攖。", "陰巖多沮洳，泥苔汏相仍。", "薄暮雨欲來，白雲起如蒸。", "稍觀前山暗，已復如懸繩。", "行行入中林，心悸萬皷鳴。", "三泉如雪翻，競瀉石上聲。", "值此絕世景，避賊難爲情。", "路轉復臨川，濁流方滿盈。", "波神恣桀鷔，勢欲丘壑平。", "雄張擁行潦，河瀆將抗衡。", "我方媚斯水，敢誇海若名。", "呌度雨踰急，山烟深杳冥。", "捨棹即絕壁，扶持陟碐層。"]'),
('b233b4dd-1749-4624-8290-8f834ecb678c','上楮平山','張嵲','宋','宋诗','song-poetry','','[]','層陰生萬里，歲晚嵐霧昏。',120,'全唐诗/poet.song.105000.json','["層陰生萬里，歲晚嵐霧昏。", "終日轉盤道，那知入寒雲。", "忽上最高頂，劃見衆山繁。", "嵯峨揷蒼旻，迫窄塞厚坤。", "俯仰混一氣，眺聽屬無垠。", "直欲遡豐隆，逝將排帝閽。", "小臣敢上訴，邊塵暗中原。", "天寧忍下土，厭此豺虎群。", "庶幾動真宰，一洗戎馬氛。", "此意復茫昧，側佇揚精魂。"]'),
('15aecfe4-6295-4dad-8574-6e696e741352','劉谷山','張嵲','宋','宋诗','song-poetry','','[]','奉令事設險，兹山再經歷。',204,'全唐诗/poet.song.105000.json','["奉令事設險，兹山再經歷。", "歲暮陰雲昏，雪後杉桂碧。", "修篁亞路低，老木參天直。", "下瞰穹谷中，衆樹紛若戟。", "或爲龍蛇鬬，或作熊虎躑。", "陰崖不受春，冬带輪囷色。", "古苔如綠毛，因依露猶滴。", "陰風忽動谷，衆籟久方寂。", "儻非神物居，定有龍蛇宅。", "山陰魏家平，百丈峙絕壁。", "戰樓摩雲霄，武帳侵斗極。", "鈎援諒無庸，梯衝當棄絕。", "雖無墨翟守，天險豈所敵。", "攬勝心以愉，經險情屢惕。", "撫事既靡愆，微驅諒安惜。", "何當四海晏，誅茅此投迹。", "詩成無與言，搔首三歎息。"]'),
('cb4f054c-a13f-475e-9cc2-19a584f26e46','野竹','張嵲','宋','宋诗','song-poetry','','[]','野竹何修修，森然滿山麓。',60,'全唐诗/poet.song.105000.json','["野竹何修修，森然滿山麓。", "清溪潄蒼根，夜雨滋寒玉。", "幹密風豈揺，林深鳥應宿。", "蒼山黄葉中，見此歘驚目。", "經行一回首，何用慰羈束。"]'),
('76b92506-1ffa-455e-9f65-0c7ba9396b99','穗粟','張嵲','宋','宋诗','song-poetry','','[]','世亂棄祿仕，居間食苦貧。',144,'全唐诗/poet.song.105000.json','["世亂棄祿仕，居間食苦貧。", "置田上庸山，稍依農畝鄰。", "歲入無幾何，誅求方荐臻。", "老農幸導我，播植當自勤。", "晨起具餱糧，伐木西澗濱。", "畬田去歲秋，稸粟今年春。", "肥磽半百畝，良苗生已勻。", "監督課子弟，耘耔煩隸人。", "所望在一飽，詎敢悲苦辛。", "及此歲將晏，場功躬自親。", "所得未償費，相顧但深顰。", "歸去且讀書，愧兹百年身。"]'),
('1499c0e9-dd9f-4285-8e4e-50ca49eed98f','將池僧舍東軒曉起','張嵲','宋','宋诗','song-poetry','','[]','兹軒臨絕頂，遠與前山平。',84,'全唐诗/poet.song.105000.json','["兹軒臨絕頂，遠與前山平。", "睡起月初上，冷冷曉風清。", "暗嶺躍飛雷，白雲出疏星。", "四顧莽不辨，惟聞候蟲鳴。", "居人正酣寢，我已事晨征。", "思婦閨中意，游子天外情。", "策羸取微徑，羈夢何由成。"]'),
('f802e938-d449-4a4d-a148-c640beebf39b','種竹','張嵲','宋','宋诗','song-poetry','','[]','屏居倦幽獨，出門無所適。',168,'全唐诗/poet.song.105000.json','["屏居倦幽獨，出門無所適。", "種竹滿前庭，坐玩凌寒色。", "森森密陰净，竦竦條幹直。", "晴日借景光，霜風時蕩析。", "自我來此居，三見歲華易。", "小孫漸成童，長楊憶初植。", "雜花亦紛然，似欲娱閴寂。", "世慮久已忘，况乃頭半白。", "舊鄉喪亂後，城郭滿荆棘。", "藉使能北歸，亦不異作客。", "獨懷首丘念，未易忘日夕。", "讀書計誠謬，習静理何益。", "萬事鳥過空，何處留遺跡。", "世故漫酬酢，迢遥混今昔。"]'),
('a7629e4c-6f14-4950-8521-ecb5cfeaf77e','庚申寒食湖上作','張嵲','宋','宋诗','song-poetry','','[]','今朝寒食節，撥撒揮涕餘。',84,'全唐诗/poet.song.105000.json','["今朝寒食節，撥撒揮涕餘。", "何心事游行，誰使膏我車。", "出門悟春遠，綠遍萬里塗。", "陰林雜花稀，巨樹新葉敷。", "春風慰游客，蕩漾回衣裾。", "舉杯復置杯，岸幘唯平湖。", "豈無坐上客，不見朱與徐。"]'),
('087335f4-491d-4ee6-9cba-b8afc1536933','四月旦大雨晝夜不止者兩日微水一夕暴漲','張嵲','宋','宋诗','song-poetry','','[]','山木綠陰暗，駭雲當晝繁。',156,'全唐诗/poet.song.105000.json','["山木綠陰暗，駭雲當晝繁。", "驚風乍掩冉，積雨連荒村。", "映岫若銀竹，瀉澗如翻盆。", "懸霤遂及旦，暗空還至昏。", "長川怒方蓄，濁浪正崩奔。", "暫見没岸草，已復侵山樊。", "衝波激遠嶼，聚沫旋林根。", "劈箭揺定目，殷雷驚客魂。", "俄吞衆瀨没，瀺灂成奫輩。", "波神信雄桀，灝漾方無垠。", "儻不究其源，豈辯河瀆尊。", "朝盈暮已竭，暫滿安足論。", "明旦立沙尾，若带青沄沄。"]'),
('3f693abc-f8fb-4661-bcff-7dc0a80d4825','七月初四日小雨後遊步水邊','張嵲','宋','宋诗','song-poetry','','[]','雨止林葉浄，遊步喜川平。',48,'全唐诗/poet.song.105000.json','["雨止林葉浄，遊步喜川平。", "停午衆陰寂，山高一蟬鳴。", "境静道心熟，世疏塵慮輕。", "凉飈颯已至，自適羲皇情。"]'),
('16d96a92-b82c-49b1-b009-cc6cf054ccd0','和張簿韵','張嵲','宋','宋诗','song-poetry','','[]','平昔志升車，年來但芒屨。',168,'全唐诗/poet.song.105000.json','["平昔志升車，年來但芒屨。", "前旬返城邑，宵旦未踰數。", "及兹復入山，始覺離亂苦。", "行行望遠峰，山村猶幾許。", "風清初戒寒，雲垂欲收雨。", "羸馬尚嘶林，吾行已遵渚。", "茂樹曩堪攀，澄潭今可俯。", "秋意滿山川，微烟澹村塢。", "經過竹籬側，倦極欣一語。", "三鍾應昔志，一室固堪處。", "去留非本心，偶地因爲主。", "野屋盡茅茨，山田多瘠鹵。", "菽粟工療饑，薯蕷行堪煮。", "一水可乘流，從公公莫禦。"]'),
('217c2951-6ef2-4843-80b9-8f1a2d064ca7','雪中泛漢水觀捕魚','張嵲','宋','宋诗','song-poetry','','[]','既遊天漢地，復泛清漢流。',120,'全唐诗/poet.song.105000.json','["既遊天漢地，復泛清漢流。", "我本襄漢人，對酒集百憂。", "是時雲氣昏，雪片迷汀洲。", "沉沉百丈潭，坐看漁子游。", "重裘憫渾脫，得雋憐深投。", "舞空清渚逈，遍積修篁幽。", "山川疑舊里，歌舞迷新遊。", "薄暮理歸棹，中流任夷猶。", "忽驚在鄉社，誰辨陰成樓。", "歘知非舊邦，汍瀾涕難收。"]'),
('95f8caa7-f39e-4b56-aaef-a1dd155f8e87','感事二事  其一','張嵲','宋','宋诗','song-poetry','','[]','西山一丸藥，終當持遺親。',60,'全唐诗/poet.song.105000.json','["西山一丸藥，終當持遺親。", "奈何嗜利者，藉口託愛君。", "太真絕袖去，中興爲名臣。", "功業竟誰歸，老嫗終苦辛。", "大恩竟不報，初無烏鵲仁。"]'),
('98180afb-070c-4a0e-8b90-85f9bf6a8512','感事二事  其二','張嵲','宋','宋诗','song-poetry','','[]','投身螭鬽域，寧免衆鬼欺。',192,'全唐诗/poet.song.105000.json','["投身螭鬽域，寧免衆鬼欺。", "黄昏風雨集，所向道路迷。", "一鬼在前嘯，群鬼争和之。", "從以衆妖鳥，紛披鳴樹枝。", "訓狐當傍呌，破獍隨後啼。", "斯須哭土梟，次第嘷狐狸。", "睢盱恣陵傲，踸踔争新奇。", "變態遂百出，殽然當此時。", "胡爲乃歷兹，側佇成𥈭眙。", "其始爲股栗，慘悽粟生肌。", "懼以柔脆軀，遂爲衆鬼糜。", "其中稍自定，注視但嗟咨。", "其終乃釋然，堅坐翻愉怡。", "鬼見不爲動，技窮將罷歸。", "人命固有常，此物終何爲。", "遲留待明發，請與衆鬼辭。"]'),
('317a2468-4227-4269-88a8-37d7c40b40d4','春晚風雨甚暴衡門獨立望微水有作','張嵲','宋','宋诗','song-poetry','','[]','中原殊未平，避地甘羈束。',48,'全唐诗/poet.song.105000.json','["中原殊未平，避地甘羈束。", "著意問樵漁，尚恐驚麋鹿。", "出門亦何事，望望清江曲。", "雨氣晚來寒，驚風亂新綠。"]'),
('d9f72f1c-622f-4195-b681-419f6f62f860','方城驛','張嵲','宋','宋诗','song-poetry','','[]','古驛藏幽谷，回環亂峰稠。',108,'全唐诗/poet.song.105000.json','["古驛藏幽谷，回環亂峰稠。", "驛前山特秀，翠氣光浮浮。", "晴日經短簷，奇温驚敝裘。", "門前萬山道，過客空悠悠。", "憶昔廬戢黎，伐庸此淹留。", "山中老鸛鶴，應識旌斾愁。", "事去一轉首，巖花幾經秋。", "石碐與澗道，猶是曩者否。", "秪應軍旅聲，長咽寒溪流。"]'),
('62d9cb27-24a6-44d4-8e98-943cd6cc3d40','遊靈巖寺','張嵲','宋','宋诗','song-poetry','','[]','吳王避暑地，西施採香路。',156,'全唐诗/poet.song.105000.json','["吳王避暑地，西施採香路。", "陵谷偶未移，山川尚如故。", "遺宫俱泯滅，輪奐乃僧户。", "梵放想遺轉，考槃疑簨簴。", "繁華隨化遷，歘若高鳥度。", "憂勤及豫怠，興隆與傾仆。", "何異貉一丘，同歸易晞露。", "平湖際遠海，環山莽回互。", "澗草足芳菲，山泉多沮洳。", "昔人經行處，賞會今已屢。", "来者復爲誰，將亦遵往步。", "新故更遞代，一往復何故。", "日暮鐘磬閒，聊將澹吾慮。"]'),
('f2a2df3a-af13-4205-b419-681cb85819f8','南澗亭詩','張嵲','宋','宋诗','song-poetry','','[]','行穿密竹盡，勝概集斯亭。',96,'全唐诗/poet.song.105000.json','["行穿密竹盡，勝概集斯亭。", "地遠嵐光重，冬溫草木青。", "俯鑒含空水，還觀山作屏。", "巖溜有時歇，松聲無暫停。", "遐思南澗作，彷彿識儀刑。", "世緣因歲闊，静習與心冥。", "離人慕肥遯，駐屐戀巖扄。", "不似投荒柳，悲吟涕淚零。"]'),
('bc424590-1f1e-409d-9534-31114c86c2ff','入峡','張嵲','宋','宋诗','song-poetry','','[]','天秋萬象静，雲横亂峰起。',288,'全唐诗/poet.song.105000.json','["天秋萬象静，雲横亂峰起。", "已下微王山，入峡自兹始。", "驚湍扵此盡，安流澹如砥。", "兩山鬰嵳峩，壁立相對峙。", "上凌空崇外，下插渌浄底。", "層巖碧樹滋，洄潭丹葉委。", "舟行石罅中，江流瓮城裏。", "舉頭天若带，墮此清瀰瀰。", "忽驚龕巖大，奔浪喧客耳。", "魚陀考方言，歲出魚萬尾。", "水邊菖蒲青，石上土花紫。", "淙流来不絕，無由訪源委。", "俄經陳佗洞，斬絕不容趾。", "土人若猿猱，躋攀因葛藟。", "燃火入其中，數丈神披靡。", "睹兹泉壑迥，始覺化工偉。", "投身西南陬，肆意閲奇詭。", "是邦不生人，境勝乃如此。", "寕非造物初，意盡向山水。", "神驚畏石墜，志豁欣樹美。", "窮探日易晚，惜去船欲舣。", "徐聞湧波濤，漸見山峛崺。", "奇觀忽鶩過，我興方未已。", "賴此慰羈愁，無庸傷轉徙。"]'),
('135be826-8dd3-4d26-809d-74269329c66e','過楊村溪','張嵲','宋','宋诗','song-poetry','','[]','坡陁兩山間，滄波旦夕騖。',120,'全唐诗/poet.song.105000.json','["坡陁兩山間，滄波旦夕騖。", "高柳横澄流，歲久根全露。", "細雨川上来，瀾漪滿沿泝。", "灌木生退灘，危橋架孤嶼。", "石瀨斵春冰，山雲粉輕絮。", "往歲憶經過，物色如雅素。", "陽春日已遠，嘆息流年度。", "来軌不暫停，往躅自成故。", "初爲閩嶺遊，後指江東去。", "風急子規啼，何由傍歸路。"]'),
('11e8c06c-b14a-4802-b09f-ec4d92b18ecd','春晝睡起偶書二首  其一','張嵲','宋','宋诗','song-poetry','','[]','忽忽掩關卧，起来春日曛。',48,'全唐诗/poet.song.105000.json','["忽忽掩關卧，起来春日曛。", "和風吹草木，雜花紛已繁。", "他鄉農事興，悽然懷故園。", "青山雖滿眼，何用慰憂煩。"]'),
('9595099c-c696-488f-807f-d8a6f2385b16','春晝睡起偶書二首  其二','張嵲','宋','宋诗','song-poetry','','[]','閉户長春草，日晏獨高眠。',84,'全唐诗/poet.song.105000.json','["閉户長春草，日晏獨高眠。", "起步遶廣庭，愛此風景妍。", "青山羅郭外，白日當中天。", "坐見柳意濃，亦知花向殘。", "鷄鳴水外村，人耕原上田。", "玩物意方適，居閒情轉延。", "忽悟是作客，驟使心悁然。"]'),
('f23df588-9c0b-4d42-879d-4fa5b96eb516','五月二十四日自達州至永睦縣投宿廢學即事書懷','張嵲','宋','宋诗','song-poetry','','[]','學廢鄉校空，鳥雀欲據有。',276,'全唐诗/poet.song.105000.json','["學廢鄉校空，鳥雀欲據有。", "甚雨晚来晴，循簷厭黄口。", "巴水亦能大，一暮沒堤柳。", "落照滿漲川，歸雲翼山岫。", "達州去未遠，望望空回首。", "母老兒未齚，何苦事西走。", "輕生冒畏塗，用意在升斗。", "三復禱雨辭，此道廢已久。", "恭聞賢侍郎，求才如恐後。", "密置鄭莊驛，屢接鬷蔑手。", "英俊頗雲集，巖穴猶輻湊。", "菅蒯且不遺，豈獨棄枯朽。", "矧嘗辱英盻，屢以温言授。", "私心頗感激，嘗欲事奔走。", "攪衣中夜起，頮面不盡垢。", "平生慕藺心，已在轅門右。", "某也濩洛人，時命大不偶。", "讀書慕經濟，頗亦略句讀。", "雅意死知已，且復羞自售。", "耻爲轅下駒，終若喪家狗。", "遭亂乏禄食，避地闕田畝。", "栖栖窮塗間，但未操井臼。", "我公寕忍茲，無令混樵叟。"]'),
('8ad3003c-64d7-49a2-8b61-eef67b69a421','去年十一月十二日致宏如秦州僕餞之餘口復到生口作别明年六月十二日僕自竹山避地泝流上餘口道由生口復經分手之地感時書事奉寄致宏時建炎四年也','張嵲','宋','宋诗','song-poetry','','[]','憶昔游河梁，對床三夜語。',288,'全唐诗/poet.song.105000.json','["憶昔游河梁，對床三夜語。", "平生慷慨心，遠别顔亦苦。", "朔風黄葉深，尚記驅車去。", "君行已映林，我首猶屢顧。", "重經分手地，物色宛如許。", "懷人感河山，撫節驚寒暑。", "别来世事多，瑣細不足數。", "惟有綠林徒，跳梁猶若故。", "漢南十二州，一半爲盜據。", "向之西来師，猛鷙類熊虎。", "從以萬馬群，旌旃蔽村塢。", "惟知口打賊，未辨狸搏鼠。", "徵求徒浚民，萬分一無補。", "空令貧者斃，復使富室窶。", "去年粟如金，艱食古未睹。", "今春瀕漢州，秋種不入土。", "如何十萬師，不辦一朝貯。", "傳聞許汝郊，平民盡俘擄。", "秋高馬首南，跬足仰誰禦。", "棲山無定居，處邑復多懼。", "無資憂殍踣，有粟畏攘取。", "懷安昔所戒，隨衆謀遠舉。", "第恐向他州，未保終安堵。", "悠悠四海間，託身定何所。"]'),
('1f14fd1e-970a-4137-a0d0-94280d640c0f','過大包閣寄夏漕致宏','張嵲','宋','宋诗','song-poetry','','[]','積雪天欲晴，山深霧猶擁。',192,'全唐诗/poet.song.105000.json','["積雪天欲晴，山深霧猶擁。", "大包誰締結，架壑一何聳。", "崕傾石路仄，峡束驚波湧。", "垂堂尚何言，顛墜虞接踵。", "經過固已殆，卻顧神屢悚。", "前山淨如洗，浩浩雲根動。", "崕花作蜜香，山童似猴拱。", "舊鄉迷遠近，所歷但如夢。", "窮通久已忘，况此髪種種。", "猶欣故人近，寛我懼將恐。", "語亂眉定顰，道舊腹應捧。", "燈前侍兒出，花外寒煙重。", "羈懷醉裏寛，離念風前恫。", "游宦愧吹竽，劇談猶賈勇。", "觀君富聲華，顧我成闒茸。", "行臺定匪賒，失喜欲距踴。"]'),
('09a00376-7d3a-4a94-a638-69553b9ea8f7','南山觀梅','張嵲','宋','宋诗','song-poetry','','[]','春雪欲垂地，春水縠紋浮。',120,'全唐诗/poet.song.105000.json','["春雪欲垂地，春水縠紋浮。", "亂山無人到，梅花供客愁。", "輕風側烏帽，韶序欺白頭。", "攀條記舊賞，嗅蘂悲前遊。", "斜日忽反照，煙華風際流。", "已歎繁華盛，俄觀青蔭稠。", "沉吟兩京路，惻悵瀕漢洲。", "尚想萬玉妃，清樽交獻酬。", "天涯歎憔悴，覽物空夷猶。", "飲罷不能賦，臨風三歎休。"]'),
('634337c3-1d28-4d30-9359-8c02cc6528ee','晨起登寺閣前山爲霧覆微露山麓宛如平遠偶書春物','張嵲','宋','宋诗','song-poetry','','[]','日出霧猶重，微茫認山麓。',156,'全唐诗/poet.song.105000.json','["日出霧猶重，微茫認山麓。", "遠目疑可窮，澶漫如夷陸。", "韶序日已深，時禽囀幽谷。", "青林不受春，景氣潤脩竹。", "日晴烟光亂，風澹水容渌。", "閩嶺農事初，荒泉被山曲。", "耒耜没深泥，鳬鴨讙相逐。", "躬耕記往年，遭亂成羈束。", "故園隔山河，桑柘猶在目。", "丘隴諒荒蕪，春歸惟灌木。", "囚拘愴兹晨，儻徉悲前躅。", "緣情固攀援，理會何桎梏。", "且寄終日閒，玩此春苗綠。"]'),
('0534fe0f-bd0c-482c-813f-f9db2ad68998','廬陵曾氏臨江作亭以舍過客因同舍来求詩','張嵲','宋','宋诗','song-poetry','','[]','亂後足漂零，所至倦遷客。',48,'全唐诗/poet.song.105000.json','["亂後足漂零，所至倦遷客。", "那知此江上，飛亭跨穹石。", "客来贛山青，客去贛水寂。", "徙倚亭上人，悠悠往来陌。"]'),
('c73cefcb-245d-4512-bdab-1fb29243c472','月下觀海棠','張嵲','宋','宋诗','song-poetry','','[]','澄空流華月，列炬林梢綴。',48,'全唐诗/poet.song.105000.json','["澄空流華月，列炬林梢綴。", "衆焰爍明霞，紅曛花似醉。", "流連陶嘉月，共惜春風駛。", "預歎他日來，餘紅紛滿地。"]'),
('68bb1785-87c7-4c3c-bdc2-88e6bf414458','贈别','張嵲','宋','宋诗','song-poetry','','[]','艾杼滅澆殪，方召平夷蠻。',288,'全唐诗/poet.song.105000.json','["艾杼滅澆殪，方召平夷蠻。", "夏書紀少康，小雅詠周宣。", "茂烈蓋當代，休聲垂億年。", "君臣今望之，猶若神人然。", "皇天昔降亂，國步多艱辛。", "海宇政揺蕩，封疆託大臣。", "召旻歌卒章，三復徒愴神。", "寇攘有厚賞，山林多賤貧。", "小夫矜寵秩，持以傲寒士。", "達人每大觀，詎肯屈其志。", "從人畏損名，不從斯逆耳。", "骯髒每不容，委隨多狥死。", "孔明佐玄德，君臣稱魚水。", "田祖輔本初，愎諫昧良圖。", "蜀成鼎足勢，臥龍名益都。", "袁喪官渡師，二臣隨見屠。", "女蘿依青松，蘞蔓相綿延。", "歲暮饒雪霜，枝幹猶縈纒。", "蔓草生毁垣，逢時亦芊芊。", "積雨毁垣墜，苕頴亦以乾。", "婉婉我良友，才具宜佐時。", "果敢無與前，議論有餘資。", "功名可立致，要當慎其爲。", "吳橘北化橙，良玉貴不緇。"]'),
('6819633a-e26a-465b-a62d-b994b6014809','再經蒲溪往年避地處','張嵲','宋','宋诗','song-poetry','','[]','淹流既失策，賊至甘遠屏。',72,'全唐诗/poet.song.105000.json','["淹流既失策，賊至甘遠屏。", "往歲憶曾遊，逕路猶可省。", "今来冬向除，昔至夏方永。", "山寒竹樹疏，歲陰雲霧冷。", "破屋今已無，荒筠蔓枯穎。", "昔人安在哉，經過涕垂領。"]'),
('0fca0559-288a-41f4-8e2a-2aa5f563e8ec','窮陰忽霽獨往山下看梅','張嵲','宋','宋诗','song-poetry','','[]','千峰雪猶積，萬木春已迴。',108,'全唐诗/poet.song.105000.json','["千峰雪猶積，萬木春已迴。", "窮陰倦羈束，忽欣陽景開。", "徐步出衡門，中野展幽懷。", "杖策遂侵尋，獨下前山隈。", "驚湍激遠飈，疏篁耿寒梅。", "婆娑時動容，似與客徘徊。", "歲晏益多感，况斯韶景催。", "暫賞豈所懽，離念方催頽。", "還觀增愴惻，三歎爲誰來。"]'),
('c5138de5-9060-4ab3-a019-747624a61b8a','鳴筑亭','張嵲','宋','宋诗','song-poetry','','[]','碕岸互縈斜，因依愛筠綠。',36,'全唐诗/poet.song.105000.json','["碕岸互縈斜，因依愛筠綠。", "雖疑境過清，未必傷幽獨。", "偶坐松下石，泉聲作琴筑。"]'),
('71e83cca-d645-4f1e-bfc5-df6ea7989b50','贈趙端','張嵲','宋','宋诗','song-poetry','','[]','殘方歲已晏，層陰萬里生。',84,'全唐诗/poet.song.105000.json','["殘方歲已晏，層陰萬里生。", "何如苦寒際，子有關陕行。", "風煙正浩蕩，夜雨吹成冰。", "時危壮士志，日暮游客情。", "感子請别意，令我肝膽傾。", "告之以盡言，念子遠徂征。", "聊代繞朝策，勉旃圖令名。"]'),
('a2ae3de3-fc8d-4d6f-8215-9dae4a2d7ea7','贈陳符寶去非','張嵲','宋','宋诗','song-poetry','','[]','大雅久不作，此風日蕭條。',108,'全唐诗/poet.song.105000.json','["大雅久不作，此風日蕭條。", "紛紛世上兒，啁啾亂鳴蜩。", "唯公妙句法，字字陵風騷。", "如鼓清廟絃，聽者無淫滔。", "癯瘦藏具美，和平蓄餘豪。", "思苦理自寄，志深言益高。", "顧我吟風苦，知公心力勞。", "世無杜陵老，誰知何水曹。", "柳韋儻可作，論詩應定交。"]'),
('a63b61d8-5fb4-4c2c-acf7-0a99d553dfb1','贈元方叔','張嵲','宋','宋诗','song-poetry','','[]','吾叔超世士，筆力回狂瀾。',96,'全唐诗/poet.song.105000.json','["吾叔超世士，筆力回狂瀾。", "作詩到合處，未謝春草篇。", "罷官守環堵，冷屋風蕭然。", "操尚非矯世，静退真所安。", "慷慨引濁醪，俛默窺塵編。", "冥搜得新語，自喜欲忘年。", "常言畢婚嫁，歸老漢水邊。", "此意有真趣，勿爲兒輩言。"]'),
('3fc1695c-2fa1-49f8-b0e8-405765661660','與孫太冲游湖上寺','張嵲','宋','宋诗','song-poetry','','[]','作客歲月久，新春生白鬚。',144,'全唐诗/poet.song.105000.json','["作客歲月久，新春生白鬚。", "淹留竟何爲，閉戶猶繙書。", "今朝天氣佳，逍遥步城隅。", "初旭野尚晦，青草含露濡。", "好風如有期，微漪滿平湖。", "白日照原野，青山開畫圖。", "晴林峰外稠，壊塔煙中孤。", "山坳見修竹，游步得僧居。", "地偏蘭茝芳，氣暖夭桃舒。", "何年深宫姬，藁葬依浮圖。", "一往随化遷，豈復平陽車。", "顧之三歎息，不飲定何如。"]'),
('a74f2831-032a-4d2e-9841-bee5e08a2fa4','醒心泉','張嵲','宋','宋诗','song-poetry','','[]','幽泉清見石，停停映山樹。',72,'全唐诗/poet.song.105000.json','["幽泉清見石，停停映山樹。", "風定絕漪瀾，雨餘多沮洳。", "適諧塵外心，時来澹吾慮。", "靈竇幾年開，何由訊源委。", "泉上木陰稠，交柯存清泚。", "憶昔遊杏山，蒙泉政如此。"]'),
('9e551eca-4e8d-40f2-8966-c405e129613a','溪水','張嵲','宋','宋诗','song-poetry','','[]','溪水東流去，何時合大江。',48,'全唐诗/poet.song.105000.json','["溪水東流去，何時合大江。", "豈無雙鯉魚，附書還故鄉。", "不憂溪水遲，所恨壠坂長。", "臨流一歎息，四顧山蒼蒼。"]'),
('214d4e7d-1782-459a-a128-f4c209807d9e','渡溪水','張嵲','宋','宋诗','song-poetry','','[]','清溪寒不流，空明涵萬象。',144,'全唐诗/poet.song.105000.json','["清溪寒不流，空明涵萬象。", "連山倒景來，顧盼迷俯仰。", "雲浮潭底深，鳥度鏡中往。", "悠悠寒藻疏，一一游魚上。", "危橋颭長硔，行客情屢愴。", "溪傍萬竿竹，矗矗倚崕嶂。", "蒼根带古色，落葉墮深廣。", "陰森暗藩籬，蕭摵掃空曠。", "無人結茅茨，有客契心賞。", "物外識遠情，天邊知旅况。", "野店猶遠煙，僕夫力難強。", "何以紓我懷，浩歌聊自放。"]'),
('189f6a99-86e2-447a-a336-9a2981819019','勸農','張嵲','宋','宋诗','song-poetry','','[]','奉詔勵農耦，建旟行近郊。',144,'全唐诗/poet.song.105000.json','["奉詔勵農耦，建旟行近郊。", "流雲生薄陰，遠色澹平皋。", "溪口逾散渙，山遠始岧嶤。", "柔荑展翠茵，穹石架長橋。", "暫休佳士廬，竹樹干雲霄。", "步障疑圍飾，雜花競嫺妖。", "粧面羞短垣，兒童驚鼓鐃。", "皇恩信廣大，祇事因遊遨。", "競識使君車，夫婦雜顛毛。", "竟夕不知回，偃月生林梢。", "已舉候亭火，猶滯川上橈。", "撫已愧民氓，歸思戒屯膏。"]'),
('fe146ff3-da89-4091-8d6d-a0d64d49db1c','沐髪','張嵲','宋','宋诗','song-poetry','','[]','今旦一沐浴，廢兹簡編功。',48,'全唐诗/poet.song.105000.json','["今旦一沐浴，廢兹簡編功。", "讀書豈常懃，鞭策常自攻。", "繄予髪種種，力此将何庸。", "不如掩卷坐，前山翠濛濛。"]'),
('37f68af9-4268-4a2c-aeb8-4b98e53e9059','瘦','張嵲','宋','宋诗','song-poetry','','[]','駑馬固多肉，元鶴原骨輕。',48,'全唐诗/poet.song.105000.json','["駑馬固多肉，元鶴原骨輕。", "以彼棧豆意，方此雲霄情。", "汨汨世紛遠，蕭蕭中慮盈。", "将尋包道士，一問昇天行。"]'),
('ed647ddf-17b5-48df-add4-29bf3ed7686a','暑雨遂如深秋','張嵲','宋','宋诗','song-poetry','','[]','炎蒸成積雨，異候無寒暑。',60,'全唐诗/poet.song.105000.json','["炎蒸成積雨，異候無寒暑。", "睡覺無餘聲，清燈翳復吐。", "長年遭喪亂，萬事其誰語。", "愒日閲流年，茫然忘去取。", "諒無經世心，還山藝禾黍。"]'),
('23934164-f8f4-44b6-8b25-b7c74773d436','登真觀在利州嘉川縣西五里南臨宋江相傳云張天師棲真之地至今有遺履池縣下二十餘里江心有積石土人謂天師殯鬼堆石上有紋隱起類篆籀土人謂天師符觀中多大柏連抱皆數百年物也又有鐵鑄老君二其一已損六月初五日少息觀中聞其事于小童與石刻頗驗云','張嵲','宋','宋诗','song-poetry','','[]','天師羽化久，殊館臨官道。',84,'全唐诗/poet.song.105000.json','["天師羽化久，殊館臨官道。", "繫馬松門深，風清亂蟬噪。", "開基今幾時，庭樹皆連抱。", "有池號遺履，無地尋丹竈。", "金像獨儼然，詎識何人造。", "學仙匪吾事，訪古乃其好。", "物色聊默存，他年憶曾到。"]'),
('e8865823-68ec-4893-8bd5-ad58d8c2bdd1','贈黄子真','張嵲','宋','宋诗','song-poetry','','[]','再来居檇李，又枉故人車。',84,'全唐诗/poet.song.105000.json','["再来居檇李，又枉故人車。", "故人固是客，我居豈吾廬。", "共在天之涯，猶如水中鳬。", "細話漢傍事，想見江紆餘。", "死者不可作，生者多離居。", "無輕今日别，與子皆白鬚。", "臨分尚何言，早寄江陰書。"]'),
('a21c5ab7-833b-4847-baa9-542a845a05cf','齋祠湖上作','張嵲','宋','宋诗','song-poetry','','[]','還山映平湖，未厭傷極目。',120,'全唐诗/poet.song.105000.json','["還山映平湖，未厭傷極目。", "籃輿值初晴，步步轉湖曲。", "宿霧鬰喬林，寒曦煦穹谷。", "廢刹今幾時，浮圖在山腹。", "村荒樵牧多，歲晚稉稻熟。", "曲岸倒菰蒲，回潭聚鳬鶩。", "前瞻嵐嶺分，右顧緣原綠。", "遊眺暫蕭疏，沉吟反羈束。", "齋祠奉簡書，尸素慙微禄。", "日暮聞幽禽，睠此林下宿。"]'),
('e41f02e6-f9f7-443f-a2b7-b89920b75be5','四月十一日遊湖上作','張嵲','宋','宋诗','song-poetry','','[]','餘花送春暮，群綠迎夏初。',120,'全唐诗/poet.song.105000.json','["餘花送春暮，群綠迎夏初。", "清晨出郡郭，溪山含雨濡。", "宿靄昏近麓，初陽灔平湖。", "空明映山樹，澹淡浮青蕪。", "亭亭天際峰，微茫如有無。", "縱櫂水波闊，叩舷幽意抒。", "白鳥若娱人，盡日鳴菰蒲。", "舉酒一相囑，岸巾清嘯餘。", "佳游雖浩蕩，離念終鬰紆。", "寄與北来客，賞心良自誣。"]'),
('a77f1958-9f44-4a16-ba6c-244697c2e7b0','山中紅葉','張嵲','宋','宋诗','song-poetry','','[]','青女衒微巧，染絳妬春工。',72,'全唐诗/poet.song.105000.json','["青女衒微巧，染絳妬春工。", "如何青林表，忽有萬炬紅。", "渾疑在絕塞，斥堠傳夕烽。", "爛爛爍晚日，燁燁含天風。", "錦繡滿山谷，佳興浩無窮。", "全勝在蕭寺，吟玩廣庭中。"]'),
('592c27c6-2dca-459d-92a0-ddbea420ba3a','泝流入微王峡','張嵲','宋','宋诗','song-poetry','','[]','又上微王峡，山寒含翠霧。',48,'全唐诗/poet.song.105000.json','["又上微王峡，山寒含翠霧。", "青壁盡侵雲，鱗鱗多碧樹。", "山深石狀古，地僻禽聲怒。", "竟日不逢人，茫茫水空注。"]'),
('672a215a-ab9b-42e4-a51c-17aff63e0411','與趙智叔嶬弟泛舟回燈下','張嵲','宋','宋诗','song-poetry','','[]','西風今日寒，細雨濕青嶂。',120,'全唐诗/poet.song.105000.json','["西風今日寒，細雨濕青嶂。", "微江水渌波，大石牽舟上。", "岸菊猶未芳，山木先後黄。", "滿灘圓石浄，兩岸鳴寒螿。", "回舟暮色集，颯颯雨聲急。", "愛此雲林幽，未信衣巾濕。", "初爲山水遊，藉以驅離憂。", "及此賞心盡，翻兹羈客愁。", "来歸向蓬茅，樹黑風蕭蕭。", "背壁青燈暗，山空夜寂寥。"]'),
('d1ed9f39-2669-4a95-bc82-bb326fc0baaf','晨起','張嵲','宋','宋诗','song-poetry','','[]','盥櫛及平旦，曉庭風露清。',72,'全唐诗/poet.song.105000.json','["盥櫛及平旦，曉庭風露清。", "蕭然無一事，對此夏陰成。", "春晚方受謝，孤花有餘榮。", "地遠物性遂，時禽自飛鳴。", "書籍但掩卷，冲虛道已盈。", "非爲隱淪客，自快適野情。"]'),
('98d658ff-a552-4f4d-9420-ab20281aed98','早行','張嵲','宋','宋诗','song-poetry','','[]','平湖望不極，天垂作週遭。',84,'全唐诗/poet.song.105000.json','["平湖望不極，天垂作週遭。", "今朝春風暴，漣漪生微濤。", "高楊明遠村，黄花點青皋。", "可驗去人遠，烏鳶低作巢。", "老年無戲事，即此當游遨。", "浮舟不知遠，但覺白日高。", "煙中何處寺，孤塔冠山椒。"]'),
('f543f587-7a38-4f8a-8e2b-006da80b5013','中秋四十一弟歸自豫章','張嵲','宋','宋诗','song-poetry','','[]','老病罷搜句，空對秋月明。',72,'全唐诗/poet.song.105000.json','["老病罷搜句，空對秋月明。", "寂寥天宇逈，慘慄夜氣清。", "松門委餘照，蕭散此閒行。", "歸来坐庭除，濁酒聊自傾。", "但喜親愛會，豈謂賞心并。", "回思故園夜，惻愴獨緘情。"]'),
('1bf843df-803f-46e9-b15f-661bc3a5e13a','贈相僧楊嬾散','張嵲','宋','宋诗','song-poetry','','[]','野鶴本長生，孤雲無定意。',96,'全唐诗/poet.song.105000.json','["野鶴本長生，孤雲無定意。", "託迹雖世間，游心乃塵外。", "請問絳人年，曾觀柏寢器。", "微言洞倚伏，妙中驚人世。", "往夏識方瞳，今春分别袂。", "飛帆煙雨外，駐錫雲林際。", "逸興輕遠游，滯念牽離思。", "後夜聽鐘鳴，應在寒山寺。"]'),
('b673abcb-646a-4ad4-ad1f-641aa22878ea','喜晴','張嵲','宋','宋诗','song-poetry','','[]','陽春今已歸，孟夏饒草莾。',60,'全唐诗/poet.song.105000.json','["陽春今已歸，孟夏饒草莾。", "積雨樹陰成，新晴渚蒲長。", "前山澗水喧，隔竹黄鸝響。", "一徑度喬林，涓流會心賞。", "野静閴無人，蕭條成獨往。"]'),
('765add14-9fb3-4ebf-b797-23f03e727e5d','題竹','張嵲','宋','宋诗','song-poetry','','[]','南州困歊暑，蔽映資篔簹。',48,'全唐诗/poet.song.105000.json','["南州困歊暑，蔽映資篔簹。", "簾捲午陰静，窗開夕氣凉。", "徑幽憐筍密，庭空喜幹長。", "相期待歲晏，持以凌繁霜。"]'),
('332917a2-72fe-42be-9dc4-e1058f646237','六月初七日雨小止遊蒲溪臨獨木橋而還','張嵲','宋','宋诗','song-poetry','','[]','石岩兩相束，竹樹交柯綠。',48,'全唐诗/poet.song.105000.json','["石岩兩相束，竹樹交柯綠。", "因聽林外聲，遂來幽澗曲。", "濕煙深不散，淺瀨漂寒玉。", "木杪見雲生，前峰聊注目。"]'),
('e6829918-045d-4eb8-9870-f67e4cdb608b','林鴉詩','張嵲','宋','宋诗','song-poetry','','[]','長楸弄朝日，吳宫聞夜啼。',36,'全唐诗/poet.song.105000.json','["長楸弄朝日，吳宫聞夜啼。", "晨集主人屋，暮宿上林枝。", "如何失儔侣，獨向空林飛。"]'),
('10fc9c39-39e3-47cd-9f71-bb66ddd31df2','西溪','張嵲','宋','宋诗','song-poetry','','[]','西溪泱泱來，佇立溪橋上。',36,'全唐诗/poet.song.105000.json','["西溪泱泱來，佇立溪橋上。", "回風生微瀾，夜雨發幽響。", "聽兹無盡聲，詎覺年華往。"]'),
('26b74677-1155-4170-8460-c36a75eea5d3','曉登靈梵寺閣二首  其一','張嵲','宋','宋诗','song-poetry','','[]','晨氣霧露除，初日照高閣。',60,'全唐诗/poet.song.105000.json','["晨氣霧露除，初日照高閣。", "青山偪歲昏，碧樹霜餘落。", "俯澗愛鳴泉，臨郊美華薄。", "幽情歘自欣，鄉念頻成愕。", "且寄當日閒，無論今與昨。"]'),
('17174e87-7a6f-4697-8d2f-db7a24745eac','曉登靈梵寺閣二首  其二','張嵲','宋','宋诗','song-poetry','','[]','晨登高望閣，愛此經簷日。',60,'全唐诗/poet.song.105000.json','["晨登高望閣，愛此經簷日。", "稍觀宿霧捲，坐見前山出。", "望岫喜林疏，聞泉令竹密。", "與世若相忘，懷人如有失。", "聊此寄晨昏，慚無經世術。"]'),
('b6193aaf-c46c-4576-b6ee-0c49c4c5717c','雨','張嵲','宋','宋诗','song-poetry','','[]','冥冥雲出溪，浩浩風薄木。',84,'全唐诗/poet.song.105000.json','["冥冥雲出溪，浩浩風薄木。", "濕煙驅不散，映岫森雨足。", "場功既云畢，麥隴望已綠。", "矧予無一事，屏處謝追逐。", "霜空晴固佳，雨暗亦所欲。", "悠悠老大心，萬事付所屬。", "獨敢私言潤，活盡新栽竹。"]'),
('d30c6c34-b1e2-4613-a52d-eef818c0cbcf','題景溫筠居','張嵲','宋','宋诗','song-poetry','','[]','昔遊安康道，野竹曉森森。',120,'全唐诗/poet.song.105000.json','["昔遊安康道，野竹曉森森。", "疏籬隱茅茨，置屋何幽深。", "卜鄰嗟未辦，長夢秋風林。", "如何嘉公子，得此蕭寺陰。", "作軒面蒼根，坐卧當幽尋。", "夜雨老苔色，微風助哀音。", "軒前置綠蟻，軒後陳素琴。", "我料之子意，必無朝市心。", "宜邀能賦客，爲擬效古吟。", "折簡索我詩，高詠慚南金。"]'),
('00ea9291-040d-438f-ae77-88cc698a62e0','吊和靖故居','張嵲','宋','宋诗','song-poetry','','[]','頽垣已蕪漫，人事日蕭寂。',72,'全唐诗/poet.song.105000.json','["頽垣已蕪漫，人事日蕭寂。", "賴近青蓮宫，殘僧識遺跡。", "傍連嵐嶺秀，面對湖光溢。", "惟應此如昨，萬變非疇日。", "悠悠夏已深，故沼荷初積。", "振古盡如斯，徒然悵今昔。"]'),
('e0d09523-97b9-453d-b107-929fc9cec412','雪晴','張嵲','宋','宋诗','song-poetry','','[]','陽崖被積雪，照水自光輝。',48,'全唐诗/poet.song.105000.json','["陽崖被積雪，照水自光輝。", "乘暖時時墮，偏憐映日飛。", "經行嗟境勝，去去與心違。", "居者詎知此，日高猶掩扉。"]'),
('17c897d4-5aca-4d8b-b8f3-51decd0df88e','行建溪上是晚同宿小橋感懷書事','張嵲','宋','宋诗','song-poetry','','[]','上庸亂石滿微水，建平孤嶼横中流。',352,'全唐诗/poet.song.105000.json','["上庸亂石滿微水，建平孤嶼横中流。", "驚濤穹隆旋雲繞，經過親見客沉舟。", "建溪物色兩相似，使我惻貯悲西州。", "閩中窮臘春欲動，陳荄已見新萌抽。", "十尋嶺樹森翠葆，百尺瀑泉垂素虬。", "已遭霜露感人意，况復梅花欺客愁。", "沙村呌渡日色晚，野店投宿林燈幽。", "語言不通費辨數，逆旅主人才見留。", "十年敵騎遍寰海，北客走到天南陬。", "天高地逈豈不廣，南来北去皆離憂。", "傳聞敵騎又深入，旃毳欲臨瓜步洲。", "吁嗟華夏半爲鬼，干戈喋血衝斗牛。", "天公亦宜小解事，號令一使災禍瘳。", "刜除欃槍殪旬始，彎弓一矢摧旄頭。", "擢寇之筋洒寇血，永使萬國無戈矛。", "山清海晏氛祲息，地闢天開宗社休。", "黄屋卻臨天北極，紫壇復在郊南丘。", "千官濟濟奉宸扆，萬姓蠢蠢蒙皇猷。", "六營健兒易驅使，四海黎庶依田疇。", "老夫漸得反閭里，汛掃墳墓栽松楸。", "洗耳不聞兵革事，畢命邱樊何怨尤。", "願言秪恐未成遂，作客蹉跎霜鬢秋。"]'),
('4a59340f-d930-4f86-b8fc-633e6024fc86','題均州超然亭','張嵲','宋','宋诗','song-poetry','','[]','君不見綿州官府誠磊落，越王樓觀翔寥廓。',310,'全唐诗/poet.song.105000.json','["君不見綿州官府誠磊落，越王樓觀翔寥廓。", "又不見昔日荆州分上游，舉世獨傳王粲樓。", "蕞然土木何足數，託名勝士真難休。", "何年此地有新構，楊公巧智人誰侔。", "芟夷荒穢走狐鼠，一朝翼瓦飛城頭。", "軒窗四面瞰木杪，下顧衆宇如敦丘。", "卓然獨立世塵外，高視物表心夷猶。", "西山列翠擁雲嶠，漢水拽練縈寒流。", "江楓染絳照林莽，蘆花吐雪連滄洲。", "秋高盡放遠山出，點綴天宇濃眉修。", "人間何處有此景，未識黄樓如此否。", "楊公舉世稱賢侯，好客不减韓荆州。", "仁風惠政已及物，退公餘事歸觥籌。", "我来正值秋節晚，勝概一得從公遊。", "敢辭山路困行役，小舸艤岸聊淹留。", "劇談抵掌去苛禮，賓幙主人交獻酬。", "固知如此興不淺，大白豈惜爲公浮。", "卻思賓散城烏集，回首新亭風景愁。", "聊攄累句寫清賞，作賦能事遲曹劉。"]'),
('408e74ff-8254-47ae-be4a-72e24939f37f','過屈平昭君故宅','張嵲','宋','宋诗','song-poetry','','[]','夔州之山皆入雲，夔女寢陋男不文。',224,'全唐诗/poet.song.105000.json','["夔州之山皆入雲，夔女寢陋男不文。", "山川歷歷應如舊，昭君屈平猶荒村。", "三百篇後無繼者，始作離騷紹風雅。", "君門九重難叩閽，欲登閬風聊蹀馬。", "精衷寫盡君不聞，徙倚懷沙淚盈把。", "漢家靡曼盈六宫，明妃容與如春風。", "琵琶何能慰行路，檻檻氊車隨去鴻。", "椒蘭得得在修門，獨任先生作放臣。", "妃嬪無數貯金屋，秪遣王嬙犯塞塵。", "萬古江山虛秀氣，二人賢色皆鍾美。", "天之生此諒應難，一棄單于一沈水。", "遠色蒼蒼難致極，弔古徘回淚霑臆。", "二宅遺基自古存，石巖天深秋日昏。", "滄波渺渺流遺恨，後人誰爲賡天問。"]'),
('f50ab6d1-f7ec-4667-a6af-c7fee7964bb6','閩中早春','張嵲','宋','宋诗','song-poetry','','[]','愁見繁雲帖死灰，驟喜春從天際回。',240,'全唐诗/poet.song.105000.json','["愁見繁雲帖死灰，驟喜春從天際回。", "晴雲流爛滿峰起，瀲灔陂塘泉脈来。", "春歸欲騐将何許，柳腰杏頬知春處。", "出門矯首望四郊，滿目都無故園樹。", "暖景猶疑是故園，紛紅糅白終蕭然。", "黄茅不受春色染，化工無地施妖妍。", "老夫此時三歎息，晴靄暄風總輕擲。", "緣岡繞澗試幽尋，好鳥一聲山桂碧。", "卻憶當年漢水邊，花光柳色媚晴天。", "江頭醉罷日将落，芊眠草色生長煙。", "秪今春事知何有，傷心萬里空回首。", "中原但有骨如麻，杜曲應無花似酒。", "我今流落荒山隈，秋蓬作鬢心催頽。", "逢花政恐被花惱，幸兹寂寞無狂媒。", "閉門睡足高舂後，爐煙一炷消清晝。"]'),
('16cdf7bb-d7c4-45da-ab00-6b6c0d4561a1','欲雪','張嵲','宋','宋诗','song-poetry','','[]','欲雪未雪天糢糊，凍行沙尾鶬鴰呼。',64,'全唐诗/poet.song.105000.json','["欲雪未雪天糢糊，凍行沙尾鶬鴰呼。", "北風刮耳立不住，更騎鈍馬穿枯蘆。", "兩生憐我意不舒，江頭三日占檣烏。", "高堂明朝置安輿，買羊沽酒償勤劬。"]'),
('5fbaa3ec-3578-4ac6-b28c-3468bc21b8cd','吳宫詞','張嵲','宋','宋诗','song-poetry','','[]','新粧間花光，口脂雜蘂氣。',56,'全唐诗/poet.song.105000.json','["新粧間花光，口脂雜蘂氣。", "相對兩生春，停杯自成醉。", "高歌白苧舞西施，半夜雨来宫錦移。", "明日重來歌舞地，宫水浮花繞宫樹。"]'),
('fabe7abc-3c15-4ffb-b99d-ca8ca8501c25','翟方進','張嵲','宋','宋诗','song-poetry','','[]','相君事郡當少時，見謂遲鈍遭謾欺。',272,'全唐诗/poet.song.105000.json','["相君事郡當少時，見謂遲鈍遭謾欺。", "一從蔡叟問所適，羈遊萬里来京師。", "從馮老姥織屨賣，學問聲名從此大。", "胡常初毁更見譽，一日超升登掾宰。", "男兒立身要自勵，旬歲連摧兩司隸。", "薛公視遇不敢輕，果見登遷居相位。", "徒知得意快恩讎，峻文未肯持平例。", "九卿先達故郡歸，紅陽貴倨猶奪氣。", "忽聞當坐定陵事，慙懼乞骸更見慰。", "深窮黨友圗自安，十有九人同免官。", "得君萬事無不可，觧使衆醜成妖嫻。", "一朝天文示變異，李尋奏記翩然至。", "養牛尊酒天上来，萬歲之期何可避。", "使人致命忽馳去，半道尚書言物故。", "十年寵貴一日空，徒見縞衣蒙檻柱。", "誰云蓋棺事則已，下流衆怨何能止。", "芋魁飯豆亦云足，至今鴻隙歌鴻鵠。"]'),
('040209c6-3fa9-44b4-9c64-e05d6dcb0da8','仲冬冬至後','張嵲','宋','宋诗','song-poetry','','[]','仲冬冬至後，春從九地回。',299,'全唐诗/poet.song.105000.json','["仲冬冬至後，春從九地回。", "去年逢春在此寺，今年復向此寺逢。", "春來春去無復見花草，但有東風刮地如驚雷。", "人生七十能幾時，四度逢春祇在斯。", "祠官不復更遞代，直若倉庾氏，久任無年期。", "大農賦禄隨官品，豐儉由來皆有分。", "空儘天年在世間，饑飽死生皆不問。", "癃老非才固應爾，豪俊當年亦爲此。", "謂非貶謫實纍囚，謂是歸田猶禄仕。", "憶昔漢唐與本朝，咸有自新及起廢。", "如今豈無大眚及溥天，不在他時洒心例。", "人生如寓年年老，歲歲彫零人漸少。", "莫嫌四見魏唐春，尚得逢春到華皓。", "祠官之設自何時，聞是元豐宰相之所爲。", "欲擯老成皆不用，託於優假創斯規。", "當時弊政出一切，豈謂瘡疣後世遺。", "専寵持權事雖巧，榮華寧得多時好。", "君不見金陵零落故相家，一如寂寞韶陽廟。"]'),
('88366260-ef34-453f-8dfc-5d4209b6e749','覺道同玩梅','張嵲','宋','宋诗','song-poetry','','[]','雪盡徑泥乾，團欒遶樹看。',126,'全唐诗/poet.song.105000.json','["雪盡徑泥乾，團欒遶樹看。", "玉梅呈素艶，霜重月華寒。", "一蕚半含春意密，數苞未破臙脂粒。", "斜枝倒浸碧池深，羅衣暗惹香風濕。", "須知賈午最多情，繡囊偷佩芳筵驚。", "又疑仙人下姑射，玉容寂寞幽態清。", "去年梅花開，干戈猶未掃。", "今年梅花開，勸君休草草。", "莫待子規啼，梅花滿地蝴蝶飛。"]'),
('c7a83515-84a7-49f5-9762-c568d6abae43','約人泛舟','張嵲','宋','宋诗','song-poetry','','[]','前旬小雨飛廉纖，今旬夜雨聲滿簷。',64,'全唐诗/poet.song.105000.json','["前旬小雨飛廉纖，今旬夜雨聲滿簷。", "高原草青花欲消，幽人意與春蕭條。", "四山不復見桃李，開到梨花春有幾。", "似聞城下野水生，正好浮舟煙雨裏。"]'),
('f559c338-ebba-4af6-9ccf-562ac0c63ad5','崇山圖七賢詩','張嵲','宋','宋诗','song-poetry','','[]','題輿意匠崇崖圖，魯侯爲賦溪隠詩。',240,'全唐诗/poet.song.105000.json','["題輿意匠崇崖圖，魯侯爲賦溪隠詩。", "長松短壑歷可數，坐使妙境移于斯。", "地靈神秀天所秘，豺嘷虺伏鬼莫窺。", "芟蓬扶翳快登覽，若有異物陰相之。", "嵌巖嶻嶪臨漢滸，左拱右揖如追隨。", "七峰遠峙攅劍直，三溪旁繚縈带垂。", "芳洲蘭杜飛白鷺，滄浪漁艇牽鈎絲。", "煙霏露融水鑑浄，一聲孤笛横雲霓。", "淑氣亭亭掃般若，昂精燦燦棲明祠。", "幽尋眼力覻大巧，卜築得此林巒奇。", "堂如連艦岸若玦，呀成空谷窪爲池。", "妙觀觀盡見覺性，靜隠隠德騰光輝。", "信美誰謂非雲土，致爽自足和天倪。", "鄧公之孫特不凡，渥洼繡韀黄金羈。", "胸中萬頃九雲夢，江湖寛曠貞以期。"]'),
('7ad19fbf-f4b7-473d-8430-f829f8e94bb1','入峡詩','張嵲','宋','宋诗','song-poetry','','[]','微王大峡何崢嶸，疊嶂層巒礙飛鳥。',208,'全唐诗/poet.song.105000.json','["微王大峡何崢嶸，疊嶂層巒礙飛鳥。", "石壁排空何可鑿，拽雲蒸霧無昏曉。", "凝思天地始胚胎，清川一道何從来。", "聯峰既非巨靈擘，絕岸不聞神禹開。", "兩山中斷緣何許，異事人傳向開府。", "鑿石穿雲神鬼愁，至今行跡行人睹。", "從此奔流出亂山，東匯沮漳入荆楚。", "鱗鱗山樹經寒碧，枝侵雨露根連石。", "境勝應来仙馭遊，巖深定有蛟龍宅。", "君侯事跡已煙沉，流水年年石上深。", "山川不改時代積，徒使人興萬古心。", "土人事神何敢侮，桂酒春秋荐椒糈。", "衎衎巫歌神降時，森森廟樹来風雨。"]'),
('5dca9da3-8e75-4849-b099-7bcd36367266','乘舟阻風','張嵲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','澤國天低星斗濕，疾風吹波作山立。',160,'全唐诗/poet.song.105000.json','["澤國天低星斗濕，疾風吹波作山立。", "岸頭草木皆震動，雞犬鳴吠紛相及。", "通宵萬竅無停聲，平明更作春濤驚。", "青天東下日杲杲，風伯盛怒何當平。", "人言航河只一葦，咫尺猶須論萬里。", "乃知世事不可期，指點舟人轉船尾。", "常悲無梁越長川，我今操舟翻百難。", "平生所遇半如許，豈獨此事堪長歎。", "吁嗟屏翳真可鄙，歲歲祠官費秩禮。", "我聞敵騎南渡年，萬里長江波不起。"]'),
('d3d02d96-5e36-4764-b9ee-faf868f93a09','西谷歌','張嵲','宋','宋诗','song-poetry','','[]','西川峰嶺皆綿延，一峰突兀如青蓮。',224,'全唐诗/poet.song.105000.json','["西川峰嶺皆綿延，一峰突兀如青蓮。", "崔嵬勢壓東南倒，穹崇下俯群峰小。", "古木陰森寒未凋，長雲慘澹晴猶繞。", "陰巖積雪溜輕冰，南嶺驚春囀幽鳥。", "山西有谷聞深曲，中有人家在山麓。", "晝掩柴荆雞犬閒，歲耕煙岫囷倉足。", "巫山岷嶺遥相連，知是層城幾洞天。", "避世秦人應綠髪，茹芝仙子好朱顔。", "寰區喪亂方如許，寸地尺天無安堵。", "我欲携家住此山，高謝時人出塵土。", "女蘿薜荔結爲衣，文杏香茅緝爲宇。", "滿谷栽松紫翠寒，漫山種杏赬霞吐。", "朝尋石乳丹洞深，暮斸茯苓蒼檜古。", "山中父老志斯言，他時来訪吹笙侣。"]'),
('dd80a2ee-54df-402f-8a74-2097fe5a574f','喜雨行','張嵲','宋','宋诗','song-poetry','','[]','歲星運行至荒落，鶉尾初占建魁杓。',224,'全唐诗/poet.song.105000.json','["歲星運行至荒落，鶉尾初占建魁杓。", "大旱金石皆流爍，旱魃何知恣爲虐。", "大田多稼三百廛，盡是農夫耦十千。", "一朝焦枯如束管，赤地百里焚則烟。", "官長視民如視子，常恐歲饑爲殣死。", "並走群望嚴神祀，卻盖斥肩昭勤止。", "至誠果能格明神，明神爲公訴蒼旻。", "蒼旻油然興濃雲，濃雲鬰興雨如霖。", "農家不傘走溝遂，抖擻偃禾有生意。", "詰朝犯曉細□□，縷縷青黄交穎穗。", "農人以手加額頭，使我不死賴宋侯。", "白老垂髫聲呦呦，優游咸歌脫窮愁。", "陵山攅空插蒼玉，舒水拖絹浸寒綠。", "山高水長歲月續，德我宋侯歌不足。"]'),
('fc22d78c-4bf2-4503-b0ac-231692d2e156','贈趙公旦','張嵲','宋','宋诗','song-poetry','','[]','少年意氣隘九州，遠别不爲兒女愁。',288,'全唐诗/poet.song.105000.json','["少年意氣隘九州，遠别不爲兒女愁。", "秪今摧頽落異縣，跬步信宿生離憂。", "况今送子又千里，使我别緒何能休。", "憶昔石城初識面，兩髦紒幘君纔收。", "余方弱冠事科舉，竝轡共適東西州。", "春風尋勝襄傍寺，夜月復登臨漢樓。", "鳳林花開無遠近，漁梁柳暗迷汀洲。", "荆門至陋不足數，杏山百丈清泉幽。", "徑過物色盡可記，至今夜夢當時遊。", "從兹一别星再終，相望不啻馬牛風。", "臨安相見各驚歎，君非丁壯予老翁。", "長離更挟鵷鶵至，射策同攀郄詵桂。", "上書不肯干相公，頫首甘爲州縣吏。", "故人義重非時俗，三程過我荒村寺。", "歡言不覺春夜闌，破月已上前林端。", "一杯相屬且自適，莫話舊遊成慨歎。", "聞君早有求田約，四方寧有襄陽樂。", "時平我則徑西歸，遠追高士鹿門期。"]'),
('8fd4372e-8298-4104-b193-9e458571d1c5','贈黄子真','張嵲','宋','宋诗','song-poetry','','[]','再作醉李客，四年兩相從。',56,'全唐诗/poet.song.105000.json','["再作醉李客，四年兩相從。", "當時江頭樹，又暗行李中。", "嗟君事業誠有餘，十年客路常崎嶇。", "祇應未識今傑士，懷刺試謁劉南徐。"]'),
('4f3f26af-1dad-476d-9374-d45de2a3ef38','種植詩','張嵲','宋','宋诗','song-poetry','','[]','魏塘草樹環佛宫，兩春不識花白紅。',104,'全唐诗/poet.song.105000.json','["魏塘草樹環佛宫，兩春不識花白紅。", "但有柳絮迷晴空，今年始種木芙蓉。", "間以寒菊助丰容，新栽黄葵已蒙茸。", "坐待泬寥秋色濃，鞠衣仙人来御風。", "似聞芍藥富紅紫，願分餘波作春事，要令睡眼迷緗綺。", "勿言滯客無幾求，将致來禽及青李。"]'),
('7207de44-ea08-4f07-a211-5b482660ec26','蔓菁花詩','張嵲','宋','宋诗','song-poetry','','[]','遊絲百尺如堪挽，小蟲群飛欣日暖。',123,'全唐诗/poet.song.105000.json','["遊絲百尺如堪挽，小蟲群飛欣日暖。", "蒿莱滿地不見春，唯有蔓菁迷病眼。", "無復陵陂間碎金，青苔漫想玄都觀。", "今朝幸值天無風，飛来雌蝶畏雄蜂。", "村中女兒将插鬢，不信河陽萬樹紅。", "幽人惜春春已遠，把酒屬君君自遣，蔓菁開花猶爛熳。", "君不見西園桃李能幾時，此輩天教擅春晚。"]'),
('ea9e1c5b-2538-4b38-acbd-a061a04995c3','寒食行','張嵲','宋','宋诗','song-poetry','','[]','寒食由来古今重，四海人人作丘壠。',243,'全唐诗/poet.song.105000.json','["寒食由来古今重，四海人人作丘壠。", "兩京道上松柏多，盡是王公大家塚。", "伊昔年年當此時，鈿車寶馬相追隨。", "紛紛錦樹滿原野，暖風遲日争光輝。", "草間燒紙樹間哭，羅列杯盤烏攫肉。", "侵晨祭罷薄暮歸，旋風剪剪吹餘灰。", "爾時馬醫夏畦鬼，亦受子孫追養禮。", "豐薄由来稱有無，咸具盤餐致醪醴。", "家家丘墳各爲主，何人壠上無新土。", "自從遭亂去鄉關，幾歲松楸不曾睹。", "况復其間多發掘，孝子慈孫淚如雨。", "流落他州遇火前，去年如此復今年。", "新阡舊壠祇回首，無復原頭掛紙錢。", "君不見東都之傍永安道，車轍平来生碧草。", "四時祠祭今寂然，五陵春樹生蒼烟。"]'),
('84117e4d-ff34-44eb-9787-8da0112b4d67','秋暑','張嵲','宋','宋诗','song-poetry','','[]','涉旬秋暑不可觸，髪疏被汗如膏沐。',96,'全唐诗/poet.song.105000.json','["涉旬秋暑不可觸，髪疏被汗如膏沐。", "忽然三日風撼山，冬裘未具膚生粟。", "去年登高作重九，黄菊未開新酒熟。", "今年無酒不登高，獨行漫繞庭邊菊。", "中原季月欲折膠，江界隕霜無脫木。", "擁鼻從今四序移，遮眼殘書豈真讀。"]'),
('3ad04622-32f6-4f1b-9d0a-0271e26ada36','夏致宏方城道中以詩見寄避地窮山秋雨仍作因次其韵','張嵲','宋','宋诗','song-poetry','','[]','柴門直面排青壁，山木凋霜疏寂歷。',96,'全唐诗/poet.song.105000.json','["柴門直面排青壁，山木凋霜疏寂歷。", "西風吹雨衆山昏，聲落茅簷斷還滴。", "每讀離騷傷遠遊，一爲遷客又經秋。", "四時代謝不停軌，澂江萬古長悠悠。", "丹楓蕙葉照巖壑，物態故欲增繁憂。", "詩成滿岫濕煙起，寸心折盡空搔頭。"]'),
('826e221d-3802-46ff-8233-87ae558a1e53','春日','張嵲','宋','宋诗','song-poetry','','[]','老去仍羈旅，逢春非我春。',48,'全唐诗/poet.song.105000.json','["老去仍羈旅，逢春非我春。", "物華隨意别，感慨與時新。", "柳重将迎客，花然似笑人。", "十年憂國淚，依舊洒衣巾。"]'),
('e63e998e-87dd-460a-8b08-86516140175c','七月二十四日山中已寒二十九日處暑','張嵲','宋','宋诗','song-poetry','','[]','塵世未徂暑，山中今授衣。',48,'全唐诗/poet.song.105000.json','["塵世未徂暑，山中今授衣。", "露蟬聲漸咽，秋日景初微。", "四海猶多壘，餘生久息機。", "漂流空老大，萬事與心違。"]'),
('7d2ea6bd-de05-46eb-b3ea-5d2da240215f','病中夜雨','張嵲','宋','宋诗','song-poetry','','[]','新涼增客意，卧病復踰時。',48,'全唐诗/poet.song.105000.json','["新涼增客意，卧病復踰時。", "雨脚夜深白，蟲聲秋後悲。", "高低山樹立，迢遞曉鐘遲。", "此夕天涯鬢，知添幾縷絲。"]'),
('ea5b898c-2817-44c9-a07c-fa34738a8153','忽見早梅','張嵲','宋','宋诗','song-poetry','','[]','積雪凝閩嶺，凌風識暗香。',48,'全唐诗/poet.song.105000.json','["積雪凝閩嶺，凌風識暗香。", "疏花經雨瘦，卧影入溪長。", "萬里難爲贈，九回空繞膓。", "綠原聊駐屐，試待月荒涼。"]'),
('c9ba53e9-5f38-4345-a507-98e53c123fca','坐聽啼鳥如春禽響信筆書','張嵲','宋','宋诗','song-poetry','','[]','閩山冬候暖，寒鳥似春禽。',48,'全唐诗/poet.song.105000.json','["閩山冬候暖，寒鳥似春禽。", "一聽間關語，偏傷羈寓心。", "雨霑陳葉盡，雲壓暮山深。", "坐久疏鐘歇，餘聲過遠林。"]'),
('4151800b-cd60-46d6-8e34-b5ee6c6183ed','次韵子直二首  其一','張嵲','宋','宋诗','song-poetry','','[]','南北半程雲，澄江對蓽門。',48,'全唐诗/poet.song.105000.json','["南北半程雲，澄江對蓽門。", "未能操井臼，試學牧雞豚。", "智勇懷三傑，英雄鄙二袁。", "男兒須報主，未用反招魂。"]'),
('588d4d3b-a3fd-49ca-88f0-69e66f6cb361','次韵子直二首  其二','張嵲','宋','宋诗','song-poetry','','[]','曠朗秋天迥，嶺雲依樹消。',48,'全唐诗/poet.song.105000.json','["曠朗秋天迥，嶺雲依樹消。", "飛飛歸鳥急，去去廣川遥。", "鴻鵠本難畜，松筠常後凋。", "誰爲招隠賦，歲暮獨難聊。"]'),
('8455328d-cb16-42fe-a2d6-52752c6e9e07','次韵朱希真二首  其一','張嵲','宋','宋诗','song-poetry','','[]','東觀曾同入，南宫復雁行。',48,'全唐诗/poet.song.105000.json','["東觀曾同入，南宫復雁行。", "甞寮雖具爾，投分獨難忘。", "榮悴無多異，漂零共一鄉。", "遥欣訪蕭寺，顛倒曳衣裳。"]'),
('eb2e61c7-8a8e-46fa-b9a6-29cc5a8c02a7','次韵朱希真二首  其二','張嵲','宋','宋诗','song-poetry','','[]','禪榻仍兼卧，蒲團穏著綿。',48,'全唐诗/poet.song.105000.json','["禪榻仍兼卧，蒲團穏著綿。", "自疑方外客，猶費縣官錢。", "意懶如聞道，身閒似得仙。", "何當集蘭若，已辦泛湖船。"]'),
('9b9c184f-ccdb-46c6-8c87-eb7d592b1344','再次韵寄朱希真二首  其一','張嵲','宋','宋诗','song-poetry','','[]','一舍徒相望，書來秖細行。',48,'全唐诗/poet.song.105000.json','["一舍徒相望，書來秖細行。", "野梅行欲盡，幽興詎能忘。", "老去尤耽句，春来更憶鄉。", "看看過寒食，北望一霑裳。"]'),
('f3e8d52c-36cd-47a0-825f-be4c1b612418','再次韵寄朱希真二首  其二','張嵲','宋','宋诗','song-poetry','','[]','初喜花明炬，還愁柳墮綿。',48,'全唐诗/poet.song.105000.json','["初喜花明炬，還愁柳墮綿。", "時須盃裏物，聊費杖頭錢。", "天上足官府，人間有地仙。", "卻慚營道嬾，渾似逆風船。"]'),
('7b18115b-8355-4854-9cdc-4cd2c60a61de','次韵周守二首  其一','張嵲','宋','宋诗','song-poetry','','[]','西川方用武，憂思惔如焚。',48,'全唐诗/poet.song.105000.json','["西川方用武，憂思惔如焚。", "秋興悲黄葉，閒情屬野雲。", "鳴鴻何日到，絡緯不堪聞。", "每憶盈尊酒，清談從使君。"]'),
('79991c87-77e0-4c5d-9e7c-05b6ea1206a3','次韵周守二首  其二','張嵲','宋','宋诗','song-poetry','','[]','秋色際遥海，乘高傷遠眸。',48,'全唐诗/poet.song.105000.json','["秋色際遥海，乘高傷遠眸。", "風塵方未艾，身世豈勝愁。", "黄菊已過晚，濁醪徒滿甌。", "何時奉松□，一醉碧溪頭。"]'),
('64834911-5b4b-4811-9765-d62979539229','次韵周子直四首  其一','張嵲','宋','宋诗','song-poetry','','[]','寰宇安危異，乾坤歲序同。',48,'全唐诗/poet.song.105000.json','["寰宇安危異，乾坤歲序同。", "投身雲嶠碧，落膽戰塵紅。", "晋馬成南渡，宗周入國風。", "操戈誰衛社，群盜正爭雄。"]'),
('38ba70d5-f01a-4c83-9a58-dc17f45d4e03','次韵周子直四首  其二','張嵲','宋','宋诗','song-poetry','','[]','西北壃途蹙，東南信未通。',48,'全唐诗/poet.song.105000.json','["西北壃途蹙，東南信未通。", "小夫方自智，大將莫論功。", "敵馬来關外，油幢入閬中。", "孤臣難自力，報國意無窮。"]'),
('4b3260d2-baca-4b62-a73b-72e26f61c969','次韵周子直四首  其三','張嵲','宋','宋诗','song-poetry','','[]','□樊多勝日，杖屨偶相同。',48,'全唐诗/poet.song.105000.json','["□樊多勝日，杖屨偶相同。", "西嶺輕陰結，東山落照紅。", "葵傾終向日，蒲弱易含風。", "甘作囚山柳，休爲投閣雄。"]'),
('c2546630-dfb2-4f65-be8e-19f119d841f6','次韵周子直四首  其四','張嵲','宋','宋诗','song-poetry','','[]','淵明門謾設，仲蔚徑才通。',48,'全唐诗/poet.song.105000.json','["淵明門謾設，仲蔚徑才通。", "用世慙無術，哦詩喜有功。", "舊廬群盜裏，北闕戰塵中。", "塞路多豺虎，吾生信自窮。"]'),
('4ddd5182-08aa-452d-9e83-7a6d31ec090e','又次韵四首  其一','張嵲','宋','宋诗','song-poetry','','[]','長夏林泉好，還欣觴羽同。',48,'全唐诗/poet.song.105000.json','["長夏林泉好，還欣觴羽同。", "顛毛愁裏白，顴頬醉来紅。", "日蹇嗟南國，民離歎北風。", "當塗寧市駿，俗眼競嘲雄。"]'),
('e2c76def-06c0-4b4b-a8b2-576918e666fc','又次韵四首  其二','張嵲','宋','宋诗','song-poetry','','[]','異世如張贄，深居似敬通。',48,'全唐诗/poet.song.105000.json','["異世如張贄，深居似敬通。", "致身寧有意，覔句恐無功。", "世事忘言外，群情一笑中。", "詩書猶可詠，吾道未終窮。"]'),
('4a9b1045-38a6-4db0-a9b0-d8b9beb4131c','又次韵四首  其三','張嵲','宋','宋诗','song-poetry','','[]','臨流清溽暑，薄暮一尊同。',48,'全唐诗/poet.song.105000.json','["臨流清溽暑，薄暮一尊同。", "林葉風翻白，山梅雨漬紅。", "驚魂須楚些，繕性賴真風。", "舊學嗟荒落，新詩識渾雄。"]'),
('c3b8fbf1-f000-4155-8bf0-71bb1a5b5a3d','又次韵四首  其四','張嵲','宋','宋诗','song-poetry','','[]','篇章雖漫往，悃愊詎能通。',48,'全唐诗/poet.song.105000.json','["篇章雖漫往，悃愊詎能通。", "待子應無恙，臨池定有功。", "綺疏群大杪，倒影亂流中。", "何日陪康樂，登臨興未窮。"]'),
('bb79f771-9f35-43ba-937e-6c1be479a8fa','山中月夜','張嵲','宋','宋诗','song-poetry','','[]','過雨得清夜，月明惟水聲。',48,'全唐诗/poet.song.105000.json','["過雨得清夜，月明惟水聲。", "葉光知露隕，蘭馥賴風清。", "天地未悔禍，豺狼猶阻兵。", "故園同此夕，長望一霑纓。"]'),
('6a1a8ef4-adf9-4069-9d52-3380b2f9d05e','雨霽獨夜','張嵲','宋','宋诗','song-poetry','','[]','繁星凝夜氣，黑月惟西山。',48,'全唐诗/poet.song.105000.json','["繁星凝夜氣，黑月惟西山。", "一室空林迥，逾知天地寛。", "葉乾風有韵，石亂水多湍。", "獨坐澄諸念，憂来信有端。"]'),
('268b04d8-3488-4b89-a04a-c0691c71fe01','今春花卉盛時黄霧連十餘日不觧久不作詩偶成','張嵲','宋','宋诗','song-poetry','','[]','病覺詩思竭，年華奈若何。',48,'全唐诗/poet.song.105000.json','["病覺詩思竭，年華奈若何。", "亂花欺客恨，黄霧作春魔。", "地僻交遊絕，庭空鳥雀多。", "亂離從節變，不復嘆蹉跎。"]'),
('31407b0c-1054-45c9-a4de-e3dc72754d3a','郡樓對雨和周守韵二首  其一','張嵲','宋','宋诗','song-poetry','','[]','蒼煙迷野色，林谷尚微分。',48,'全唐诗/poet.song.105000.json','["蒼煙迷野色，林谷尚微分。", "暮雨已吹幔，層巖猶出雲。", "晚風時斷續，落葉自繽紛。", "寂寞窮山裏，何堪入夜聞。"]'),
('fd6f9970-0ffc-4583-8b60-465968c0660c','郡樓對雨和周守韵二首  其二','張嵲','宋','宋诗','song-poetry','','[]','暮雨昏平遠，南山漸不分。',48,'全唐诗/poet.song.105000.json','["暮雨昏平遠，南山漸不分。", "濛濛連楚塞，細細濕行雲。", "從宦成羈束，登危厭糾紛。", "何時疏竹裏，還向舊山聞。"]'),
('e318026c-cc85-48ca-9551-b1e180ee8f13','桃花塢','張嵲','宋','宋诗','song-poetry','','[]','三吳皆白水，處處秖横舟。',48,'全唐诗/poet.song.105000.json','["三吳皆白水，處處秖横舟。", "獨有桃花塢，光風盡日留。", "一朝山雨過，忽見夏陰稠。", "詎昔繁華晚，徒嗟歲月遒。"]'),
('f3839c3c-6aef-4758-80ff-f5fb0ea51fd1','褒城縣雨中','張嵲','宋','宋诗','song-poetry','','[]','嶺雲方笠覆，簷雨已盆傾。',48,'全唐诗/poet.song.105000.json','["嶺雲方笠覆，簷雨已盆傾。", "山氣晝侵幔，灘聲夜入城。", "子真空舊隠，褒姒謾垂名。", "訪古多磨滅，秋風山樹赬。"]'),
('a143f1f4-73fe-4d87-ac60-e6ef3e822213','夢中作得六句覺後足成','張嵲','宋','宋诗','song-poetry','','[]','山中茅屋好，况復竹籬新。',48,'全唐诗/poet.song.105000.json','["山中茅屋好，况復竹籬新。", "一逕往来客，萬山迎送人。", "葉殷渾欲染，冬暖卻疑春。", "近得幽棲地，時来岸角巾。"]'),
('a10a69d8-11e2-4cd0-895e-7db610fde74a','秋日懷古園有作','張嵲','宋','宋诗','song-poetry','','[]','故里田廬遠，他鄉禾黍秋。',48,'全唐诗/poet.song.105000.json','["故里田廬遠，他鄉禾黍秋。", "風高初下葉，川淺欲生洲。", "月出空山静，煙生遠樹稠。", "已諳爲客意，堅坐任遲留。"]'),
('edbae0d9-4eb6-44b5-8407-d75641b4907c','途中偶成寄幕下諸公','張嵲','宋','宋诗','song-poetry','','[]','曠朗高天浄，蟬鳴江漢秋。',48,'全唐诗/poet.song.105000.json','["曠朗高天浄，蟬鳴江漢秋。", "川晴山歷歷，身遠意悠悠。", "落日慘行子，長風欺弊裘。", "郡樓今夜月，應從庾公游。"]'),
('ddc56532-ccfa-43f8-8fdc-5816adcfa5e9','秋懷','張嵲','宋','宋诗','song-poetry','','[]','忽忽經年事，悠悠滯客心。',48,'全唐诗/poet.song.105000.json','["忽忽經年事，悠悠滯客心。", "晚花生廢圃，老樹立秋陰。", "豈有清樽醉，寧辭白髪侵。", "樓高見豪髪，老大怯登臨。"]'),
('66facd40-5636-4823-a996-a57afc1bfb3e','望瞿塘峡','張嵲','宋','宋诗','song-poetry','','[]','萬古瞿塘峡，猶存禹鑿痕。',48,'全唐诗/poet.song.105000.json','["萬古瞿塘峡，猶存禹鑿痕。", "岷峨驅衆水，灔澦没孤根。", "雲黑樹含雨，祠荒鴉噪昏。", "悲涼瀼西地，三嘆相營魂。"]'),
('9592be34-9a3f-456e-afdd-ba7fd404767f','入瞿塘峡','張嵲','宋','宋诗','song-poetry','','[]','瞿塘深窈窕，翠氣曉空濛。',48,'全唐诗/poet.song.105000.json','["瞿塘深窈窕，翠氣曉空濛。", "亂石增驚浪，長灘激迅風。", "舟行天壍內，身在夾城中。", "絕壁皆侵漢，于兹識禹功。"]'),
('a3ec1389-2913-41d3-a495-329a6937fdf7','贈黄子真','張嵲','宋','宋诗','song-poetry','','[]','江漢知名士，石城黄子真。',48,'全唐诗/poet.song.105000.json','["江漢知名士，石城黄子真。", "殷勤能過我，坎壈歎斯人。", "此去仍爲客，舟行任過春。", "無資振遊舊，懷抱不能伸。"]'),
('12bf3db2-2472-4677-9d18-9a727e6ba63a','送賀子忱漕閩','張嵲','宋','宋诗','song-poetry','','[]','上蔡舊名士，中臺令望郎。',48,'全唐诗/poet.song.105000.json','["上蔡舊名士，中臺令望郎。", "行馳封傳寵，路向七閩長。", "山水聞清遠，官曹試暇皇。", "遥憐荔枝熟，虗館進風涼。"]'),
('58815856-44dc-4620-b6bf-05be17057a12','送許子禮漕湖南','張嵲','宋','宋诗','song-poetry','','[]','爲郎端有望，漕務復需能。',48,'全唐诗/poet.song.105000.json','["爲郎端有望，漕務復需能。", "湖外頻無歲，漢傍連有興。", "足兵先一飽，化俗遲三登。", "時到湘西寺，高臺得暫凴。"]'),
('84b22a72-f3ba-4f39-baa7-a29f11bf0081','雨後望雲','張嵲','宋','宋诗','song-poetry','','[]','歲序屬殘臘，雲容先發春。',48,'全唐诗/poet.song.105000.json','["歲序屬殘臘，雲容先發春。", "氛氲迎近壑，亂鬈靄遥津。", "暮色含微雨，林滋被細筠。", "憂居時物變，有淚洒蒼旻。"]'),
('bdb386b0-886b-4e0c-a67b-9668ca969999','立春後一日偶書','張嵲','宋','宋诗','song-poetry','','[]','薄暮春風惡，黄塵漲遠山。',48,'全唐诗/poet.song.105000.json','["薄暮春風惡，黄塵漲遠山。", "冥冥林靄變，冉冉鳥飛還。", "作客信多畏，依人足強顔。", "飄揚它日意，回首鬢毛斑。"]'),
('fe911014-74fc-479b-a9f4-6fe47b9ffa69','偶成寄致宏','張嵲','宋','宋诗','song-poetry','','[]','爲問邉城客，經春復若何。',48,'全唐诗/poet.song.105000.json','["爲問邉城客，經春復若何。", "孤生寛意少，游子苦顔多。", "青壁題詩處，澄潭載酒過。", "塞垣風色惡，應憶舊雲蘿。"]'),
('c249be05-6364-4ea7-b3c9-6e8ae9945cf9','山前紅葉','張嵲','宋','宋诗','song-poetry','','[]','前山風落木，俯檻愛斕斑。',48,'全唐诗/poet.song.105000.json','["前山風落木，俯檻愛斕斑。", "凌曉千花麗，經旬萬炬閒。", "詞人歌火繖，巴客訝燒山。", "不似庭花艷，開時瞬息間。"]'),
('43be8bd6-ed1b-4f7f-88db-60aebadea6a1','贈相僧楊嬾散','張嵲','宋','宋诗','song-poetry','','[]','邂逅湖傍寺，翻然還語離。',48,'全唐诗/poet.song.105000.json','["邂逅湖傍寺，翻然還語離。", "春風飛錫遠，暮雨渡杯遲。", "渺渺孤雲意，翩翩野鶴姿。", "百年堪幾别，何處重相期。"]'),
('b7df8c9d-e7bf-4c2b-b8ec-be78afc43aa3','戲呈覺老','張嵲','宋','宋诗','song-poetry','','[]','投曉過書齋，風門自閉開。',48,'全唐诗/poet.song.105000.json','["投曉過書齋，風門自閉開。", "雲容疑水墨，雪意吝瓊瑰。", "筆冷吟呵凍，爐寒坐畫灰。", "何如氊帳下，低唱兩三杯。"]'),
('444758dd-09cb-4fb4-9bf5-ea72ceaa46f8','清明','張嵲','宋','宋诗','song-poetry','','[]','園幽春去遠，山暗綠初成。',48,'全唐诗/poet.song.105000.json','["園幽春去遠，山暗綠初成。", "雨過林姿潤，風回池面平。", "十年空潦倒，萬里近清明。", "淚盡新阡樹，如今青葉生。"]'),
('2ac7438b-1ab5-4f78-9edc-8a4393393898','獨夜','張嵲','宋','宋诗','song-poetry','','[]','清燈蕭寺遠，不寐夜何長。',48,'全唐诗/poet.song.105000.json','["清燈蕭寺遠，不寐夜何長。", "風細頻翻葉，雲輕才護霜。", "磵黑水決決，月明山蒼蒼。", "作客歲月晚，故園春欲芳。"]'),
('dc1940c2-5446-4ca4-a80f-e52152c03310','苦熱','張嵲','宋','宋诗','song-poetry','','[]','三吳多異候，瘧癘日愁予。',48,'全唐诗/poet.song.105000.json','["三吳多異候，瘧癘日愁予。", "夏日雖可畏，清風非穆如。", "殘春且重繭，徂暑但深居。", "凍飲清涼耐，由来未可儲。"]'),
('afc44a7f-a9b4-4882-8dce-c7190d21b880','送趙公望入蜀','張嵲','宋','宋诗','song-poetry','','[]','異世黄叔度，宗支劉辟疆。',48,'全唐诗/poet.song.105000.json','["異世黄叔度，宗支劉辟疆。", "相看不覺厭，此别詎能忘。", "四海兵戈滿，山川道路長。", "去留無上策，分手鬢毛蒼。"]'),
('b3e052ff-2c99-460c-9d42-f55e2a14c284','秋日晚出郡郊','張嵲','宋','宋诗','song-poetry','','[]','暝色生平野，喬林動遠風。',48,'全唐诗/poet.song.105000.json','["暝色生平野，喬林動遠風。", "蟲鳴古道迥，月白戍樓空。", "歲月悲歡異，山川今古同。", "荒城見揺落，未免泣途窮。"]'),
('e3e80ae7-26e9-425c-ba3d-bcf76be891b3','寓居','張嵲','宋','宋诗','song-poetry','','[]','是處爲家得，斯居亦漫成。',48,'全唐诗/poet.song.105000.json','["是處爲家得，斯居亦漫成。", "西齋便静密，小閣更深明。", "送老一床足，遺形百慮輕。", "傍人訝幽僻，端可寄餘生。"]'),
('64417d8c-a891-4b54-b10f-b3180c017511','和周守登樓對雪  其一','張嵲','宋','宋诗','song-poetry','','[]','寒風動原野，密雪度層軒。',48,'全唐诗/poet.song.105000.json','["寒風動原野，密雪度層軒。", "素積長郊色，青餘遠岫痕。", "輕冰幽沼合，棲鳥暮叢喧。", "邉騎暗河洛，應無閉戶袁。"]'),
('1165a76e-46d0-4826-9017-992b0965ae83','和周守登樓對雪  其二','張嵲','宋','宋诗','song-poetry','','[]','風積同雲凝，飛花際八寰。',48,'全唐诗/poet.song.105000.json','["風積同雲凝，飛花際八寰。", "碧流連遠水，玉立認群山。", "戎馬逾猖獗，生民政險艱。", "兔園歌吹地，回望損朱顔。"]'),
('e57b9dd9-0f00-4cc2-a311-cd33029b97b5','余於六月初三日泛舟至奇石洞留題洞中一首','張嵲','宋','宋诗','song-poetry','','[]','世人應未到，若士或曾遊。',48,'全唐诗/poet.song.105000.json','["世人應未到，若士或曾遊。", "岸隔千峰秀，門臨萬瀨愁。", "蜺旌疑可遲，丹洞擬深投。", "歸去誇塵侣，城闉鶴暫留。"]'),
('7d341c28-3ab0-4f39-83e9-a46eb89f5ccf','賦得山上樹','張嵲','宋','宋诗','song-poetry','','[]','鬰鬰復蒼蒼，扶疏翻曉光。',48,'全唐诗/poet.song.105000.json','["鬰鬰復蒼蒼，扶疏翻曉光。", "豈能偏雨露，秪益早風霜。", "蕭瑟秋将暮，紛披葉盡黄。", "深溪調鼎樹，歲晚獨能芳。"]'),
('0ea7b251-d112-47ac-9d03-4fddff92e2a8','遊北巖','張嵲','宋','宋诗','song-poetry','','[]','尋山輕近境，偶向此中来。',48,'全唐诗/poet.song.105000.json','["尋山輕近境，偶向此中来。", "精舍層巖擁，穹林石路開。", "排雲今歲竹，封徑幾年苔。", "僧老無餘事，端居傲刼灰。"]'),
('7c69b922-39be-436f-b4a8-af69674b909b','往年沿檄金州謁女媧神祠是時猶未亂也紹興壬子挈家避地三巴後過祠下登山椒以望江漢自是故園懸隔矣','張嵲','宋','宋诗','song-poetry','','[]','七年如轉首，復過此山頭。',48,'全唐诗/poet.song.105000.json','["七年如轉首，復過此山頭。", "閲世興衰異，傷時涕淚流。", "嗟無補天手，豈有去鄉愁。", "漸覺山河異，憑高更少留。"]'),
('26b805e1-c449-4855-a5d6-bb4112eb1ffa','次韵太守會宜休亭二首  其一','張嵲','宋','宋诗','song-poetry','','[]','屐齒破苔色，林塘欣共尋。',48,'全唐诗/poet.song.105000.json','["屐齒破苔色，林塘欣共尋。", "水光連竹塢，山翠上衣襟。", "疏柳揺斜日，高梧轉晚陰。", "娵隅休入詠，可怕兕觥深。"]'),
('dedbcca8-93c3-4278-9654-89f3b09c2812','次韵太守會宜休亭二首  其二','張嵲','宋','宋诗','song-poetry','','[]','萬竹鏁深翠，幽亭枕柳塘。',48,'全唐诗/poet.song.105000.json','["萬竹鏁深翠，幽亭枕柳塘。", "共臨朱檻坐，遥借渚蘋香。", "烏喜樹陰密，魚遊荷影涼。", "聊從山簡醉，疏逸興何長。"]'),
('7c12e955-f76b-4f79-bc2b-0244baead4a6','喜晴','張嵲','宋','宋诗','song-poetry','','[]','一春黄霧暗，今旦天始清。',48,'全唐诗/poet.song.105000.json','["一春黄霧暗，今旦天始清。", "林姿明積雨，水色澹初晴。", "好鳥關關囀，新泉決決鳴。", "前山有佳色，聊以駐幽情。"]'),
('6d2fe048-f103-4eea-9707-c9ff3e94d35c','登寺閣見月上率然成詠','張嵲','宋','宋诗','song-poetry','','[]','殘陽猶半谷，片月已臨山。',48,'全唐诗/poet.song.105000.json','["殘陽猶半谷，片月已臨山。", "暮色千林起，鄉心萬里還。", "不堪常俯仰，寧有但間關。", "絕世非吾意，幽棲寄暫閒。"]'),
('41f830dd-4873-47d0-b935-24d485a32480','九日  其一','張嵲','宋','宋诗','song-poetry','','[]','重陽述令序，景物自爲嘉。',48,'全唐诗/poet.song.105000.json','["重陽述令序，景物自爲嘉。", "易辦如江酒，難浮似粟花。", "追遊疑所務，寄興眇無涯。", "舊俗臺應廢，何人杖馬檛。"]'),
('83a91e34-a497-49dc-82c2-b307d59c8b55','九日  其二','張嵲','宋','宋诗','song-poetry','','[]','九日空山裏，乘高感歲華。',48,'全唐诗/poet.song.105000.json','["九日空山裏，乘高感歲華。", "霜風翻絳葉，晴日亂黄花。", "積雨饒新徑，荒林足亂雅。", "連年頻避地，憔悴客田家。"]'),
('ac922706-dda7-48d6-88ee-5506372a4d58','歸日再過分水嶺','張嵲','宋','宋诗','song-poetry','','[]','兹山已巉絕，盤道乏縈廻。',48,'全唐诗/poet.song.105000.json','["兹山已巉絕，盤道乏縈廻。", "路向日邊出，人從雲外来。", "澗聲高更咽，梅蘂雪猶開。", "卻憶僧房坐，深爐擁細灰。"]'),
('4029a367-8bac-46ea-84e7-4f16b9a26bdc','金州行衙','張嵲','宋','宋诗','song-poetry','','[]','城頭翻鼔罷，庭樹晚風愁。',48,'全唐诗/poet.song.105000.json','["城頭翻鼔罷，庭樹晚風愁。", "破隙華星大，當簷素月流。", "灘聲侵夜急，江霧入城浮。", "此夕天涯客，何心倚戍樓。"]'),
('84ed7714-fb09-4258-a619-48de68c80dc7','舟行書所見','張嵲','宋','宋诗','song-poetry','','[]','津木始凋霜，溪梅已飄素。',48,'全唐诗/poet.song.105000.json','["津木始凋霜，溪梅已飄素。", "河山自殊方，景物宛如故。", "悠悠川陸行，日日年華度。", "遷客未停舟，江烟欲成暮。"]'),
('6dd8df94-1bed-42f4-9b16-7de669c2ebfe','寄題友人小軒','張嵲','宋','宋诗','song-poetry','','[]','簪組豈爲累，悠然塵事微。',48,'全唐诗/poet.song.105000.json','["簪組豈爲累，悠然塵事微。", "看山心自適，閉戶客来稀。", "流水三吳大，清霜衆卉腓。", "何由納芒履，一爲款荆扉。"]'),
('f2e7c231-5ead-4255-a34a-85493a50f417','山中','張嵲','宋','宋诗','song-poetry','','[]','深夏遠林黑，溶溶雲動山。',48,'全唐诗/poet.song.105000.json','["深夏遠林黑，溶溶雲動山。", "晚川澄衆影，霽色潤層巒。", "地靜知秋至，衣輕覺暑闌。", "居山非有意，偶托即身安。"]'),
('146bd6d9-0972-48c1-81cd-2d54d8af104e','興州道中遇雨','張嵲','宋','宋诗','song-poetry','','[]','非干秋色苦，客意自蕭條。',48,'全唐诗/poet.song.105000.json','["非干秋色苦，客意自蕭條。", "谷口玄雲惡，關門白露高。", "泥塗連遠驛，寒雨暗長郊。", "誰念征衣薄，西風方怒號。"]'),
('76e3b6d6-3b69-4a34-8251-f0b4e2af1828','通惠泉','張嵲','宋','宋诗','song-poetry','','[]','東西幾山隔，石徑不容車。',48,'全唐诗/poet.song.105000.json','["東西幾山隔，石徑不容車。", "那知厚地底，自然成井渠。", "甘餘留齒頬，清足鑒眉鬚。", "不用瓶罍貯，纍纍似酒酤。"]'),
('e2ffa7ff-d90c-471f-88fd-8b7c96759659','寄題江月亭','張嵲','宋','宋诗','song-poetry','','[]','暮氣集江縣，斯亭發興深。',48,'全唐诗/poet.song.105000.json','["暮氣集江縣，斯亭發興深。", "憑欄看巴水，見月過東岑。", "淺瀨金蛇動，澄潭白璧沉。", "天邊未歸客，折盡此時心。"]'),
('cccc116f-559f-48d7-ad03-1fad5bb16f13','即事','張嵲','宋','宋诗','song-poetry','','[]','落日邊書急，秋風戰鼓多。',48,'全唐诗/poet.song.105000.json','["落日邊書急，秋風戰鼓多。", "私憂真過計，長算合如何。", "盡欲清淮戍，仍收瀚海波。", "棲遲一尊酒，幽恨滿關河。"]'),
('de9d85b1-0b9b-43fe-89d8-cc364de6ccf9','九月十四日登崇山晚歸','張嵲','宋','宋诗','song-poetry','','[]','陽精天際滅，暮色望中生。',48,'全唐诗/poet.song.105000.json','["陽精天際滅，暮色望中生。", "嵐氣侵衣薄，山風墮葉輕。", "林空霜月迥，沙白夜江明。", "雲裏相呼雁，翩翩尚遠征。"]'),
('7a07fb8f-79e8-4e16-b2b8-b3e1e1bc76da','初春','張嵲','宋','宋诗','song-poetry','','[]','原野土膏動，懷生各自欣。',48,'全唐诗/poet.song.105000.json','["原野土膏動，懷生各自欣。", "老年歡緒少，獻歲物華新。", "草木涵時澤，江湖寄病身。", "百年都幾日，四見魏塘春。"]'),
('36238038-907b-4fa0-a8d2-214224db1b33','次韵周守遊海棠溪','張嵲','宋','宋诗','song-poetry','','[]','浣紗何處是，空翠隔崔嵬。',48,'全唐诗/poet.song.105000.json','["浣紗何處是，空翠隔崔嵬。", "嫩綠連山暗，妖紅照水開。", "惜春嗟婉娩，載酒約徘徊。", "莫怪臙脂濕，曾經夜雨来。"]'),
('56b69797-dcba-41e0-b594-e2c80a659aef','窮居暑雨','張嵲','宋','宋诗','song-poetry','','[]','空庭滿積雨，竟日看圓紋。',48,'全唐诗/poet.song.105000.json','["空庭滿積雨，竟日看圓紋。", "未厭草木薉，不堪蛙黽喧。", "奔流遥澗水，亂上前峰雲。", "境静悟諸幻，泊然遺世紛。"]'),
('d32dba86-6340-4ca4-a1de-1212af764ef3','陳參政挽詩三首  其一','張嵲','宋','宋诗','song-poetry','','[]','今古雖同盡，存亡惕遽分。',48,'全唐诗/poet.song.105000.json','["今古雖同盡，存亡惕遽分。", "人誰爲爲善，天不右斯文。", "莫遂三年築，空悲四尺墳。", "音塵竟何所，俯仰嘆蒿焄。"]'),
('59276014-7a73-435f-8374-e9bbb80baa02','陳參政挽詩三首  其二','張嵲','宋','宋诗','song-poetry','','[]','脱屣違人代，振容即路岐。',48,'全唐诗/poet.song.105000.json','["脱屣違人代，振容即路岐。", "名流祠洗馬，白旐痛元規。", "一代風流盡，千年翰墨垂。", "傷心墓前水，故作夜深悲。"]'),
('4674d9ca-2cdf-4b7e-894a-bb0300445100','陳參政挽詩三首  其三','張嵲','宋','宋诗','song-poetry','','[]','徒知天可恃，豈謂病終侵。',48,'全唐诗/poet.song.105000.json','["徒知天可恃，豈謂病終侵。", "遽使儀刑意，翻成殄瘁心。", "開阡賢子力，卜遠外姻臨。", "墓木看初種，俄悲已茂林。"]'),
('c80de838-b00b-4349-b6b6-f58a368bbe19','劉忠顯挽詞  其一','張嵲','宋','宋诗','song-poetry','','[]','黄屋辭丹闕，貞臣赴敵營。',48,'全唐诗/poet.song.105000.json','["黄屋辭丹闕，貞臣赴敵營。", "觧言終不反，先面竟如生。", "誰並當時節，獨流千祀名。", "承家有賢嗣，諒不愧西平。"]'),
('3838036c-c493-429e-a83c-f96161986f08','劉忠顯挽詞  其二','張嵲','宋','宋诗','song-poetry','','[]','抗節群公愧，攄忠異國尊。',48,'全唐诗/poet.song.105000.json','["抗節群公愧，攄忠異國尊。", "威稜千古在，姦佞百年存。", "盛德源流遠，公朝禮物敦。", "豐碑昭令德，榮耀及来昆。"]'),
('28607588-d744-497f-b96b-357bfaea2152','劉忠顯挽詞  其三','張嵲','宋','宋诗','song-poetry','','[]','天運丁陽九，蒙塵事可傷。',48,'全唐诗/poet.song.105000.json','["天運丁陽九，蒙塵事可傷。", "群寮徒陷敵，賊子更臣張。", "自古寧無死，惟公獨有光。", "向来從僞者，生意日荒涼。"]'),
('e939a5ed-1467-4041-b740-aa3a32b6caf2','劉忠顯挽詞  其四','張嵲','宋','宋诗','song-poetry','','[]','視死如歸士，捐軀徇國臣。',48,'全唐诗/poet.song.105000.json','["視死如歸士，捐軀徇國臣。", "殺身雖一概，爲義豈無因。", "孔墨休相並，張南僅比倫。", "微公今史上，死節定何人。"]'),
('91ecc098-8087-4bc0-a6d8-ea9cc0e16143','劉忠顯挽詞  其五','張嵲','宋','宋诗','song-poetry','','[]','臨難不忘死，爲忠已足多。',48,'全唐诗/poet.song.105000.json','["臨難不忘死，爲忠已足多。", "全生猶有路，仗節竟如何。", "可騐平生志，宜令後世歌。", "諸儒主褒貶，毫髪未容訛。"]'),
('d67a1927-d525-4e01-aadb-4099ed492d6a','王寶學挽詞二首  其一','張嵲','宋','宋诗','song-poetry','','[]','德望三山重，勤勞一節忠。',48,'全唐诗/poet.song.105000.json','["德望三山重，勤勞一節忠。", "丹心明貫日，英氣浩如虹。", "趣召恩方急，跏趺事已空。", "功名重回首，寂寞淚東風。"]'),
('6020c423-14d7-4d4a-876f-5f7585f36f0d','王寶學挽詞二首  其二','張嵲','宋','宋诗','song-poetry','','[]','故相傳勲閥，風流見典刑。',48,'全唐诗/poet.song.105000.json','["故相傳勲閥，風流見典刑。", "所期爲旱雨，何意墮明星。", "有美閒桴鼓，姑蘇詫使亭。", "若追甘露事，忠首定丹青。"]'),
('4b4787cb-132d-43e0-97ad-5d0c98286d1b','劉無虞尊人挽詩二首  其一','張嵲','宋','宋诗','song-poetry','','[]','蓄德竟不耀，坐觀門戶成。',48,'全唐诗/poet.song.105000.json','["蓄德竟不耀，坐觀門戶成。", "生無三事貴，禄有萬鍾榮。", "色養無違志，陵終若事生。", "秋風如罔極，蕭瑟在松聲。"]'),
('cdb05a15-e51c-4208-ae1b-71bd27c2b48a','劉無虞尊人挽詩二首  其二','張嵲','宋','宋诗','song-poetry','','[]','刻杖方優老，臨川忽逝波。',48,'全唐诗/poet.song.105000.json','["刻杖方優老，臨川忽逝波。", "登年惟載德，生子舊持荷。", "此日悲風樹，他時廢蓼莪。", "輀車方即路，鄰杵爲停歌。"]'),
('fe1ef128-17b5-4568-b772-740d90adaa7c','李廣甫挽詞','張嵲','宋','宋诗','song-poetry','','[]','磊落生平志，酣歌萬慮空。',48,'全唐诗/poet.song.105000.json','["磊落生平志，酣歌萬慮空。", "名從敦樸重，家爲克勤豐。", "誰與萊衣戯，唯餘杖蕚紅。", "素車慚有阻，揮淚灑霜風。"]'),
('a030470b-8a7e-44cf-bd14-728bdee6dae7','鄒德久挽詞二首  其一','張嵲','宋','宋诗','song-poetry','','[]','萬里南来日，惟君意最親。',48,'全唐诗/poet.song.105000.json','["萬里南来日，惟君意最親。", "渾如相識舊，殊異白頭新。", "一别遽千古，九衢空萬人。", "道鄉雖有子，不使繼清塵。"]'),
('d0d60539-c404-408e-ac2a-56de4828ea20','鄒德久挽詞二首  其二','張嵲','宋','宋诗','song-poetry','','[]','才具稱要腹，奮然吞八荒。',48,'全唐诗/poet.song.105000.json','["才具稱要腹，奮然吞八荒。", "相期終用世，誰料秪爲郎。", "地下修文久，人間逝水長。", "平湖遊覽處，山色舊蒼蒼。"]'),
('faffb808-78c1-40c3-a81f-a23536b8e181','范覺民挽詞四首  其一','張嵲','宋','宋诗','song-poetry','','[]','射策驚寰海，收名儗岱嵩。',48,'全唐诗/poet.song.105000.json','["射策驚寰海，收名儗岱嵩。", "俄從白面士，遽作黑頭公。", "積善齡何促，流光後必豐。", "他年悲宰樹，獨在淛江東。"]'),
('2882f698-a0c3-4dbb-9ba3-e3c54fc63fea','范覺民挽詞四首  其二','張嵲','宋','宋诗','song-poetry','','[]','舊陰交盖處，草草遂離群。',48,'全唐诗/poet.song.105000.json','["舊陰交盖處，草草遂離群。", "何意終天别，居然此地分。", "豐盈宜上壽，鼎盛忽西曛。", "遥想天台路，悲笳慘暮雲。"]'),
('4ec9cdab-eef5-4e4c-ae60-79dddf1febd2','范覺民挽詞四首  其三','張嵲','宋','宋诗','song-poetry','','[]','有位居台鉉，無年究遠猷。',48,'全唐诗/poet.song.105000.json','["有位居台鉉，無年究遠猷。", "共懷三入望，忽嘆九原幽。", "歸葬新阡遠，追榮恤典優。", "興衰春夢短，人世諒何求。"]'),
('7f01551b-1f08-4366-bf48-b346b87f9cec','范覺民挽詞四首  其四','張嵲','宋','宋诗','song-poetry','','[]','生平輕語别，徒恃接鄉閭。',48,'全唐诗/poet.song.105000.json','["生平輕語别，徒恃接鄉閭。", "及此悲存沒，追維恨闊疏。", "已聞窀穸日，猶怪孟郊書。", "宿草他年哭，仍悲非故墟。"]'),
('52674ed4-701a-477a-a39e-c009aea0cc2a','陸堯夫母吳夫人挽詞','張嵲','宋','宋诗','song-poetry','','[]','在姆毋煩訓，承家綽有宜。',48,'全唐诗/poet.song.105000.json','["在姆毋煩訓，承家綽有宜。", "辛勤當早歲，宴樂近期頤。", "既極南陔養，仍深楓樹悲。", "他年褒女史，不愧管彤詩。"]'),
('bd44c35b-58f5-4bb0-9db6-3dae7fa84c95','余夫人挽詞','張嵲','宋','宋诗','song-poetry','','[]','弱歲承蘋藻，慈和內政惇。',48,'全唐诗/poet.song.105000.json','["弱歲承蘋藻，慈和內政惇。", "辛勤立門戶，壽考見曾孫。", "寵秩官封貴，徽音琬琰存。", "新阡卜何許，當可萬家屯。"]'),
('42a9f6dc-9e60-4e3c-ba1d-bcbc5a8da5b8','送人赴闕','張嵲','宋','宋诗','song-poetry','','[]','宗廟璵璠器，皇家柱石臣。',288,'全唐诗/poet.song.105000.json','["宗廟璵璠器，皇家柱石臣。", "策名存紫府，佐世值昌辰。", "德懋膺宸眷，才雄處要津。", "文辭追賈馬，賓望並荀陳。", "共貴豐年玉，咸推席上珍。", "薦延言有味，發摘政如神。", "既畏西門猛，兼懷鄭産仁。", "化民幾變魯，群盗遂奔秦。", "峻節推邦直，高風聳佞人。", "立身惟耿耿，讒口遂狺狺。", "一出修門道，重嘗未下蓴。", "豈同游澤畔，詎類卧漳濵。", "逸興傾醇酎，清談岸角巾。", "處屯常若泰，在屈每如伸。", "忽下泥金詔，初回雨露春。", "巾車趨象闕，鳴玉覲楓宸。", "江漢終歸海，風花復墜茵。", "途長知騄驥，霜後識松筠。", "道合明良舊，恩濡寵數新。", "調元歸大鼐，爕理屬洪鈞。", "賤子獨何者，龍門亦有賓。", "承顔常數數，惠訓每諄諄。", "屢賞王濛語，寧遺趙壹貧。", "數言真可誦，一語足書紳。"]'),
('a2082bba-391f-4429-8b30-80352f89cbf4','題六合英氏廟','張嵲','宋','宋诗','song-poetry','','[]','野曠煙迷縣，溪湍柳繫航。',96,'全唐诗/poet.song.105000.json','["野曠煙迷縣，溪湍柳繫航。", "雉鳴初翳麥，蠶長未眠桑。", "地有前朝恨，爐殘古廟薌。", "空江長漠漠，寒日自荒荒。", "竟墮蕭何計，仍同項氏亡。", "相黥寧作帝，晝錦亦還鄉。", "嚴瀨終辭漢，箕山不禪唐。", "君王千載恨，行客亦凄凉。"]'),
('135b574f-b90d-40b4-b458-6ceacad16ec0','螢火','張嵲','宋','宋诗','song-poetry','','[]','徂暑初殘夜，飛螢遍曲塘。',72,'全唐诗/poet.song.105000.json','["徂暑初殘夜，飛螢遍曲塘。", "翕張舒焰短，斗注引輝長。", "翻屋星移位，窺簾燼吐光。", "未應彌輦路，聊可映書囊。", "乍與風俱遠，偏隨雨送凉。", "老夫常作客，看汝鬢毛蒼。"]'),
('a3fbf8ee-f9d9-49e2-84bb-83aa3d49d267','偪冬至小雪','張嵲','宋','宋诗','song-poetry','','[]','落葉將埋徑，林寒欲刺天。',72,'全唐诗/poet.song.105000.json','["落葉將埋徑，林寒欲刺天。", "情凝遥嶺外，雪墜草堂前。", "竹密潛增響，梅疏欲鬬妍。", "紛紛迷遠樹，整整度清川。", "未擬乘高看，惟思擁褐眠。", "衡門聊騁望，憔悴廹新年。"]'),
('db0917d7-b762-4ac8-9785-1cfec6752446','和張簿韵','張嵲','宋','宋诗','song-poetry','','[]','長来棲遯興偏濃，秋日山光望欲空。',64,'全唐诗/poet.song.105000.json','["長来棲遯興偏濃，秋日山光望欲空。", "圓紋被水川涵雨，碎影翻林樹带風。", "群山綿亘多連峡，微水瀠洄只向東。", "各有田園歸未得，追陪强欲備鄰翁。"]'),
('0ec36371-1829-4c1f-b3d0-33e5e0c1447a','贈江司令朝宗','張嵲','宋','宋诗','song-poetry','','[]','投老叨恩得一州，平生江令始從游。',64,'全唐诗/poet.song.105000.json','["投老叨恩得一州，平生江令始從游。", "揮豪坐上誇新句，岸幘罇前傲早秋。", "幸有高情能命駕，寧能十日爲吾留。", "詩成苦被黄花惱，急送兵厨與破愁。"]'),
('54d41380-4824-4a9a-a61d-06de102e7a17','十二月二十一日贈沃令','張嵲','宋','宋诗','song-poetry','','[]','訟庭無事長苔衣，卧聽松風白晝遲。',64,'全唐诗/poet.song.106000.json','["訟庭無事長苔衣，卧聽松風白晝遲。", "紙帳亂紋龜殻皺，道衫深綠鶴翎垂。", "塵犀揮處論前史，香篆銷時理秘辭。", "官長既閒春亦早，玉梅初綻兩三枝。"]'),
('917f3cf4-e39c-4bb1-9e2a-85df743fcd65','余所寓僧舍蜂筒忽散去僅留其半僧云分蜂時每如此尋復追求再得之貯以别龕感而成詩','張嵲','宋','宋诗','song-poetry','','[]','每逢晴日競飛飜，忽爲群居負責言。',64,'全唐诗/poet.song.106000.json','["每逢晴日競飛飜，忽爲群居負責言。", "甘美日充辭豢養，蟠藏歲久念騰騫。", "趨衙乍覺朋曹少，分邑疑因支庶繁。", "莫便無情同燕雀，階除得食語喧喧。"]'),
('01937797-c56e-4c83-9d97-f30c50cfd640','賀師垣賜御書一德格天之閣牌并鍍金器皿青羅凉繖從人紫羅衫鍍金腰带儀物等四首  其一','張嵲','宋','宋诗','song-poetry','','[]','炎精光復論元功，事業伊周信比蹤。',64,'全唐诗/poet.song.106000.json','["炎精光復論元功，事業伊周信比蹤。", "許國一心明貫日，存孤高節凛經冬。", "甲區地勢羅千雉，奎畫天門跳六龍。", "自古至誠參化育，濟時行道本中庸。"]'),
('86276ee0-7cd4-4973-8705-9ac9c778f37a','賀師垣賜御書一德格天之閣牌并鍍金器皿青羅凉繖從人紫羅衫鍍金腰带儀物等四首  其二','張嵲','宋','宋诗','song-poetry','','[]','重屋雕甍勢欲翩，睿題藻翰揭中天。',64,'全唐诗/poet.song.106000.json','["重屋雕甍勢欲翩，睿題藻翰揭中天。", "秪緣吉德存方寸，廼爾叢霄格大圓。", "傳自孔門皆一道，稽諸說命合三篇。", "中興如問君臣美，萬世昭時六字傳。"]'),
('c1ea4537-c2ac-4319-b987-61dac9c5595c','賀師垣賜御書一德格天之閣牌并鍍金器皿青羅凉繖從人紫羅衫鍍金腰带儀物等四首  其三','張嵲','宋','宋诗','song-poetry','','[]','柳絲揺曵拂堤沙，瑞氣中藏上相家。',64,'全唐诗/poet.song.106000.json','["柳絲揺曵拂堤沙，瑞氣中藏上相家。", "風動五雲迷御爼，香從雙闕賜天花。", "仙韶合奏塵飛盡，中使宣斟日未斜。", "既醉太平誰事業，爲傾恩意入流霞。"]'),
('042b577c-cb2d-4d0e-890d-8ce628a22ff1','賀師垣賜御書一德格天之閣牌并鍍金器皿青羅凉繖從人紫羅衫鍍金腰带儀物等四首  其四','張嵲','宋','宋诗','song-poetry','','[]','恩詔新頒導從儀，夾塗無復走烏衣。',64,'全唐诗/poet.song.106000.json','["恩詔新頒導從儀，夾塗無復走烏衣。", "競紆紫霧更袍色，仍有黄金上带圍。", "翠幰翩翻風易暖，雕槃璀璨日争輝。", "沙堤矚目人人說，小相行看接軫歸。"]'),
('5be0ec5e-3746-490d-8285-c9fb53c24748','遊嶽麓寺三首  其一','張嵲','宋','宋诗','song-poetry','','[]','平生耳裏湘西寺，此日真成叩梵宫。',64,'全唐诗/poet.song.106000.json','["平生耳裏湘西寺，此日真成叩梵宫。", "地闢晋朝多勝概，人師支遁有高風。", "身遊大士毗耶境，目盡湘東返照中。", "佳處未能頻駐屣，此行尋勝亦怱怱。"]'),
('51899bd9-88ce-41f7-9553-39fb19967233','遊嶽麓寺三首  其二','張嵲','宋','宋诗','song-poetry','','[]','杖策松門興未窮，更過金地雨花中。',64,'全唐诗/poet.song.106000.json','["杖策松門興未窮，更過金地雨花中。", "山泉淅瀝通幽户，林葉蕭森下晚風。", "目極平皋方蒼莽，烟深城郭自空濛。", "他年襆被僧房宿，聊與支郎話色空。"]'),
('8075b771-6719-4f89-8cf2-ce3f2916719e','遊嶽麓寺三首  其三','張嵲','宋','宋诗','song-poetry','','[]','林壑盤紆松徑深，華臺暇日暫登臨。',64,'全唐诗/poet.song.106000.json','["林壑盤紆松徑深，華臺暇日暫登臨。", "雲開楚岫千重出，日落蒼梧萬里陰。", "賈傅文章仍自昔，武王城郭已非今。", "傷時訪古堪流涕，徙倚聊爲澤畔吟。"]'),
('cdab1898-664a-4863-a80e-cceec60d1636','奉酬致宏贈别  其一','張嵲','宋','宋诗','song-poetry','','[]','强顔從宦益堪悲，此日逢君異昔時。',64,'全唐诗/poet.song.106000.json','["强顔從宦益堪悲，此日逢君異昔時。", "末路未忘交似漆，相看各已鬢垂絲。", "亂來世事渾難料，老去生涯詎可思。", "客裏别君情更惡，同歸猶恐尚差池。"]'),
('6ca25494-0bb1-4db5-8dd9-19fbf077d62a','奉酬致宏贈别  其二','張嵲','宋','宋诗','song-poetry','','[]','此生將老竟何爲，未信全關造物兒。',64,'全唐诗/poet.song.106000.json','["此生將老竟何爲，未信全關造物兒。", "十載宦遊無我拙，一生懷抱有君知。", "天邊故國人空老，江畔黄花誰與期。", "跨馬東歸猶是客，離亭别酒莫盈巵。"]'),
('a4dcc897-d4cc-4cfb-befb-e597304ac39a','從劉待制游中梁山寺','張嵲','宋','宋诗','song-poetry','','[]','樓閣高低跨碧空，鱗鱗群樹亞山風。',64,'全唐诗/poet.song.106000.json','["樓閣高低跨碧空，鱗鱗群樹亞山風。", "滄江東去流天外，秦岫西來繞漢中。", "野曠自然傷遠目，天高聊復送飛鴻。", "登臨不起河山念，今日中原有謝公。"]'),
('f04bafa1-5fdb-4669-be8d-700a30f9d0f9','遊道林寺詩三首  其一','張嵲','宋','宋诗','song-poetry','','[]','萬畦霜稻卧黄雲，小徑縈紆接寺門。',64,'全唐诗/poet.song.106000.json','["萬畦霜稻卧黄雲，小徑縈紆接寺門。", "不見高人空像設，更無衲子辯風幡。", "樓觀遠岫秋增媚，窗枕寒溪夜更喧。", "他日重来瞻近影，一憑香火薦蘋蘩。"]'),
('79a7dbff-9b87-4da2-b7c6-7a6c55baf7c3','遊道林寺詩三首  其二','張嵲','宋','宋诗','song-poetry','','[]','悠揚秋日澹岡陵，繫馬喬林叩梵扄。',64,'全唐诗/poet.song.106000.json','["悠揚秋日澹岡陵，繫馬喬林叩梵扄。", "過雨溪流初瀰瀰，無風竹影自泠泠。", "空餘古柏庭前老，依舊寒山户外青。", "惆悵祖師飛錫地，巖阿誰爲一鐫銘。"]'),
('2316b230-edd5-43db-ad98-11753a588e93','遊道林寺詩三首  其三','張嵲','宋','宋诗','song-poetry','','[]','墟落生煙晝欲昏，亂山行盡到平原。',64,'全唐诗/poet.song.106000.json','["墟落生煙晝欲昏，亂山行盡到平原。", "雨餘疊嶂添新秀，水落寒沙見舊痕。", "古寺有僧棲壞屋，遺斜無主自荒村。", "徘徊欲訪當時事，黄葉驚風斷客魂。"]'),
('0ad81923-2829-489d-80e2-a40079b0b8f5','登白帝城二首  其一','張嵲','宋','宋诗','song-poetry','','[]','霜風吹日下長原，夔子城荒灌木繁。',64,'全唐诗/poet.song.106000.json','["霜風吹日下長原，夔子城荒灌木繁。", "東去諸山朝峡口，西来衆水會關門。", "千年白帝空祠廟，萬里家山秪夢魂。", "絕塞邊頭重廻首，秋聲凄斷不堪論。"]'),
('72fa9058-f21a-483c-ae9c-7e820c89de6a','登白帝城二首  其二','張嵲','宋','宋诗','song-poetry','','[]','殊方秋盡怯登臨，萬里屯雲結歲陰。',64,'全唐诗/poet.song.106000.json','["殊方秋盡怯登臨，萬里屯雲結歲陰。", "崖壁𡷸岈知禹績，江山割據識雄心。", "滄波南下奔雲急，單舸東遊兩鬢侵。", "漂轉十方仍作客，沉吟懷古淚沾襟。"]'),
('80a12ca1-a066-4939-85b4-e33a12bd4613','送趙郎二首  其一','張嵲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','匡山太白書淫久，不但天才盖一時。',64,'全唐诗/poet.song.106000.json','["匡山太白書淫久，不但天才盖一時。", "須慕更生勤博古，莫師長吉祗爲詩。", "八塼學士多時譽，七步賢王有令資。", "數子風流君可致，劍門他日看雄辭。"]'),
('ff3b2a19-fbf3-450e-b15f-465163c94345','送趙郎二首  其二','張嵲','宋','宋诗','song-poetry','','[]','亂離何處託浮生，羡子今爲劍外行。',64,'全唐诗/poet.song.106000.json','["亂離何處託浮生，羡子今爲劍外行。", "異縣頻年多送遠，中原何日見承平。", "雲開壠首河山逈，月出巴江閣道横。", "此别相逢定何許，各須努力待時清。"]'),
('c1c307a8-d385-4bf8-82a7-6435a571d28f','余於今年二月初一日夜夢中與劉彦禮兄弟水邊飲酒賦詩曾記所作元八句忘其餘今足成之','張嵲','宋','宋诗','song-poetry','','[]','夢裏相逢竟是非，人生皆夢亦何疑。',64,'全唐诗/poet.song.106000.json','["夢裏相逢竟是非，人生皆夢亦何疑。", "花邊置酒行杯速，石上聽泉得句遲。", "千里幸能申闊積，一歡何必是前期。", "諦觀石火光中事，慮不長於未覺時。"]'),
('fd9462e8-b273-4f94-9d0e-9ba2a0acbd6b','舟泊宜都','張嵲','宋','宋诗','song-poetry','','[]','二年峡內厭覊束，此日江湖欣渺茫。',64,'全唐诗/poet.song.106000.json','["二年峡內厭覊束，此日江湖欣渺茫。", "烱烱晴鷗明晚色，悠悠殘日動波光。", "遠眸盡處即他境，叠嶂痕邊仍舊鄉。", "自是望鄉須淚落，不緣風樹使心傷。"]'),
('a18dda72-13c7-405c-a900-c079e97f48e4','題永睦縣高齋','張嵲','宋','宋诗','song-poetry','','[]','沓嶂寛圍巴水通，登臨眼界浩無窮。',64,'全唐诗/poet.song.106000.json','["沓嶂寛圍巴水通，登臨眼界浩無窮。", "空蒙嵐翠雲煙外，明滅波光樹影中。", "莫詠楓林傷極目，且依蘋末挹雄風。", "中原十載人將盡，相見休嗟似轉蓬。"]'),
('673e1e19-68ac-4601-9351-a28afe378c95','過鄖鄉縣','張嵲','宋','宋诗','song-poetry','','[]','孤城寂寂枕江湄，萬室燒餘事可悲。',64,'全唐诗/poet.song.106000.json','["孤城寂寂枕江湄，萬室燒餘事可悲。", "故老歸来泣環堵，行人竚立問遺基。", "年華祗覺凋容鬢，花鳥何曾管亂離。", "依舊漢傍春事好，野桃開盡暖風遲。"]'),
('6dfd8b25-cb7f-4e73-b85f-9d4a4471d1ff','秋懷二首  其一','張嵲','宋','宋诗','song-poetry','','[]','日壓城煙光少留，朝昏應似我悠悠。',64,'全唐诗/poet.song.106000.json','["日壓城煙光少留，朝昏應似我悠悠。", "人生百歲今已半，世故萬端無幾求。", "學道初聞滅正受，深居不賦畔牢愁。", "尚須一舸輕波上，自詠新詩送白頭。"]'),
('339339cf-eab8-4f42-a057-ecb74c904319','秋懷二首  其二','張嵲','宋','宋诗','song-poetry','','[]','淛河十月菊猶斑，客御貂裘未覺寒。',64,'全唐诗/poet.song.106000.json','["淛河十月菊猶斑，客御貂裘未覺寒。", "遲暮更知爲客惡，覊窮猶自借書看。", "朔風幾夜驅鴻雁，苦雨驚時損蕙蘭。", "安得雀離三百尺，一超紆譎破憂端。"]'),
('da394bfe-994b-42e0-a164-f1ad140b084a','山中月夜','張嵲','宋','宋诗','song-poetry','','[]','中原群盗幾時平，避地荒山萬慮驚。',64,'全唐诗/poet.song.106000.json','["中原群盗幾時平，避地荒山萬慮驚。", "霜月有情凝夜色，溪流無盡落寒聲。", "滿山林影龍蛇動，繞屋風枝劍珮鳴。", "自惜壯懷消欲盡，只將捜句了餘生。"]'),
('965b1786-a45a-4bd3-91c0-e2174e5fc9fb','送别','張嵲','宋','宋诗','song-poetry','','[]','十年漂轉鬢成絲，細話平生萬事非。',64,'全唐诗/poet.song.106000.json','["十年漂轉鬢成絲，細話平生萬事非。", "卻憶青燈初罷酒，俄聞鐡騎已成圍。", "當時痛飲今誰在，從此覊遊與願違。", "客裏别君還歲晚，江湖寥廓淚堪揮。"]'),
('bebc2ab2-ef57-45b5-a40c-d4856dd857b5','予寓居麻子山自入冬以後大小雪凡十餘作傳聞平地已有春意而兹山偪臘復雪寒威特甚','張嵲','宋','宋诗','song-poetry','','[]','荒山絕頂受春遲，幾見冰花散陸離。',64,'全唐诗/poet.song.106000.json','["荒山絕頂受春遲，幾見冰花散陸離。", "江國凝思唯把酒，雲林注目又成詩。", "修篁壓路增幽意，初月臨空耿素姿。", "寧有扁舟可乘興，柴門惆悵獨移時。"]'),
('a96134fb-f5d9-40a1-8401-036b3d1e7bdb','雪晴','張嵲','宋','宋诗','song-poetry','','[]','鳥烏聲樂作初晴，日到寒窗氣象新。',64,'全唐诗/poet.song.106000.json','["鳥烏聲樂作初晴，日到寒窗氣象新。", "天接瓊瑶三萬頃，樹明組練五千人。", "已從炎海生陰戾，更與神皋洗戰塵。", "曾侍紫宸知帝力，隆興借與萬家春。"]'),
('b6c0944d-f3f4-4984-85d6-947948ac2031','小雪作','張嵲','宋','宋诗','song-poetry','','[]','霜風一夜落寒林，莽蒼雲煙結歲陰。',64,'全唐诗/poet.song.106000.json','["霜風一夜落寒林，莽蒼雲煙結歲陰。", "把鏡漸無勳業念，愛山唯駐隐淪心。", "冰花散落衡門静，黄葉飄零一逕深。", "世亂身窮無可奈，强將悲慨事微吟。"]'),
('e6905192-480e-458b-9765-82cf2e154ca7','枕上聞雪呈趙郭二公','張嵲','宋','宋诗','song-poetry','','[]','上瑞来寧玉座憂，夜聲先到竹窗幽。',64,'全唐诗/poet.song.106000.json','["上瑞来寧玉座憂，夜聲先到竹窗幽。", "饑腸已作来年飽，病眼聊須臘月收。", "高士清貧無敝履，故人狂興阻扁舟。", "卻思清曠江邊路，鶉兔成車酒自篘。"]'),
('d2f7074c-6068-473c-b77d-9f865ca7bf74','詠鶴','張嵲','宋','宋诗','song-poetry','','[]','昂藏野鶴混群雞，志在雲天失路悲。',64,'全唐诗/poet.song.106000.json','["昂藏野鶴混群雞，志在雲天失路悲。", "湖海稻粱元未足，虞衡羅網莫輕施。", "獨憐鎩翮垂寒雨，可念長鳴向曉曦。", "卻使群烏驚羽翼，上林能占主人枝。"]'),
('880deb42-c77e-41d5-9f04-c1fddda00062','宿歸仁寺','張嵲','宋','宋诗','song-poetry','','[]','精藍置屋切雲根，此地何從着世紛。',64,'全唐诗/poet.song.106000.json','["精藍置屋切雲根，此地何從着世紛。", "縹緲僧窗更臨水，氛氲崖樹欲參雲。", "青山細認千重叠，暮氣徐觀萬里曛。", "兩岸蟲鳴燈一點，舟人相語夜深聞。"]'),
('1574df0e-5e89-4648-8858-16c9cd1c1e5b','高司業二首  其一','張嵲','宋','宋诗','song-poetry','','[]','春浮花氣擁門闌，星昴神嵩瑞世間。',64,'全唐诗/poet.song.106000.json','["春浮花氣擁門闌，星昴神嵩瑞世間。", "一字夢靈通洛學，諸儒文弊隔賢關。", "巨源淳德真金玉，吏部高名信斗山。", "此去致君堯舜上，黑頭卿相自朱顔。"]'),
('08941695-ba20-4e9a-9da8-5d3fceb49faf','高司業二首  其二','張嵲','宋','宋诗','song-poetry','','[]','旌頭落盡少微明，追復成均雅頌聲。',64,'全唐诗/poet.song.106000.json','["旌頭落盡少微明，追復成均雅頌聲。", "詔起儒宗高一代，禮隆師範表諸生。", "拾遺柱史當螭立，潤色綸言倚馬成。", "行把荷囊多獻納，要將文彩助昇平。"]'),
('4a68def7-c4d5-43c4-b6a0-3f89bab7772f','代王侍郎送程尚書赴信州三首  其一','張嵲','宋','宋诗','song-poetry','','[]','化龍陂逈照旌旗，懷玉峰高緩馬覊。',64,'全唐诗/poet.song.106000.json','["化龍陂逈照旌旗，懷玉峰高緩馬覊。", "地接鄉關猶晝錦，人從國老借元龜。", "一州如斗何勞者，六合同風要在兹。", "此去未能温坐席，卻隨春到鳳凰池。"]'),
('434dd4b2-3159-4287-95e5-18dea510c519','代王侍郎送程尚書赴信州三首  其二','張嵲','宋','宋诗','song-poetry','','[]','德望居朝大吕輕，眷思難怫丐歸情。',64,'全唐诗/poet.song.106000.json','["德望居朝大吕輕，眷思難怫丐歸情。", "履聲暫去端門曉，刀夢新占虎節榮。", "有道致君三任喜，無心貪寵一麾行。", "天衷祗恐思耆舊，不待黄堂報政成。"]'),
('c8610374-4a2a-4ae0-9b6f-b3f660c9a49e','代王侍郎送程尚書赴信州三首  其三','張嵲','宋','宋诗','song-poetry','','[]','君王鍾意撫斯民，不惜朝端屈老臣。',64,'全唐诗/poet.song.106000.json','["君王鍾意撫斯民，不惜朝端屈老臣。", "連錦麾毫千字寵，黄金横带萬釘珍。", "長安日近恩光邇，刺史天高惠政新。", "我愧仙巖舊猿鶴，依然軒冕縳閒身。"]'),
('35c19dd9-9780-41b4-89d9-dfbd3e59272c','初夏已晚山中即事','張嵲','宋','宋诗','song-poetry','','[]','山雲倐忽自晴陰，積雨門楥蔓草侵。',64,'全唐诗/poet.song.106000.json','["山雲倐忽自晴陰，積雨門楥蔓草侵。", "一带清川供極目，千重沓嶂伴微吟。", "雄鳩鳴處園林密，白鳥飛来溝水深。", "麥秀桑柔夏方永，不堪時序苦侵尋。"]'),
('bc4e89e9-b15c-42aa-90ba-b08854e3f15f','遣興二首  其一','張嵲','宋','宋诗','song-poetry','','[]','人生何必論才良，賢否窮通脱未量。',64,'全唐诗/poet.song.106000.json','["人生何必論才良，賢否窮通脱未量。", "運否蛟龍猶蠖屈，時來鳥雀亦鷹揚。", "王侯螻蟻同歸盡，鍾鼎山林各所藏。", "何用作文嗟不遇，已將名利等蠅翔。"]'),
('ffd080df-fbc6-4e65-b97c-19920fe4bc31','遣興二首  其二','張嵲','宋','宋诗','song-poetry','','[]','少年豪縱志凌雲，著論將期擬過秦。',64,'全唐诗/poet.song.106000.json','["少年豪縱志凌雲，著論將期擬過秦。", "當日詩書徒用世，如今文字豈謀身。", "亂離不用毛錐子，漂轉聊同木偶人。", "主父平生希鼎食，年来一飽尚艱辛。"]'),
('676e06c2-d4e7-4f09-bc37-ba28448bde18','三月二日奉詔赴西園曲宴席上賦呈致政開府太師三首  其一','張嵲','宋','宋诗','song-poetry','','[]','幅巾私第已歸休，當宁虚懷更款留。',64,'全唐诗/poet.song.106000.json','["幅巾私第已歸休，當宁虚懷更款留。", "避寵雖辭持節冊，送行猶用濟川舟。", "城南舊圃扄花洞，洛下新莊引御溝。", "詔諭兩京居密邇，不妨乘興往還游。"]'),
('94ff7634-d626-44a4-9952-e6c421968e25','三月二日奉詔赴西園曲宴席上賦呈致政開府太師三首  其二','張嵲','宋','宋诗','song-poetry','','[]','邦人欽佇見儀刑，詔使相望對寵靈。',64,'全唐诗/poet.song.106000.json','["邦人欽佇見儀刑，詔使相望對寵靈。", "位冠三公師尚父，躬全五福壽康寧。", "久留行色春過半，乍别天顔涕欲零。", "誰識上心優老意，從行仍許鯉趨庭。"]'),
('f7efc223-6437-480d-a626-3cb5d1c24e16','三月二日奉詔赴西園曲宴席上賦呈致政開府太師三首  其三','張嵲','宋','宋诗','song-poetry','','[]','昔美都門祖二疏，太冲篇詠貴良圖。',64,'全唐诗/poet.song.106000.json','["昔美都門祖二疏，太冲篇詠貴良圖。", "不聞賓主俱公鼎，未見篇章出寶跗。", "河嶽英靈添賦咏，都人士女競歡娱。", "皆言元老歸休盛，恩禮便蕃自古無。"]'),
('27cfb3b5-b178-4c7b-980a-04efd18925be','雨中感懷','張嵲','宋','宋诗','song-poetry','','[]','西風揺落葉聲悲，避亂荒山萬緒迷。',64,'全唐诗/poet.song.106000.json','["西風揺落葉聲悲，避亂荒山萬緒迷。", "一室漂揺任寒雨，百年昏曉信鳴雞。", "清霜已染千楓樹，殺氣應隨萬馬蹄。", "黄屋秋來定何許，孤臣安敢恨覊栖。"]'),
('3021321c-5202-471b-bf27-e78617e77cbd','舟中感懷','張嵲','宋','宋诗','song-poetry','','[]','故園此去渾如客，異縣而今卻是家。',64,'全唐诗/poet.song.106000.json','["故園此去渾如客，異縣而今卻是家。", "還日簷楹應着燕，來時楊柳未藏鵶。", "孤舟泛泛春江闊，去鳥飛飛岸樹斜。", "卻憶當年南下日，傷心泣盡日昏華。"]'),
('fd8e2ab5-fba7-4ffc-9ff4-011cc9bca12d','歎名','張嵲','宋','宋诗','song-poetry','','[]','十年四海稱忠壯，誰料將軍陰子謀。',64,'全唐诗/poet.song.106000.json','["十年四海稱忠壯，誰料將軍陰子謀。", "舊物空餘叱撥馬，新聲莫唱白符鳩。", "民謠幾歲傳鈎落，笙席何人戀故侯。", "溟海茫茫孤鳥没，一埋蓬顆便千秋。"]'),
('5b969c13-729f-48f1-bc98-919780797e0f','會覽亭三首  其一','張嵲','宋','宋诗','song-poetry','','[]','縹緲飛亭接郡樓，平崗絕岸對滄洲。',64,'全唐诗/poet.song.106000.json','["縹緲飛亭接郡樓，平崗絕岸對滄洲。", "天邊遠岫寒無色，城下澄江湛不流。", "林影終朝垂澹瀩，水禽隨暖弄輕浮。", "何時放髪從漁父，會傍蒼烟卧釣舟。"]'),
('54edfab5-78d0-41e5-b345-33bd07366e7b','會覽亭三首  其二','張嵲','宋','宋诗','song-poetry','','[]','野岸平林對郡城，登臨領要在斯亭。',64,'全唐诗/poet.song.106000.json','["野岸平林對郡城，登臨領要在斯亭。", "江吞荆楚流空闊，山入興洋翠杳冥。", "歲晚雲煙昏近甸，沙晴鷗鷺滿前汀。", "杖藜竟日窮心賞，猶自覊愁未肯醒。"]'),
('289bbdcb-91cd-464a-bf1f-d303900c68e0','會覽亭三首  其三','張嵲','宋','宋诗','song-poetry','','[]','角聲嗚咽下城頭，水國風煙欲暮愁。',64,'全唐诗/poet.song.106000.json','["角聲嗚咽下城頭，水國風煙欲暮愁。", "遠日苦遭層嶂隔，歸心欲逐大江流。", "漁村積火臨沙岸，賈客連檣集市樓。", "千里家山一廻首，林梢新月又如鈎。"]'),
('9497a037-d7db-4a5b-9b72-118c991cad7a','潭州道中','張嵲','宋','宋诗','song-poetry','','[]','青山接雲雲接天，碧林溪樹兩相鮮。',64,'全唐诗/poet.song.106000.json','["青山接雲雲接天，碧林溪樹兩相鮮。", "地連諸徼分秋色，天近平湖識渚煙。", "望盡好峰仍注目，賞餘幽樹更垂鞭。", "是身已作無貲省，乘興將隨下瀨船。"]'),
('533d7add-e49c-4145-9299-e03a50305bfe','示疑者','張嵲','宋','宋诗','song-poetry','','[]','天見已如摩勒果，佛求休待鉢曇花。',64,'全唐诗/poet.song.106000.json','["天見已如摩勒果，佛求休待鉢曇花。", "萬緣畢竟歸空刼，舉世徒勞筭海沙。", "除幻已超白骨觀，修真閒運紫河車。", "時人欲識歸投處，無盡光中是我家。"]'),
('588e7637-f21b-429e-9223-2a27950057ab','溪梅初放','張嵲','宋','宋诗','song-poetry','','[]','荒山犖确倦征行，溪畔逢梅照眼明。',64,'全唐诗/poet.song.106000.json','["荒山犖确倦征行，溪畔逢梅照眼明。", "枝裊霜天寒日薄，影沉碧澗晚流清。", "最憐雪後開来痩，可忍風前落去輕。", "卻悔折歸無可贈，舊遊千里但凝情。"]'),
('96a9953d-5c9b-4cc1-9ec3-48598f3123d8','次韵石用之春晴遊西湖','張嵲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春晴結客出城隅，無數僧坊論給孤。',64,'全唐诗/poet.song.106000.json','["春晴結客出城隅，無數僧坊論給孤。", "紅貼馬蹄花底路，綠籠船背柳邊湖。", "逍遥各自從鵬鷃，斷續寧須較鶴鳬。", "端立一丘爲老計，移文何謝北山逋。"]'),
('a68c0870-3707-4907-a0c5-7ea7aff6cb04','舟中即事','張嵲','宋','宋诗','song-poetry','','[]','西来一櫂任委蛇，春日惟增雨露悲。',64,'全唐诗/poet.song.106000.json','["西来一櫂任委蛇，春日惟增雨露悲。", "故國佳辰逢禁火，水鄉農事見扶犁。", "年華祗觧凋容鬢，花鳥何曾管亂離。", "目極傷心誰告語，含毫獨賦遠遊詩。"]'),
('36867b3a-299c-4cdc-8903-77af14dbb5c0','泊舟','張嵲','宋','宋诗','song-poetry','','[]','遥依沙岸繫扁舟，風落荒山萬木愁。',64,'全唐诗/poet.song.106000.json','["遥依沙岸繫扁舟，風落荒山萬木愁。", "枕下驚波時汨汨，天邊寒夢信悠悠。", "遭憂和嶠仍丹淚，遠適虞翻易白頭。", "離亂偪人全策少，微生從此任浮遊。"]'),
('51a10f63-b30b-402a-9ed2-e6c0b475cd08','自竹山歸酇上墳','張嵲','宋','宋诗','song-poetry','','[]','晨曦出沒霧交流，獨喚江船立渡頭。',64,'全唐诗/poet.song.106000.json','["晨曦出沒霧交流，獨喚江船立渡頭。", "嵐光映縣民居麗，紅葉漫山客意愁。", "溪雲欲作今朝雨，崖菊猶含舊歲秋。", "此日還歸追曩事，孤生淚盡黑貂裘。"]'),
('b85deca8-4bc7-41c0-9f0a-92647f9139eb','周參謀以詩催再遊末章戲賦二首  其一','張嵲','宋','宋诗','song-poetry','','[]','九十日春晴幾日，得堪行處便須行。',64,'全唐诗/poet.song.106000.json','["九十日春晴幾日，得堪行處便須行。", "官因局冷常多暇，眼到花開亦暫明。", "當信光陰如過隙，莫教風雨暗長檠。", "乘陽不礙遊人路，定看花驄正勒鳴。"]'),
('6242e81b-2eff-4635-85d8-0a0c0021d8c5','周參謀以詩催再遊末章戲賦二首  其二','張嵲','宋','宋诗','song-poetry','','[]','競說楊枝傾上國，樂天題品付歌行。',64,'全唐诗/poet.song.106000.json','["競說楊枝傾上國，樂天題品付歌行。", "但同學語雛鶯小，未見回眸剪水明。", "席舍主人能顧曲，曉來粧燭想銷檠。", "海棠何必尋龍井，願聽周詩賦鹿鳴。"]'),
('f130ca47-b5ec-4b48-bae9-cbe782570259','喜張丞相破湖賊','張嵲','宋','宋诗','song-poetry','','[]','遥欣丞相受降時，湖外歡聲入鼓鼙。',64,'全唐诗/poet.song.106000.json','["遥欣丞相受降時，湖外歡聲入鼓鼙。", "十萬水軍歸禁旅，二千里地反鋤犁。", "弄兵無復潢池內，棄甲應同熊耳齊。", "從此上流無犬吠，好營停障接京西。"]'),
('3c5b9118-014e-45dd-b3d9-032c9bf01381','昔柳柳州作永州山水諸記泉石之狀如在目前兹峡上群山與柳州之文頗類','張嵲','宋','宋诗','song-poetry','','[]','山磎犖确冒荒筠，石溜涓涓盡日聞。',64,'全唐诗/poet.song.106000.json','["山磎犖确冒荒筠，石溜涓涓盡日聞。", "微水寒来渾見底，峡山雪後欲侵雲。", "深溪春動梅争發，絕壑林高日易曛。", "應似零陵溪上景，林泉多類柳州文。"]'),
('d352894f-3df9-4e00-a7f6-40723bc8d832','繼韵書胡氏孝思亭','張嵲','宋','宋诗','song-poetry','','[]','舉世針磁覔秀峰，争從窀穸問窮通。',64,'全唐诗/poet.song.106000.json','["舉世針磁覔秀峰，争從窀穸問窮通。", "喜君篤孝誠尤至，追想慈顔事已空。", "積毁到今猶瘠立，因知卓行不雷同。", "當時甘旨庭闈念，應向廬前歎樹風。"]'),
('6d628249-496d-44ad-9347-0f95d950d807','寓居','張嵲','宋','宋诗','song-poetry','','[]','未有揚雄宅一區，已驚短髪似盧蒲。',64,'全唐诗/poet.song.106000.json','["未有揚雄宅一區，已驚短髪似盧蒲。", "家貧粥飯隨魚鼓，地遠賓從祗鳥烏。", "已罷書空爲咄咄，猶思快耳作嗚嗚。", "衰殘政值中興日，聊得安閒卧五湖。"]'),
('40b7d423-3838-4f59-82c2-a842249ea676','如吳興舟中讀白樂天詩有作','張嵲','宋','宋诗','song-poetry','','[]','離離雲樹泛朝舣，十月江南未變衰。',64,'全唐诗/poet.song.106000.json','["離離雲樹泛朝舣，十月江南未變衰。", "縱櫂千尋霅溪水，散懷一卷樂天詩。", "平生名宦休回顧，隨分追遊且自欺。", "不敢將心比餘事，逍遥何似洛川時。"]'),
('43fdefd2-77d6-4b56-81d9-2342099d7240','新春偶書寄致宏','張嵲','宋','宋诗','song-poetry','','[]','二年憔悴向庸城，又見椒花倐自驚。',64,'全唐诗/poet.song.106000.json','["二年憔悴向庸城，又見椒花倐自驚。", "孤客殊方懷土意，故人絕塞未歸情。", "此生竟被儒冠誤，他日終圖後世名。", "平野春来堪細履，何時與子杖藜行。"]'),
('936fe157-0df9-4002-9950-b546c651ec16','新春有感','張嵲','宋','宋诗','song-poetry','','[]','蕭蕭篠簜擁荒岡，卻憶江皋草色長。',64,'全唐诗/poet.song.106000.json','["蕭蕭篠簜擁荒岡，卻憶江皋草色長。", "暖景暄風似春日，黄茅白葦是殊方。", "孤村默默無誰語，萬事悠悠有底忙。", "獨立寺門歸鳥盡，重山複嶺又蒼蒼。"]'),
('623c5b46-f060-47eb-a06f-5f15d80ddbfc','上庸','張嵲','宋','宋诗','song-poetry','','[]','天將層嶂限中原，獸狀禽心類百蠻。',64,'全唐诗/poet.song.106000.json','["天將層嶂限中原，獸狀禽心類百蠻。", "横木架橋来渡水，搴茅茹火去燒山。", "尋巫問事看龜意，带穗收禾禦歲艱。", "非是投荒魑魅侣，時清猶賴可東還。"]'),
('43d4fc99-7b3c-4286-8ff7-892a55b29d8c','仇氏園','張嵲','宋','宋诗','song-poetry','','[]','泠泠竹日澹疏籬，狖狖溪流注小池。',64,'全唐诗/poet.song.106000.json','["泠泠竹日澹疏籬，狖狖溪流注小池。", "紅菡白蘋當夏日，冷煙寒雨過秋時。", "主人頤燕閒情適，客子經過心事違。", "行役怱怱無麗句，漫批山木寫吾詩。"]'),
('3706d9d5-76da-4427-868f-23d25fd8285c','和友人中秋','張嵲','宋','宋诗','song-poetry','','[]','秋来未省舉盃頻，卻掃空山絕衆賓。',64,'全唐诗/poet.song.106000.json','["秋来未省舉盃頻，卻掃空山絕衆賓。", "寂歷平林方隕葉，扶疏丹桂獨生春。", "天高地逈輪當午，露白星稀夜向晨。", "聞道開樽成浪語，不妨聊作獨醒人。"]'),
('c0941e05-eec6-4e5f-911c-8e38f8235794','戯書寄夏致宏','張嵲','宋','宋诗','song-poetry','','[]','蕭何轉漕關中日，綺季逍遥商嶺時。',64,'全唐诗/poet.song.106000.json','["蕭何轉漕關中日，綺季逍遥商嶺時。", "世亂或爲舟楫用，時平自可帝王師。", "試問升車驅駟馬，如何踞石茹三芝。", "荒山歲暮雲煙冷，西望長吟獨爾思。"]'),
('2013baea-13af-48b6-9461-b88470283cc4','梅二首  其一','張嵲','宋','宋诗','song-poetry','','[]','兩京當日見初開，尚想凌雲遶故臺。',64,'全唐诗/poet.song.106000.json','["兩京當日見初開，尚想凌雲遶故臺。", "倚竹姱姿應小駐，高樓急管未須催。", "傷春遠目空千里，急景愁腸自九廻。", "爲說西園泉脈動，許攜小隊探春来。"]'),
('234620ba-2c4a-4fde-8858-20cdffa2d815','梅二首  其二','張嵲','宋','宋诗','song-poetry','','[]','荒山雪盡水生煙，獨發寒英媚遠天。',64,'全唐诗/poet.song.106000.json','["荒山雪盡水生煙，獨發寒英媚遠天。", "亂蕊凝姿殘照裏，痩松含態晚風前。", "疑將翠袖倚修竹，若獻明璫傍廣川。", "喪亂自嗟容鬢改，攀條三嗅惜流年。"]'),
('87749308-a664-467e-92bf-a752774f036d','寄題清孝菴','張嵲','宋','宋诗','song-poetry','','[]','龍山幾世閱興衰，依舊春江拍岸来。',64,'全唐诗/poet.song.106000.json','["龍山幾世閱興衰，依舊春江拍岸来。", "當代衣冠今寂寞，百年丘隴自崔嵬。", "簷經白日餘僧定，路暗青松仍刼灰。", "事去節闌春草積，乘高一望獨遲回。"]'),
('334eaede-08d4-4313-a034-09b453b30229','望微水','張嵲','宋','宋诗','song-poetry','','[]','平原莽蒼浮輕靄，白晝柴門亦自扄。',64,'全唐诗/poet.song.106000.json','["平原莽蒼浮輕靄，白晝柴門亦自扄。", "籬外水波光滅没，林邊山岫遠青冥。", "如何隐几終朝看，不及寒窗静夜聽。", "聽水看山朝復暮，那知白髪漸星星。"]'),
('c0aedb9f-92d2-4ca0-9e0f-bffa1d9b16fe','春陰江上偶書','張嵲','宋','宋诗','song-poetry','','[]','小軒西下俯通津，漠漠春陰日易曛。',64,'全唐诗/poet.song.106000.json','["小軒西下俯通津，漠漠春陰日易曛。", "白氣冒山蒸積翠，微風過水聚輕紋。", "城鴉飛去秋花夕，溪雨收餘岸草薰。", "寂寞何人念覊旅，憂来無數若絲棼。"]'),
('a3d76551-03f6-4fd4-9b6e-9188f5ccb295','登甘露寺故基','張嵲','宋','宋诗','song-poetry','','[]','烈風吹面立城隅，俯仰人間萬事徂。',64,'全唐诗/poet.song.106000.json','["烈風吹面立城隅，俯仰人間萬事徂。", "萬古江山自雄渾，百年城郭已蓁蕪。", "亂餘故物惟金鼎，事往前賢只畫圖。", "雙塔烟中廣陵市，淮南戍守未應無。"]'),
('940878aa-6a59-43df-a4a3-fa63df7b813f','種木芙蓉','張嵲','宋','宋诗','song-poetry','','[]','去歲經冬百卉空，今年多種木芙蓉。',64,'全唐诗/poet.song.106000.json','["去歲經冬百卉空，今年多種木芙蓉。", "未如蜀國城邊望，疑是秋江渡口逢。", "定乏雄蜂来慰藉，應與寒菊伴丰容。", "敢同出水方新句，空自長吟負老松。"]'),
('de6a8081-42b8-4349-9f84-598fee2af3a6','次韵石用之易安齋','張嵲','宋','宋诗','song-poetry','','[]','塵纓脱得片時閒，未見彌天釋道安。',64,'全唐诗/poet.song.106000.json','["塵纓脱得片時閒，未見彌天釋道安。", "薜荔半崖雙屐齒，滄浪何日一綸竿。", "地能容膝皆堪處，心對回光未易看。", "試問老僧安底事，不知人世有悲歡。"]'),
('d2c50c63-4753-4c2f-9f59-bc3546f3b413','和夏致宏詠梅','張嵲','宋','宋诗','song-poetry','','[]','春嵐初破曉光遲，青女消餘泫玉肌。',64,'全唐诗/poet.song.106000.json','["春嵐初破曉光遲，青女消餘泫玉肌。", "雪後離披憐落蕋，溪旁婉約愛横枝。", "不隨姑射乘風去，定與飛仙待月期。", "山静林深香暗度，折来頻動故園思。"]'),
('edd49ab9-1a4a-4dc7-a15c-867a5845cb48','憶京山大陽寺','張嵲','宋','宋诗','song-poetry','','[]','往歲曾遊大陽寺，倚天樓殿碧參差。',64,'全唐诗/poet.song.106000.json','["往歲曾遊大陽寺，倚天樓殿碧參差。", "明安菴逈峰巒古，楊廣城高逕路危。", "滿壑松聲僧定處，一堂秋雨客談時。", "如今細想經行地，三復遺詩血淚垂。"]'),
('d48d8a44-1389-478d-b80d-7cfeda02c6a4','行建溪上見拏舟上水者愴然傷懷','張嵲','宋','宋诗','song-poetry','','[]','何人刺船上寒水，卻意避地微江時。',64,'全唐诗/poet.song.106000.json','["何人刺船上寒水，卻意避地微江時。", "驚濤澎湃慈親懼，鼓棹紛紜稚子嬉。", "漫漫平沙煙上早，溟溟簧竹月生遲。", "感舊將爲仰天哭，恐驚行路秪成詩。"]'),
('071a5f60-7d72-4920-bb63-7591c288ef20','春日郊行','張嵲','宋','宋诗','song-poetry','','[]','曉尋山寺出重城，壞壁誰題半草行。',64,'全唐诗/poet.song.106000.json','["曉尋山寺出重城，壞壁誰題半草行。", "照眼芳菲空玉友，並湖風物記金明。", "新詩已見成敲鉢，舊賞懸知又棄檠。", "龍井海棠須靳惜，一樽留取聽鶯鳴。"]'),
('6aa4ed5e-7959-40dc-85e0-6bc9ae2df6b1','屏迹','張嵲','宋','宋诗','song-poetry','','[]','荒村屏迹任時移，山水昏明各異姿。',64,'全唐诗/poet.song.106000.json','["荒村屏迹任時移，山水昏明各異姿。", "穹谷煙凝成襞積，斜林風過作鱗差。", "病身豈復能強徤，末路惟應足抵巇。", "萬古升沉同鳥没，蓋棺猶未且題詩。"]'),
('025a7186-3511-4f12-a6e9-72c071f57306','泛舟觀雨','張嵲','宋','宋诗','song-poetry','','[]','雲氣交流晝窈冥，疾風吹雨雜荷聲。',64,'全唐诗/poet.song.106000.json','["雲氣交流晝窈冥，疾風吹雨雜荷聲。", "山隨眀晦姿横出，舟入渺茫詩漸成。", "託迹江湖三畆足，放懷天地一身輕。", "衘盃不用嗟覊寓，未必乘槎勝此行。"]'),
('e5bcf758-363c-436d-8d25-78bc5f584218','次韵王亞之沿湖冒雨歸','張嵲','宋','宋诗','song-poetry','','[]','禽鳴滑滑濺泥塗，賴有雲巢眼不孤。',64,'全唐诗/poet.song.106000.json','["禽鳴滑滑濺泥塗，賴有雲巢眼不孤。", "天外黑風迷鷲嶺，檻前流水憶鵝湖。", "躋攀危磴九折坂，捧玩新詩百斛珠。", "收拾殘紅付春去，四時光景任三無。"]'),
('e7505407-3164-4777-a52c-59b522f401d7','芍藥','張嵲','宋','宋诗','song-poetry','','[]','青春愛謝日遲遲，正是群芳掃跡時。',64,'全唐诗/poet.song.106000.json','["青春愛謝日遲遲，正是群芳掃跡時。", "濃露有情融睡臉，暄風無力困豐肌。", "苦將蕊氣相牽引，若對華燈不自持。", "應似西江明夜火，館娃宫裏醉西施。"]'),
('b894fd35-aee6-428b-957d-8a7181d33020','龍洞','張嵲','宋','宋诗','song-poetry','','[]','靈洞何年水亂流，試尋危棧訪丹丘。',64,'全唐诗/poet.song.106000.json','["靈洞何年水亂流，試尋危棧訪丹丘。", "此時景物迷三島，當日神龍跨九州。", "白晝瀑流方訝雨，炎天嵐氣忽驚秋。", "憧憧門外紅塵路，過客何人肯暫留。"]'),
('5a97d7d3-408a-45fb-ad22-3ac27552cfa2','自鉛山如鵝湖','張嵲','宋','宋诗','song-poetry','','[]','長松十里曉冥冥，行盡松林到法城。',64,'全唐诗/poet.song.106000.json','["長松十里曉冥冥，行盡松林到法城。", "悄悄虛廊無客語，陰陰衆綠有鶯聲。", "新荷萬點土花碧，白鷺一行春雪輕。", "麥秀漸漸桑葉暗，怳然如在故園行。"]'),
('6f17a1c7-84b3-4799-a469-f7ad31623713','九日三首  其一','張嵲','宋','宋诗','song-poetry','','[]','南國窮秋冷尚賖，隨時遊矚自堪嘉。',64,'全唐诗/poet.song.106000.json','["南國窮秋冷尚賖，隨時遊矚自堪嘉。", "且欣一雨山争出，休歎重陽菊未華。", "佳客逢秋宜得句，道人酌酒似烹茶。", "人生勝日須行樂，豫去昏鴉作陣斜。"]'),
('b33c175e-1292-42ef-bd29-211f084f62cf','九日三首  其二','張嵲','宋','宋诗','song-poetry','','[]','登高未用懷郪縣，少異誰能識孟嘉。',64,'全唐诗/poet.song.106000.json','["登高未用懷郪縣，少異誰能識孟嘉。", "歲歲青罇常有酒，年年黄菊未逢花。", "分將默坐更捜句，肯以銜盃當飲茶。", "且莫憑欄傷極目，人間秋日易西斜。"]'),
('69ba3321-d256-4a2b-9778-d1932ff9c0e3','九日三首  其三','張嵲','宋','宋诗','song-poetry','','[]','九日當年菊蕊遲，今年庭下半芳菲。',64,'全唐诗/poet.song.106000.json','["九日當年菊蕊遲，今年庭下半芳菲。", "禾收原野將成廪，楓落江湖欲授衣。", "何處好山饒勝概，擬攜家釀趁晴暉。", "病衰不復能捜句，聊插紅茰滿帽歸。"]'),
('9f87b6d3-bd01-4e18-8847-cfa6db48a70c','夏養真父挽詞','張嵲','宋','宋诗','song-poetry','','[]','四十青春鬢未皤，翻如槁謝葉辭柯。',64,'全唐诗/poet.song.106000.json','["四十青春鬢未皤，翻如槁謝葉辭柯。", "親闈有綵今難戯，客舘無魚尚有歌。", "遺愛偏存梅渚畔，新塋空占闔山阿。", "素車不得親觴酹，别望含悲獨奈何。"]'),
('2a0c700c-4ad1-4c06-9879-5a56d4ef0ae0','忠顯劉公挽詩四首  其一','張嵲','宋','宋诗','song-poetry','','[]','活人憂國見平生，晚節臨危志益明。',64,'全唐诗/poet.song.106000.json','["活人憂國見平生，晚節臨危志益明。", "漢仗塵深遠宫闕，氊裘風急半公卿。", "千人致詔竟不起，萬户封侯卻似烹。", "暮晋朝梁真可忍，紛紛螻蟻尚偷生。"]'),
('563f8256-33ef-4c1f-89c4-ffaa5695b31d','忠顯劉公挽詩四首  其二','張嵲','宋','宋诗','song-poetry','','[]','禍基媒孽自燕雲，抗議如公有幾人。',64,'全唐诗/poet.song.106000.json','["禍基媒孽自燕雲，抗議如公有幾人。", "軍旅未聞焉用試，豺狼不噬豈宜親。", "求魚緣木謾蠧國，曲突徙薪翻殞身。", "才大言深古難用，忠良千載恨常新。"]'),
('90b67ae7-0901-4316-bbd3-8c778186b86f','忠顯劉公挽詩四首  其三','張嵲','宋','宋诗','song-poetry','','[]','自從玉帛交殊域，一見寒盟爲隐憂。',64,'全唐诗/poet.song.106000.json','["自從玉帛交殊域，一見寒盟爲隐憂。", "亂相方虞鄰國難，廟堂誰聽徙薪謀。", "義如杞殖仍忠壯，識比申胥不怨尤。", "松柏蕭蕭九原路，高名常共建溪流。"]'),
('dbd16f3c-7bcc-40d2-bf0c-7aaa29ea3d94','忠顯劉公挽詩四首  其四','張嵲','宋','宋诗','song-poetry','','[]','抗論中朝猶在耳，鳴弓仇敵已臨城。',64,'全唐诗/poet.song.106000.json','["抗論中朝猶在耳，鳴弓仇敵已臨城。", "王都竟失金湯固，朝士方貪雀鼠生。", "慷慨一朝先奮節，華戎終古共知名。", "可惜千官臣僞後，蕭蕭華髪盡垂纓。"]'),
('61163c4b-952a-4aa5-97c5-a606de5630ad','哭孫信道','張嵲','宋','宋诗','song-poetry','','[]','悲君刻意異時流，十載經春着敝裘。',64,'全唐诗/poet.song.106000.json','["悲君刻意異時流，十載經春着敝裘。", "新隴預知成馬鬛，舊書何苦似蠅頭。", "孟郊骨相終齎志，賈誼才能竟不侯。", "寂寞聲名千古事，定知無益夜臺幽。"]'),
('2ea7028d-4d01-4ebe-a652-e4e2f4d08a91','挽張全真詩二首  其一','張嵲','宋','宋诗','song-poetry','','[]','辱遇本非因紹介，登門不謂便無期。',64,'全唐诗/poet.song.106000.json','["辱遇本非因紹介，登門不謂便無期。", "傾心問及言猶在，投贄書成事已悲。", "作鎮方甘建鄴水，惜賢尤在中興時。", "傷心無復諮疑事，還似當年徐孺碑。"]'),
('99591d94-e2e6-4722-af92-5acfc815e84f','挽張全真詩二首  其二','張嵲','宋','宋诗','song-poetry','','[]','玉質清臞似列仙，人間亦合得長年。',64,'全唐诗/poet.song.106000.json','["玉質清臞似列仙，人間亦合得長年。", "功名不竟如壺遂，冲淡空嗟似樂天。", "胡不憗遺緣國老，憂深殄瘁爲時賢。", "含毫誰作名臣傳，要使風流後世傳。"]'),
('00eded64-85a6-479a-b38a-0ced240e3af1','壽王蘇州','張嵲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','維昔高堂講射蓬，瑞雲吹不散薰風。',320,'全唐诗/poet.song.106000.json','["維昔高堂講射蓬，瑞雲吹不散薰風。", "十分正滿冰輪桂，一葉將飛露井桐。", "元老三朝尊相閥，餘休幾世積陰功。", "光芒孕秀星淪昴，神物儲祥嶽降嵩。", "淮水筮靈芳裔遠，蜀江波與慶源通。", "傳家自有調元手，許國常輸露膽忠。", "節勁不凋霜後柏，氣豪長吐雨餘虹。", "金隄護掃河循道，蘭省分曹宿在穹。", "銅虎屢揚飛盖皂，木牛多足太倉紅。", "朝班入簉鵷鴻列，京尹頻令狴犴空。", "暫綴漢庭安世橐，来臨吳國館娃宫。", "民安泰伯封疆外，日在韋侯嘯詠中。", "贊壽一爐金篆籀，捧觴千髻玉玲瓏。", "桃開坐閱三千歲，松夢當占十八公。", "日望鋒車歌九罭，時韜組甲詠車攻。", "如君江左今王導，有客河陽舊石洪。", "甄冶從来收朽鈍，涓埃殊未報深崇。", "省臺衮衮心何羡，旌斾揺揺思莫窮。", "賓綴阻陪稱壽斚，書緘聊復寄詩筒。", "西湖十里荷花水，净洗觥船遠祝翁。"]'),
('0ff2e445-8a1f-4684-a889-5e146c7be4ef','壽沃令二首  其一','張嵲','宋','宋诗','song-poetry','','[]','山秀江清號浙西，氣鍾賢哲誕生時。',96,'全唐诗/poet.song.106000.json','["山秀江清號浙西，氣鍾賢哲誕生時。", "商朝月正垂三統，堯殿蓂荄見七枝。", "此景聚冰藏北陸，有人眉壽等南箕。", "教條宰邑郊馴雉，導引支床室有龜。", "五百間聞喬嶽降，八千遐歷大椿期。", "書生願效封人祝，爲捧黄金一屈巵。"]'),
('63db79d8-ce75-4da0-8aef-235a25feb6ff','壽沃令二首  其二','張嵲','宋','宋诗','song-poetry','','[]','奎文昭煥夢熊羆，正值英賢慶誕時。',96,'全唐诗/poet.song.106000.json','["奎文昭煥夢熊羆，正值英賢慶誕時。", "人日空知經月是，斗杓纔徧一年移。", "銅靈仙氣鍾標格，罨畫溪光入句辭。", "發策談兵知醖籍，操刀製錦見施爲。", "三年仁政春千日，萬口歡聲壽一巵。", "願祝我翁何許歲，紅蓮葉上見遊龜。"]'),
('e1da8919-22f8-40db-b674-d0c622871d22','和李少卿','張嵲','宋','宋诗','song-poetry','','[]','獨見凉蟾欲上時，西園爽氣溢清池。',96,'全唐诗/poet.song.106000.json','["獨見凉蟾欲上時，西園爽氣溢清池。", "坐欣萬頃潮方滿，欲舉一杯誰與持。", "虚閣排雲空窈窕，青山繞郭自參差。", "氣澄象表輪踰逈，光泛高林影驟移。", "一歲佳時今鶩過，誰家横笛未休吹。", "城烏何事翻飛急，不學鷦鷯占一枝。"]'),
('06815181-eb54-41aa-ad16-5c2304761f80','懷伊亭','張嵲','宋','宋诗','song-poetry','','[]','回環擁岡巒，澶漫分林塢。',24,'全唐诗/poet.song.106000.json','["回環擁岡巒，澶漫分林塢。", "縱目以怡情，信美疑吾土。"]'),
('f2ba5ac4-8964-4e07-96e1-5dbdfb3fe229','松門','張嵲','宋','宋诗','song-poetry','','[]','長林上晚煙，明月曜深夜。',24,'全唐诗/poet.song.106000.json','["長林上晚煙，明月曜深夜。", "重閉豈吾心，自回俗士駕。"]'),
('fc5eae3c-3eaa-47e9-b5f3-a70937609af4','致爽亭二首  其一','張嵲','宋','宋诗','song-poetry','','[]','霧豁空江平，林疏遠山出。',24,'全唐诗/poet.song.106000.json','["霧豁空江平，林疏遠山出。", "龍溪夜来雨，爽氣侵衣濕。"]'),
('79d08203-8990-497d-8fda-2522b4580ed0','致爽亭二首  其二','張嵲','宋','宋诗','song-poetry','','[]','桑柘落洲渚，澄潭漁艇集。',24,'全唐诗/poet.song.106000.json','["桑柘落洲渚，澄潭漁艇集。", "幽禽忽飛来，斜日水光溢。"]'),
('ceb56aee-c72d-47bb-90da-0479251d7413','宿歸仁寺三首  其一','張嵲','宋','宋诗','song-poetry','','[]','下瞰十仞餘，遥瞻幾千里。',24,'全唐诗/poet.song.106000.json','["下瞰十仞餘，遥瞻幾千里。", "遊客日暮時，鄉心萬端起。"]'),
('b68763a7-d715-443c-b0a0-2562c8124f3b','宿歸仁寺三首  其二','張嵲','宋','宋诗','song-poetry','','[]','喬林衆鳥集，暮氣氛氲上。',24,'全唐诗/poet.song.106000.json','["喬林衆鳥集，暮氣氛氲上。", "好在三巴山，何時正相望。"]'),
('42333978-50f5-46a2-bfd7-47e4e9847ac8','宿歸仁寺三首  其三','張嵲','宋','宋诗','song-poetry','','[]','巴水任喧雲，僧窗睡方悄。',24,'全唐诗/poet.song.106000.json','["巴水任喧雲，僧窗睡方悄。", "風清月到床，露白蟲鳴草。"]'),
('8a7b8a61-01c9-4808-bafe-a7f8abe7bb8b','幽居','張嵲','宋','宋诗','song-poetry','','[]','避地依荒谷，衡茅苟自安。',24,'全唐诗/poet.song.106000.json','["避地依荒谷，衡茅苟自安。", "門前山四塞，不用買峰巒。"]'),
('8797b322-513d-4e26-b8f4-0acb3e98b902','觀月出','張嵲','宋','宋诗','song-poetry','','[]','山空樵唱稀，林昏歸鳥没。',24,'全唐诗/poet.song.106000.json','["山空樵唱稀，林昏歸鳥没。", "新月含煙霏，遥依亂峰出。"]'),
('9a5b3627-ed31-4a40-ad86-8e1e91914565','生口','張嵲','宋','宋诗','song-poetry','','[]','牽舟四日程，屈曲縈山轉。',24,'全唐诗/poet.song.106000.json','["牽舟四日程，屈曲縈山轉。", "行行問居人，始知猶近縣。"]'),
('d74bd9ab-7f64-4dd9-9a91-d35776e7f53a','信美亭二首  其一','張嵲','宋','宋诗','song-poetry','','[]','北眺逼山樊，南瞻近津滸。',24,'全唐诗/poet.song.106000.json','["北眺逼山樊，南瞻近津滸。", "登兹一消憂，信美仍吾土。"]'),
('185f38e8-7869-49a1-a191-84d94bae00fe','信美亭二首  其二','張嵲','宋','宋诗','song-poetry','','[]','躡屐上危岑，策杖臨孤嶼。',24,'全唐诗/poet.song.106000.json','["躡屐上危岑，策杖臨孤嶼。", "来往自忘疲，於此時延佇。"]'),
('f80d222c-7df7-4ad5-977b-97ac786553e6','柳陌','張嵲','宋','宋诗','song-poetry','','[]','含風皆有態，夹路自成行。',24,'全唐诗/poet.song.106000.json','["含風皆有態，夹路自成行。", "馴鴉朝暮集，接葉得深藏。"]'),
('608a0055-3483-4acd-9b9f-9b2fb9fda1aa','詠種菊','張嵲','宋','宋诗','song-poetry','','[]','手種籬邊菊，秋来亦自開。',24,'全唐诗/poet.song.106000.json','["手種籬邊菊，秋来亦自開。", "驚蝶翩翩舞，雄蜂去復来。"]'),
('1b694f4b-9798-4f85-9943-d05f2dfeebbc','懷新亭四首  其一','張嵲','宋','宋诗','song-poetry','','[]','遠意在田疇，中園結茅屋。',24,'全唐诗/poet.song.106000.json','["遠意在田疇，中園結茅屋。", "凍雨昨夜来，共欣春水足。"]'),
('4a25eb60-dc2d-4d82-982c-b75867726f13','懷新亭四首  其二','張嵲','宋','宋诗','song-poetry','','[]','耘耔競所務，喬林午風清。',24,'全唐诗/poet.song.106000.json','["耘耔競所務，喬林午風清。", "嘉穀雨来長，復兹畦水平。"]'),
('0d1478e7-28b6-4fbf-8bfd-e383252cdc8a','懷新亭四首  其三','張嵲','宋','宋诗','song-poetry','','[]','恢台當長夏，山木盡成陰。',24,'全唐诗/poet.song.106000.json','["恢台當長夏，山木盡成陰。", "良苗方競茂，悠哉林下心。"]'),
('ea56e05b-8d20-4dc8-a433-6e688566a194','懷新亭四首  其四','張嵲','宋','宋诗','song-poetry','','[]','晚秧紛已及，中田日往還。',24,'全唐诗/poet.song.106000.json','["晚秧紛已及，中田日往還。", "適與好風會，植杖觀前山。"]'),
('c02602ba-42cc-4bb4-b74e-7f5665a1c8ea','夜雨','張嵲','宋','宋诗','song-poetry','','[]','夜半山雨来，夢覺還復息。',24,'全唐诗/poet.song.106000.json','["夜半山雨来，夢覺還復息。", "寥寥簷溜空，時聞斷續滴。"]'),
