('22bb462d-9008-4437-aeaf-81aa0316a58c','永康山','張嵲','宋','宋诗','song-poetry','','[]','嵯峩千仞永康山，石路終朝轉屈盤。',32,'全唐诗/poet.song.106000.json','["嵯峩千仞永康山，石路終朝轉屈盤。", "政恐乘高傷遠目，忽然煙霧鎖峰巒。"]'),
('d2109fa1-e0b7-4cd5-9a27-305201c6d080','自禮賢還鵝湖望山頂飛流有作二首  其一','張嵲','宋','宋诗','song-poetry','','[]','農夫秧稻滿畦水，行客跨騾無樹陂。',32,'全唐诗/poet.song.106000.json','["農夫秧稻滿畦水，行客跨騾無樹陂。", "熱風吹面日方午，忽見綠巖冰柱垂。"]'),
('86282aa2-b516-4ebe-a504-a860e680b0ef','自禮賢還鵝湖望山頂飛流有作二首  其二','張嵲','宋','宋诗','song-poetry','','[]','夾日赤雲方變火，行人渴肺欲生塵。',32,'全唐诗/poet.song.106000.json','["夾日赤雲方變火，行人渴肺欲生塵。", "飛流百丈垂虹冷，愧爾山中宴坐人。"]'),
('33383ccf-4647-4e4e-a699-09cc9a1db635','唁微水','張嵲','宋','宋诗','song-poetry','','[]','水畔平沙如積雪，灘心狠石似群牛。',32,'全唐诗/poet.song.106000.json','["水畔平沙如積雪，灘心狠石似群牛。", "如何夏日千雷怒，今作寒宵嗚咽流。"]'),
('4fb264ca-0bc1-46af-aaff-9baa6f02fe16','春暮泛微水中流有作','張嵲','宋','宋诗','song-poetry','','[]','微江春水綠於藍，兩岸花開雪滿巖。',32,'全唐诗/poet.song.106000.json','["微江春水綠於藍，兩岸花開雪滿巖。", "縱棹中流望山頂，晴雲如絮亂毿毿。"]'),
('7e7b5704-099d-4883-abf2-1bd37df9c9e1','微王廟','張嵲','宋','宋诗','song-poetry','','[]','疊浪一灘翻積雪，連峰千里送青螺。',32,'全唐诗/poet.song.106000.json','["疊浪一灘翻積雪，連峰千里送青螺。", "微王建國猶來古，山鎖叢祠瞑色多。"]'),
('2a43bd23-2d68-4aac-ade8-3da47b29662b','無住墳山溪水','張嵲','宋','宋诗','song-poetry','','[]','轉山溪溜碧涓涓，一勺芳甘信所便。',32,'全唐诗/poet.song.106000.json','["轉山溪溜碧涓涓，一勺芳甘信所便。", "盖代偉人今卜宅，敬君還似老翁泉。"]'),
('de2049e7-70b8-4c43-ae3c-b53480fbc9e6','自悼','張嵲','宋','宋诗','song-poetry','','[]','銀山卷浪萬雷鳴，渚水諸灘險永清。',32,'全唐诗/poet.song.106000.json','["銀山卷浪萬雷鳴，渚水諸灘險永清。", "平日垂堂猶自戒，年來輕作二江行。"]'),
('bee60d5c-1495-462b-8c6f-49838f3e2ab2','江行','張嵲','宋','宋诗','song-poetry','','[]','南訛溽暑方流汗，北陸淒風已裂膚。',32,'全唐诗/poet.song.106000.json','["南訛溽暑方流汗，北陸淒風已裂膚。", "江介寒暄真叵測，袗絺重繭在斯須。"]'),
('22462804-35c9-48ab-bab1-3315eaeb9b4e','寄酇里','張嵲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江依舊循荒壘，零落遺民有幾家。',32,'全唐诗/poet.song.106000.json','["長江依舊循荒壘，零落遺民有幾家。", "莫伐城邊舊桃李，爲憐曾發亂前花。"]'),
('c520d4b5-b1b0-41e4-9fa5-d596de89c84e','遊道謙庵','張嵲','宋','宋诗','song-poetry','','[]','中宵澍雨平明歇，諸嶺晴陰各自分。',32,'全唐诗/poet.song.106000.json','["中宵澍雨平明歇，諸嶺晴陰各自分。", "偶來共就藜牀坐，時看前山出白雲。"]'),
('08da57dd-5d18-4479-90d4-d063d0a24f28','甲子初夏復開北戶','張嵲','宋','宋诗','song-poetry','','[]','已向魏塘經四白，又開北戶納凉颸。',32,'全唐诗/poet.song.106000.json','["已向魏塘經四白，又開北戶納凉颸。", "祇應長作窗中客，會見蓬萊清淺時。"]'),
('f68550a8-08a0-44d9-8fff-fb054eb0f830','競渡','張嵲','宋','宋诗','song-poetry','','[]','吳俗春來鬬畫船，疾驅波上若飛煙。',32,'全唐诗/poet.song.106000.json','["吳俗春來鬬畫船，疾驅波上若飛煙。", "去春放逐曾觀此，伐鼓聲中又一年。"]'),
('4cd51486-8183-4d93-83e5-5d60af3f040a','立春偶題','張嵲','宋','宋诗','song-poetry','','[]','昔年長恨春歸晚，及到春來又恐殘。',32,'全唐诗/poet.song.106000.json','["昔年長恨春歸晚，及到春來又恐殘。", "今日摧頽蕭寺裏，閉門一任歲將闌。"]'),
('9c4f2a22-fb56-4855-8115-fbcba2e318b5','新春','張嵲','宋','宋诗','song-poetry','','[]','人生一世竟何哉，老去萬緣如死灰。',32,'全唐诗/poet.song.106000.json','["人生一世竟何哉，老去萬緣如死灰。", "愛惜分陰成底用，不如惡夢早醒來。"]'),
('57f818a6-a555-4676-863f-e47c9e0b2248','次韵惜春','張嵲','宋','宋诗','song-poetry','','[]','騷人競賦惜春詩，爲惜花飛萬點時。',32,'全唐诗/poet.song.106000.json','["騷人競賦惜春詩，爲惜花飛萬點時。", "唯有農家愛春盡，黄雲堆麥雪抽絲。"]'),
('8d6a8ce7-6617-4868-8e58-3df71da57bda','有感','張嵲','宋','宋诗','song-poetry','','[]','傾摧漢祚是安昌，祇恐狂瀾世莫當。',32,'全唐诗/poet.song.106000.json','["傾摧漢祚是安昌，祇恐狂瀾世莫當。", "自古忠言寧盡用，老臣得不戒王章。"]'),
('429397c9-9f76-4570-a55e-5ad94307a845','李公','張嵲','宋','宋诗','song-poetry','','[]','李公白髪已如絲，肯惜忠言負主知。',32,'全唐诗/poet.song.106000.json','["李公白髪已如絲，肯惜忠言負主知。", "事大不應回一語，知君不作上官儀。"]'),
('938abe05-1ede-4a18-b330-8d3f872ab218','絕句','張嵲','宋','宋诗','song-poetry','','[]','犖確南山路，叢筠冒水生。',24,'全唐诗/poet.song.106000.json','["犖確南山路，叢筠冒水生。", "寒梅銷落盡，猶有數花明。"]'),
('07b5c8f2-82f9-4eb2-b760-333601b5fdb5','奉送知府郎中','張嵲','宋','宋诗','song-poetry','','[]','文章足並漢西都，老大時時有著書。',64,'全唐诗/poet.song.106000.json','["文章足並漢西都，老大時時有著書。", "共歎微言追正始，不徒能賦似相如。", "代言方佇如綸詔，攬轡今乘刺史車。", "他日來歸司帝制，未應褊狹效王舒。"]'),
('7d6d46b1-bb1a-4af0-97a8-f5adb1d01cf1','塵外堂','張嵲','宋','宋诗','song-poetry','','[]','因依置屋偏，舊棲鵠地。',47,'全唐诗/poet.song.106000.json','["因依置屋偏，舊棲鵠地。", "雜花挾徑深，竹樹交柯際。", "古人謀適野，放浪聊自肆。", "誰識郡齋邊，斯堂眇塵世。"]'),
('a580dade-505b-4b3f-b1ad-e38821eee9eb','句  其一','張嵲','宋','宋诗','song-poetry','','[]','歸家凈洗如椽筆，準擬燕然勒駿功。',16,'全唐诗/poet.song.106000.json','["歸家凈洗如椽筆，準擬燕然勒駿功。"]'),
('32a1540d-a88d-4713-9830-f59bb5a171cb','句  其二','張嵲','宋','宋诗','song-poetry','','[]','白水汪汪滿稻畦，樟花零落徧前溪。',16,'全唐诗/poet.song.106000.json','["白水汪汪滿稻畦，樟花零落徧前溪。"]'),
('6b77c960-cc82-4987-bc29-2d96cbe44e06','句  其三','張嵲','宋','宋诗','song-poetry','','[]','此堂縱逐人俱廢，亦有陽冰篆字存。',16,'全唐诗/poet.song.106000.json','["此堂縱逐人俱廢，亦有陽冰篆字存。"]'),
('8008f713-df20-4c3c-85c5-c7fc50356063','送鄧城令王該致仕','張邵','宋','宋诗','song-poetry','','[]','碌碌紅塵三十年，一官今喜賦歸田。',32,'全唐诗/poet.song.106000.json','["碌碌紅塵三十年，一官今喜賦歸田。", "此行正值鱸魚美，好向鄞江買劍船。"]'),
('a2d4c67d-3e59-4f5d-9d30-71d09b9b85b2','橫江','張邵','宋','宋诗','song-poetry','','[]','橫江一片碧，攜鶴上漁船。',24,'全唐诗/poet.song.106000.json','["橫江一片碧，攜鶴上漁船。", "收綸不成下，卻抱釣竿眠。"]'),
('88e65b88-426d-4efc-b223-393cde65a60f','句','張邵','宋','宋诗','song-poetry','','[]','蘇氈久絕寢衣想，姜被忽分挾纊春。',16,'全唐诗/poet.song.106000.json','["蘇氈久絕寢衣想，姜被忽分挾纊春。"]'),
('bb99fe03-26d7-4861-89ab-f2e142436d34','答周邦彥覓茶  其一','張祁','宋','宋诗','song-poetry','','[]','內家新賜密雲龍，只到調元六七公。',32,'全唐诗/poet.song.106000.json','["內家新賜密雲龍，只到調元六七公。", "賴有家山供小草，猶堪詩老薦春風。"]'),
('ff2f9059-cb2f-4003-9911-ddf8b3198098','答周邦彥覓茶  其二','張祁','宋','宋诗','song-poetry','','[]','仇池詩裏識焦坑，風味官焙可抗衡。',32,'全唐诗/poet.song.106000.json','["仇池詩裏識焦坑，風味官焙可抗衡。", "鑽餘權倖亦及我，十輩遣前公試烹。"]'),
('c80d5eb9-ea84-48e8-83ae-25e00683ff95','題德清教場亭','張祁','宋','宋诗','song-poetry','','[]','浩蕩秋光裏，扁舟過德清。',48,'全唐诗/poet.song.106000.json','["浩蕩秋光裏，扁舟過德清。", "樓臺占山影，鵝鴨亂溪聲。", "小飲經年別，清歌一邑驚。", "娟娟照人月，還憶謝宣城。"]'),
('97df7f0a-65bd-4ce8-9214-768cb0f458a5','廬州詩','張祁','宋','宋诗','song-poetry','','[]','平湖阻城南，長淮带城西。',290,'全唐诗/poet.song.106000.json','["平湖阻城南，長淮带城西。", "壯哉金斗勢，吳人築合肥。", "曹瞞狼顧地，苻秦又顛擠。", "六飛駐吳會，重兵盾邊陲。", "紹興丁巳歲，書生綰戎機。", "酈瓊劫衆叛，度河從僞齊。", "蒼黄驅迫際，白刃加扶持。", "在職諸君子，臨難節不虧。", "尚書徇國事，既以身死之。", "罵賊語悲壯，摏喉聲喔咿。", "嗚呼趙使君，忠血濺路歧。", "在職喬張實大將，橫尸枕階基。", "至今遺部曲，言之皆涕洟。", "法當爲請謚，史策垂清規。", "法當爲立廟，血食安淮圻。", "奈何後之人，邈然弗吾思。", "居官潭潭府，神不芘茅茨。", "冤氣與精魄，皇皇何所依。", "所以州州內，鬼物多怪奇。", "月明廷廡下，彷彿若有窺。", "謦欬聞動息，衣冠儷容儀。", "士民日凋瘵，岳牧嬰禍罹。", "一紀八除帥，五喪三哭妻。", "張侯及內子，遍體生瘡痍。"]'),
('d5227d4c-0647-405a-bd0e-6bed6b912eb5','游鍾阜呈同集諸公','張祁','宋','宋诗','song-poetry','','[]','曉出白下門，東山聳孱顔。',240,'全唐诗/poet.song.106000.json','["曉出白下門，東山聳孱顔。", "脫身廛市中，辦此一日閑。", "西風忽凛冽，秋容著堅頑。", "烟樹小搖落，寒雲起斕斑。", "但驚節物變，敢辭登陟艱。", "諸峰互嶄絕，落勢相回環。", "盤固建康城，儼若呵神姦。", "造化鍾英靈，盡壓東南山。", "厚疑接坤軸，高欲窺帝關。", "太平嚴梵刹，華屋羅千間。", "向來劫燒灰，舊觀初未還。", "象教豈易滅，佛力不可扳。", "風雷運梁棟，斤斧勤輸般。", "會見落成日，千門響銅環。", "山僧肯分甘，我亦誅茅菅。", "人生少會心，勝處天所慳。", "歸韉理殘照，欲去仍躋攀。", "後會倘可約，此興殊未闌。", "祗恐俗士駕，頻來遭詆訕。", "哦詩記幽討，賸語君其刪。"]'),
('30de57bc-7e92-4dd6-8352-72c47459ae61','東關','張祁','宋','宋诗','song-poetry','','[]','山扼平湖蓄不東，地分南北指撝中。',32,'全唐诗/poet.song.106000.json','["山扼平湖蓄不東，地分南北指撝中。", "二關形勢千年壯，三國英雄一笑空。"]'),
('bef55ddf-1c0a-4a4d-9171-ae61ec5e8433','白水橋斷碑','張祁','宋','宋诗','song-poetry','','[]','出郭悠悠信馬蹄，荒烟衰草不勝悲。',32,'全唐诗/poet.song.106000.json','["出郭悠悠信馬蹄，荒烟衰草不勝悲。", "江南舊事無人記，時有龜趺載斷碑。"]'),
('da88fdb3-d730-4149-9a6e-1e7eebd78f22','渡湘水','張祁','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','春過瀟湘渡，真觀八景圖。',48,'全唐诗/poet.song.106000.json','["春過瀟湘渡，真觀八景圖。", "雲藏嶽麓寺，江入洞庭湖。", "晴日花爭發，豐年酒易沽。", "長沙十萬戶，游女似京都。"]'),
('f8e4573d-aab6-49e5-8aa5-c87b5a5ce640','西巖','張祁','宋','宋诗','song-poetry','','[]','似有樓臺處，微聞鐘磬聲。',48,'全唐诗/poet.song.106000.json','["似有樓臺處，微聞鐘磬聲。", "溪橫前路絕，人在別峰行。", "天遠水雲淡，春深花柳明。", "如果解塵鞅，親和法王城。"]'),
('07810ad5-71ad-47af-b0f6-83fdae0873b3','田蕳雜歌','張祁','宋','宋诗','song-poetry','','[]','大麥半枯自浮沉，小麥刺水鋪綠針。',96,'全唐诗/poet.song.106000.json','["大麥半枯自浮沉，小麥刺水鋪綠針。", "山邊老農望麥熟，出門見水放聲哭。", "去年涔涔七月雨，秋田不收一粒穀。", "只今米價貴如玉，併日舉家纔食粥。", "小兒索飯蕳前啼，大兒雖瘦把鋤犂。", "晴時和麥耕荒隴，正好下秧無稻種。"]'),
('4a786198-e4b4-479d-b221-67e3991fb6e9','平沙','張祁','宋','宋诗','song-poetry','','[]','平沙漠漠雁翩翩，兩岸菰蒲水拍天。',32,'全唐诗/poet.song.106000.json','["平沙漠漠雁翩翩，兩岸菰蒲水拍天。", "小艇得魚撐月去，一聲孤笛破寒烟。"]'),
('453cfbdf-1c40-49f7-938e-6b2d9c554401','題靈仙觀','張祁','宋','宋诗','song-poetry','','[]','樓殿起山巓，無塵地自偏。',48,'全唐诗/poet.song.106000.json','["樓殿起山巓，無塵地自偏。", "松廊暗雲霧，粉壁艷神仙。", "名姓藏丹府，衣冠訪洞天。", "幼輿丘壑質，定合老松泉。"]'),
('727ec0f4-0203-455e-a239-691d3dfa2d22','廣福寺','張祁','宋','宋诗','song-poetry','','[]','老去丹心在，愁來酒興濃。',48,'全唐诗/poet.song.106000.json','["老去丹心在，愁來酒興濃。", "江山遺古意，雲水淡秋容。", "落日孤村笛，微風遠寺鐘。", "平生善知識，卻憶妙高峰。"]'),
('045f98a2-e814-4461-aad6-f1f9c1e9ce86','汪氏別墅次韻  其一','張祁','宋','宋诗','song-poetry','','[]','不應無酒飲公榮，且與園花作證明。',64,'全唐诗/poet.song.106000.json','["不應無酒飲公榮，且與園花作證明。", "我已閉門爲獨樂，君能讓畔喜雙清。", "莫教佛法無多子，卻怕詩人太瘦生。", "好是柳絲饒意態，故垂濃綠著嚶嚶。"]'),
('52720cdc-ed60-45e8-9cf9-afc5447a326b','汪氏別墅次韻  其二','張祁','宋','宋诗','song-poetry','','[]','蕪湖還似鑑湖春，我亦歸來賀季真。',64,'全唐诗/poet.song.106000.json','["蕪湖還似鑑湖春，我亦歸來賀季真。", "好賦俱陪招隱士，耦耕長似問津人。", "襟懷處處尊前好，花柳番番雨後新。", "誰道只憑詩遣興，卻因雕琢費精神。"]'),
('a22dddb4-7fd9-4c0f-aa65-b9c5e256e0e6','句  其一','張祁','宋','宋诗','song-poetry','','[]','偉哉張與喬，忠烈激偏裨。',12,'全唐诗/poet.song.106000.json','["偉哉張與喬，忠烈激偏裨。"]'),
('f586153c-0fc9-4194-b712-6c10f44361b9','句  其二','張祁','宋','宋诗','song-poetry','','[]','堂成相業思三老，山揖仙風對八公。',16,'全唐诗/poet.song.106000.json','["堂成相業思三老，山揖仙風對八公。"]'),
('6b42772c-ec30-4d26-8d65-4585862e1410','偈二首  其一','釋得昇','宋','宋诗','song-poetry','','[]','久雨不晴，一箭兩垛。',53,'全唐诗/poet.song.106000.json','["久雨不晴，一箭兩垛。", "鼻孔一時沒爛，且道是誰之過。", "賴得老趙州，出來爲你勘破。", "日輪天子現扶桑，誰管西來閑達磨。"]'),
('e828c416-adfb-4382-8ac9-104906ff1b06','偈二首  其二','釋得昇','宋','宋诗','song-poetry','','[]','萬仞崖頭打一推，待渠絕後復蘇來。',32,'全唐诗/poet.song.106000.json','["萬仞崖頭打一推，待渠絕後復蘇來。", "活鱍鱍禪須自悟，萬重關鎖一時開。"]'),
('968376a4-bd40-421c-b33c-ef9adac0dedd','題茅山胡道士琴月卷','江賓王','宋','宋诗','song-poetry','','[]','皎皎松上月，泠泠手中琴。',96,'全唐诗/poet.song.106000.json','["皎皎松上月，泠泠手中琴。", "一彈颯靈飈，再彈驅層陰。", "鏗然發清響，窅皛延餘音。", "流光復徘徊，空林轉蕭森。", "象器無乃泥，天人諒何心。", "邂逅若有得，俯仰還自吟。", "太音寄寂寥，內景涵靜深。", "山空夜將宴，微露沾衣襟。"]'),
('b7e57e8b-7b05-4fb6-9b4f-d8d27a5145fb','登第報家人','董德元','宋','宋诗','song-poetry','','[]','御筆封題墨未乾，君恩重許拜金鑾。',32,'全唐诗/poet.song.106000.json','["御筆封題墨未乾，君恩重許拜金鑾。", "故鄉若問登科事，便是當初老榜官。"]'),
('46838065-c411-4425-9ec3-5c6457a05b39','叩棺歌','吳秉信','宋','宋诗','song-poetry','','[]','信叟歸去來，三界無安不可住。',26,'全唐诗/poet.song.106000.json','["信叟歸去來，三界無安不可住。", "西方凈土有蓮胎，願去來。"]'),
('f89bba82-ba1f-451e-bb0f-9a7d07f2b2f0','題張子正觀察溪風亭二首  其一','張偁','宋','宋诗','song-poetry','','[]','亭臨流水上，地接古城隈。',48,'全唐诗/poet.song.106000.json','["亭臨流水上，地接古城隈。", "日永簷楹靜，春深錦繡開。", "鷗隨清漾遠，風雜亂香來。", "懷咏北山檄，招邀翠作堆。"]'),
('c7ca31ad-262a-4721-b14a-b945c64c38f2','題張子正觀察溪風亭二首  其二','張偁','宋','宋诗','song-poetry','','[]','碧水通三徑，高風重五侯。',48,'全唐诗/poet.song.106000.json','["碧水通三徑，高風重五侯。", "知深丹扆眷，未許赤松遊。", "山簡暫爲郡，齊公晚得周。", "會攽濱海詔，再運釣鼇鈎。"]'),
('8617fa4d-5ab5-4c4a-b2e1-bbb921cb9b50','紹興丙辰冬十有二月戊申趙德載赴官宕渠入境小雨肩輿中戲作一絕書白鶴寺壁','趙德載','宋','宋诗','song-poetry','','[]','三年冷眼笑吹竽，世態炎涼我自如。',32,'全唐诗/poet.song.106000.json','["三年冷眼笑吹竽，世態炎涼我自如。", "卻怪天公亦人事，入邦便有雨隨車。"]'),
('c1ee48eb-e7f6-4d54-84bb-eaa41815de01','昨暮侍玉霄亭坐新月初上涼風疊至配以丹荔白醑景物且美賦詩呈知府丈','袁復一','宋','宋诗','song-poetry','','[]','夜涼時到此亭中，舞袂掀髯幾許同。',64,'全唐诗/poet.song.106000.json','["夜涼時到此亭中，舞袂掀髯幾許同。", "竹葉舊曾浮大白，絳囊新喜擘輕紅。", "若爲遽舍風千疊，未苦能留月一弓。", "只尺玉峰應好在，欲招鸞馭下空濛。"]'),
('64dbd63d-21ee-44ec-af2f-2d82f8b637d9','題遺直軒','余淳禮','宋','宋诗','song-poetry','','[]','二蘇翰墨仙，同謫百蠻裏。',120,'全唐诗/poet.song.106000.json','["二蘇翰墨仙，同謫百蠻裏。", "時有田舍翁，結茅住行李。", "邇來三十年，聞名輒掩耳。", "天定能勝人，稍復蒙料理。", "公卿尋斷編，臺隸藏敝屣。", "敗屋亦見修，變故乃如此。", "開軒畫遺像，凜凜有生氣。", "卻恨封德彝，不見盛時死。", "兄弟對床眠，此意孤一世。", "騎鯨儻相逢，笑人真好事。"]'),
('9cfce203-8693-43d4-90ee-bcf2eae1a726','凈居寺','李澗','宋','宋诗','song-poetry','','[]','金地無塵俯碧灣，蒼藤古木獲幽閑。',32,'全唐诗/poet.song.106000.json','["金地無塵俯碧灣，蒼藤古木獲幽閑。", "老僧袖手垂楊裏，靜閱渡頭人往還。"]'),
('7620be6c-7300-4cc5-96c1-5599b16e9646','句','陳成之','宋','宋诗','song-poetry','','[]','半窗圖畫梅花月，一枕波濤松樹風。',16,'全唐诗/poet.song.106000.json','["半窗圖畫梅花月，一枕波濤松樹風。"]'),
('dba3115e-8978-4036-bed8-cc024f6ea5ea','句  其一','蔡楙','宋','宋诗','song-poetry','','[]','竹靜深留月，花多不辨香。',12,'全唐诗/poet.song.106000.json','["竹靜深留月，花多不辨香。"]'),
('ea849d58-b5df-47f8-8256-6ab715d08449','句  其二','蔡楙','宋','宋诗','song-poetry','','[]','曙分林影外，春盡雨聲中。',12,'全唐诗/poet.song.106000.json','["曙分林影外，春盡雨聲中。"]'),
('90cb87b0-66df-4f74-9f15-d535cdec79aa','訪南山許真人故居','李稙','宋','宋诗','song-poetry','','[]','穿雲策杖岸烏紗，來訪南山羽客家。',32,'全唐诗/poet.song.106000.json','["穿雲策杖岸烏紗，來訪南山羽客家。", "九轉既成丹竈冷，半池烟水浸桃花。"]'),
('2aef05b6-0c44-4fd0-80f9-11dab1a1e299','句','劉裳','宋','宋诗','song-poetry','','[]','高閣應山三字古，華堂卓秀一峰尊。',16,'全唐诗/poet.song.106000.json','["高閣應山三字古，華堂卓秀一峰尊。"]'),
('0d74f291-b0fe-4f50-85cb-cec424f877dd','句','張孝友','宋','宋诗','song-poetry','','[]','盡得資川真面目，元知楚國富江山。',16,'全唐诗/poet.song.106000.json','["盡得資川真面目，元知楚國富江山。"]'),
('e3cded5a-7ee7-4da3-b67e-2bf52886d2e4','題舒嘯館二首  其一','胡如壎','宋','宋诗','song-poetry','','[]','堤邊草色綠茸茸，堤上桃花落盡紅。',32,'全唐诗/poet.song.106000.json','["堤邊草色綠茸茸，堤上桃花落盡紅。", "細雨斜風三月暮，一年春事客愁中。"]'),
('7d24fd0e-be26-4672-817d-e8eb2a7b2a73','題舒嘯館二首  其二','胡如壎','宋','宋诗','song-poetry','','[]','樓前春水碧彎環，柳外愁心千疊山。',32,'全唐诗/poet.song.106000.json','["樓前春水碧彎環，柳外愁心千疊山。", "立盡殘陽人不見，東風無賴莫凭闌。"]'),
('72c2f780-d1f8-461d-a807-488ac69c08c6','答大年馬丞相','胡如壎','宋','宋诗','song-poetry','','[]','人生寄浮雲，世味如嚼蠟。',96,'全唐诗/poet.song.106000.json','["人生寄浮雲，世味如嚼蠟。", "甯分螬半食，肯逐烏三匝。", "紛紛相彼我，此道方噂沓。", "君看王孫猨，愛惡卒難合。", "吾儕異市道，所貴相知心。", "臨分傾意氣，泣下時沾襟。", "古來耿介士，不憩惡木陰。", "茫茫天宇間，四顧徒悲吟。"]'),
('b29d9071-e209-46cf-a905-06bda9c0c363','答吳尚書','胡如壎','宋','宋诗','song-poetry','','[]','豫讓能報國，程嬰能保孤。',48,'全唐诗/poet.song.106000.json','["豫讓能報國，程嬰能保孤。", "雖復千萬年，名與日月俱。", "即今天壤間，斯人焉可無。", "臨風每遐想，泫然重嗟吁。"]'),
('b7972d68-8f96-42c5-8cb7-3b616a2d7c7f','後答吳尚書','胡如壎','宋','宋诗','song-poetry','','[]','渥漥困鹽車，帖耳聲復吞。',60,'全唐诗/poet.song.106000.json','["渥漥困鹽車，帖耳聲復吞。", "駑駘飽棧豆，嘶鳴尚軒軒。", "向來溝中斷，青黄即犧樽。", "薰蕕既同器，玉石且俱燔。", "物理安可齊，我今欲忘言。"]'),
('2944c2bb-452e-4951-9c38-8ca7129ad46d','句','馮宋','宋','宋诗','song-poetry','','[]','布衣已有回天力，太學翻爲御史臺。',16,'全唐诗/poet.song.106000.json','["布衣已有回天力，太學翻爲御史臺。"]'),
('67b511f4-ba1b-4560-aadb-b79566d2cb89','游范蘿山','蕭照','宋','宋诗','song-poetry','','[]','蘿翠松青護寶幢，烟波萬里送飛艭。',32,'全唐诗/poet.song.106000.json','["蘿翠松青護寶幢，烟波萬里送飛艭。", "真人舊有吹簫事，俱傍明霞照晚江。"]'),
('e2d0f222-55f7-4030-a57f-8fc9c7e059f0','留題靈巖','趙邦美','宋','宋诗','song-poetry','','[]','披雲佳處對青山，何必登高縱遠觀。',32,'全唐诗/poet.song.106000.json','["披雲佳處對青山，何必登高縱遠觀。", "巖谷幽深無限景，可憐多是等閑看。"]'),
('e40ec6b4-1a55-4075-908a-2605aa866c33','題壁','賈舍人','宋','宋诗','song-poetry','','[]','愁見干戈起四溟，恨無才術濟生靈。',32,'全唐诗/poet.song.106000.json','["愁見干戈起四溟，恨無才術濟生靈。", "不如痛飲中山酒，直到太平方始醒。"]'),
('d46d1a1a-6b22-458b-baca-b822fb77c2be','題壁','南陽驛婦人','宋','宋诗','song-poetry','','[]','流落南來自可嗟，避人不敢御鉛華。',32,'全唐诗/poet.song.106000.json','["流落南來自可嗟，避人不敢御鉛華。", "卻憐當日鶯鶯事，獨立春風霧鬢斜。"]'),
('06a588cf-92cb-4a6f-8d60-d8449ee6c100','上元行','胡處晦','宋','宋诗','song-poetry','','[]','上元愁雲在九重，哀笳落日吹腥風。',212,'全唐诗/poet.song.106000.json','["上元愁雲在九重，哀笳落日吹腥風。", "六龍駐驆在草莽，孽胡歌舞蒲萄宮。", "抽釵脫釧到編戶，竭澤枯魚充寶賂。", "聖主憂民民更憂，驕子嬌媟天天不怒。", "向來艱難傳大寶，父老談言似仁廟。", "元年二月城下盟，未睹名臣繼嘉祐。", "哀痛今年塵再蒙，冠劍夾道趨辭公。", "神龍今在九淵臥，安得屢困蛟蛇中。", "朝廷中興無柱石，薄物細故昭帝力。", "毛遂不得處囊中，遠慚趙氏廝養卒。", "今日君王歸不得，傾城回首歌悲啼。", "會有山呼間動地，萬家香霧燒天衣。", "胡兒胡兒莫耽樂，君不見夕月常虧東北角。"]'),
('7d0a614a-6ee6-4546-9edd-e5786bcd8a5a','宿田舍','霍洞','宋','宋诗','song-poetry','','[]','北風吹晴屋滿霜，翁兒赤體悲無裳。',80,'全唐诗/poet.song.106000.json','["北風吹晴屋滿霜，翁兒赤體悲無裳。", "閨中幼婦饑欲泣，忍饑取麻燈下緝。", "一身勿暇私自憐，鳴機軋軋明窗前。", "織成五丈如霜布，翁作旋襴兒作袴。", "明朝官中租賦急，依然赤體當風立。"]'),
('19c2cc76-31e2-4428-a465-875bc6c7a089','歲饑太守春遊呈以絕句','霍洞','宋','宋诗','song-poetry','','[]','朝來五馬去尋春，誰信家家甑有塵。',32,'全唐诗/poet.song.106000.json','["朝來五馬去尋春，誰信家家甑有塵。", "枕藉道傍宜細問，恐非芳草醉眠人。"]'),
('70dec47f-a47c-499f-a608-e9f2eed5462c','題米元暉山水','翟耆年','宋','宋诗','song-poetry','','[]','善畫無根樹，能描朦𦡂山。',24,'全唐诗/poet.song.106000.json','["善畫無根樹，能描朦𦡂山。", "如今身貴也，不肯與人間。"]'),
('a43d72d7-3b00-4c24-9dc6-2030d3a53fef','南昌道中','釋曉瑩','宋','宋诗','song-poetry','','[]','東游心渺渺，趼足步遲遲。',48,'全唐诗/poet.song.106000.json','["東游心渺渺，趼足步遲遲。", "馬驛黄茅路，人家白竹籬。", "歸雲橫斷嶺，落日映荒陂。", "何地可容足，長哦招隱詩。"]'),
('68908e09-e8ef-489f-a84e-cc3b9bcae013','句  其一','釋曉瑩','宋','宋诗','song-poetry','','[]','隱泛一船東。',6,'全唐诗/poet.song.106000.json','["隱泛一船東。"]'),
('ba0308ec-8089-496c-8438-434e461d9e38','句  其二','釋曉瑩','宋','宋诗','song-poetry','','[]','回看蒼木杪。',6,'全唐诗/poet.song.106000.json','["回看蒼木杪。"]'),
('a6db960d-e56d-4595-9943-b69684c2a09d','句  其三','釋曉瑩','宋','宋诗','song-poetry','','[]','蟬噪日將落。',6,'全唐诗/poet.song.106000.json','["蟬噪日將落。"]'),
('420e25c8-9961-44e2-b221-ba90c241fdd5','句  其四','釋曉瑩','宋','宋诗','song-poetry','','[]','不到茲亭久。',6,'全唐诗/poet.song.106000.json','["不到茲亭久。"]'),
('432a95bd-0be3-49e6-ae67-ae2e783a7ed8','句  其五','釋曉瑩','宋','宋诗','song-poetry','','[]','晚來供望眼。',6,'全唐诗/poet.song.106000.json','["晚來供望眼。"]'),
('fd4c8a11-78bd-45ec-ab29-9c9a5b1feba9','句  其六','釋曉瑩','宋','宋诗','song-poetry','','[]','攜朋上故基。',6,'全唐诗/poet.song.106000.json','["攜朋上故基。"]'),
