('8e7cc3af-09e8-4063-a7e7-07fcc6073b33','贈鄧珪','黄元道','宋','宋诗','song-poetry','','[]','柳綠桃紅春晝永，家童喚起睡中忙。',32,'全唐诗/poet.song.106000.json','["柳綠桃紅春晝永，家童喚起睡中忙。", "偶然日下音書至，回首江城又夕陽。"]'),
('832a1891-300b-4e5d-83bf-47b790df91c6','句  其一','黄元道','宋','宋诗','song-poetry','','[]','巽嶺直下梅家店，福祿難過丑年春。',16,'全唐诗/poet.song.106000.json','["巽嶺直下梅家店，福祿難過丑年春。"]'),
('b04825a3-2619-4d08-a3e0-ce1a3cf755c1','採桑行','顧禧','宋','宋诗','song-poetry','','[]','男耕女蠶治有餘，使君何不思。',30,'全唐诗/poet.song.106000.json','["男耕女蠶治有餘，使君何不思。", "使君策馬城南隅，妾歸深閣繅新絲。"]'),
('e94eac6e-4bd7-4fa9-b6d1-e4d8ba30f315','震澤行','顧禧','宋','宋诗','song-poetry','','[]','襟吳控越莽無幅，銀濤漂磕青山蹙。',260,'全唐诗/poet.song.106000.json','["襟吳控越莽無幅，銀濤漂磕青山蹙。", "水底隆隆晴亦雷，鯨鯢憑之鳩提取族。", "大者爲蛟小爲蛤，吐光便欲凌日月。", "地緯夜拆霜鏡枯，觸山飛沫天地白。", "芳餌頻施巧不吞，雲輸霧委長兒孫。", "撼岳吞舟逞大力，日月已墜爝火尊。", "昨聞漁人謀其曹，整罩施網瀰江皋。", "藥程傾湖湖不流，涸智殫技將安逃。", "蛟子蝦孫泣如雨，沈虎泅鹿慘無語。", "吁嗟河伯靈何存，鳴鼓聚市遂若此。", "就中大魚最有神，夜入深宮控紫宸。", "竭澤而來拂帝意，浩蕩乾坤雨露新。", "千秋萬歲頌乃公，鰐鯨無所施其雄。", "延津灌莽飲大澤，魚安于下鳥翔空。", "君不見然犀燒燕水族寒，咫尺之水多危瀾。", "活女誨女恩無極，枯魚何事泣河干。"]'),
('28f63609-45bf-4acb-8eb3-21cde93731b1','海棠秋','顧禧','宋','宋诗','song-poetry','','[]','春風蕩漾花如織，排擯深巖天地窄。',275,'全唐诗/poet.song.106000.json','["春風蕩漾花如織，排擯深巖天地窄。", "桃李芳菲鬬艷陽，嫣痕盡染胭脂色。", "含丹欲吐嬌不勝，獺髓遙分點瓊額。", "楊妃睡足口無語，嫁作游絲怨風雨。", "花神泣罷還欲訴，不願柔枝薦繁市。", "願得常親君子傍，秋深靜綰紫綃粧。", "孤桐獨立擎素月，芙蕖零落無輝光。", "瑤枝重整臨秋水，蓼蒲歷歷羞無香。", "賞心況有雙鳬仙，琴聲夜夜醉嬋娟。", "碧霞觴泛海棠醉，曲欄麗影何蹁躚。", "君不見南朝百里花無數，郁郁紛紛吐烟霧。", "載歲無人禁採樵，丹榦瓊姿盡摧仆。", "蘭蕙當門動見鋤，草間惟歎璇霓臥。", "茲花勝植瀛蕊苑，一承顧盼猶未晚。", "冉冉臨窗如有心，嬛舞清歌樂事遠。", "蔓露凝霜色倍妍，夔州何獨無詩篇。", "茲花有詩便不朽，吁嗟托根良不偶。"]'),
('3cb31b51-6fa1-4d46-b5db-f3591233f071','小春詞','顧禧','宋','宋诗','song-poetry','','[]','玉霜斜舞桐枝濕，析木熒熒石鯨泣。',192,'全唐诗/poet.song.106000.json','["玉霜斜舞桐枝濕，析木熒熒石鯨泣。", "芙蓉子夜卸穠粧，藥雨紛糅瓊飲急。", "瓊樓玉宇微寒生，氤氳暖氣出元英。", "白鹿觀中香粉散，靈女祠前簫鼓鳴。", "木奴千樹綻濃綠，太濟粼粼黑鳥浴。", "真臘燈光射紫薇，漢宮齊唱鳳來時。", "彩虹不逐天駟流，公子初成狐腋裘。", "尚衣日日頒紅錦，挾纊猶深邊士愁。", "五鳳習習起蘭澤，龍篆新盤大府曆。", "黍臛松醪次第陳，野老欣然愛冬日。", "暖爐高會樂未央，鴻雁南飛百草黄。", "東君欲逗春消息，獨遣桃花鬬橘陽。"]'),
('507bc409-e065-41df-9dcc-fd3584f6ab83','憩小峨嵋','顧禧','宋','宋诗','song-poetry','','[]','偶上峨嵋嶺，悠然對夕曛。',48,'全唐诗/poet.song.106000.json','["偶上峨嵋嶺，悠然對夕曛。", "孤峰擎落日，古殿宿寒雲。", "石暗松濤作，天空鶴唳聞。", "幽尋愜素抱，世態自紛紜。"]'),
('ff3498c4-685d-4864-8ee7-ae2370da2d92','不寐','顧禧','宋','宋诗','song-poetry','','[]','英雄不世出，竪子自成名。',48,'全唐诗/poet.song.106000.json','["英雄不世出，竪子自成名。", "誰諛美新筆，曾憐覆楚兵。", "輕霜零病葉，急雁過寒城。", "入夜愁無似，悲笳處處聲。"]'),
('9a44734f-2cd9-4d26-9173-7fe81c6410f2','宿徐稚山齋中','顧禧','宋','宋诗','song-poetry','','[]','已將夙昔志，抵掌爲君陳。',48,'全唐诗/poet.song.106000.json','["已將夙昔志，抵掌爲君陳。", "笳鼓悲吳地，鬚眉憶漢臣。", "梅花憑夜發，柳色司年新。", "此夕關河客，應輸夜臥人。"]'),
('8ebde169-b893-4342-a3a1-b60a9f96c90a','泊太湖寄內','顧禧','宋','宋诗','song-poetry','','["\u592a\u6e56"]','草草出門去，孤帆落暮烟。',48,'全唐诗/poet.song.106000.json','["草草出門去，孤帆落暮烟。", "笑談卿宛在，辛苦夢難傳。", "雨礴蛟龍窟，雲乘橘柚邊。", "從來輕遠別，此夕倍凄然。"]'),
('a36371b0-221f-4631-ae25-fc555bf7faff','答譚子欽惟寅','顧禧','宋','宋诗','song-poetry','','[]','束髪鄙章句，清狂天下聞。',48,'全唐诗/poet.song.106000.json','["束髪鄙章句，清狂天下聞。", "戔戔招隱賦，草草送窮文。", "捫蝨輕王猛，驅車揖范雲。", "皇家疏結網，麟鳳自爲群。"]'),
('c99e4a44-714f-4ed2-984b-e624ddfe0f0b','偶作','顧禧','宋','宋诗','song-poetry','','[]','彈鋏復爾爾，登樓向落曛。',48,'全唐诗/poet.song.106000.json','["彈鋏復爾爾，登樓向落曛。", "烟深橫白鷺，楓老宿彤雲。", "松牖寒威入，琳宮遠磬聞。", "自然能遠俗，無復賦離群。"]');
